-- Poems batch 269
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('94058119-0b02-4b6a-bbc5-a6e98aff7718','懷舊第一百六','文天祥','宋','宋诗','song-poetry','','[]','天寒昏無日，故鄉不可思。',24,'全唐诗/poet.song.239000.json','["天寒昏無日，故鄉不可思。", "訪舊半爲鬼，慘慘中腸悲。"]'),
('7ac0ec08-041f-44a6-9a42-c62599fb4df2','懷舊第一百七','文天祥','宋','宋诗','song-poetry','','[]','故園花自發，無復故人來。',24,'全唐诗/poet.song.239000.json','["故園花自發，無復故人來。", "亂離朋友盡，幽珮爲誰哀。"]'),
('35bdc361-3a6e-45ab-8700-5f79a76cfb79','懷舊第一百八','文天祥','宋','宋诗','song-poetry','','[]','故人入我夢，相視涕闌干。',24,'全唐诗/poet.song.239000.json','["故人入我夢，相視涕闌干。", "四海一塗炭，焉用身獨完。"]'),
('abf477fc-6eb5-4523-a5aa-1cd3d3a22a59','懷舊第一百九','文天祥','宋','宋诗','song-poetry','','[]','中夜懷友朋，百年見存沒。',24,'全唐诗/poet.song.239000.json','["中夜懷友朋，百年見存沒。", "風吹蒼江樹，寒月照白骨。"]'),
('4ed9fb09-42b1-4096-bccd-f66e359dbb33','金應第一百一十','文天祥','宋','宋诗','song-poetry','','[]','追隨三十載，艱難愧深情。',24,'全唐诗/poet.song.239000.json','["追隨三十載，艱難愧深情。", "何處埋爾骨，呼號傍孤城。"]'),
('309b288d-8630-45ea-aa4a-860d1d471973','張雲第一百一十一','文天祥','宋','宋诗','song-poetry','','[]','痛憤寄所宣，四方服勇决。',24,'全唐诗/poet.song.239000.json','["痛憤寄所宣，四方服勇决。", "壯士斂精魂，里巷猶嗚咽。"]'),
('d2c2a69f-2deb-4dac-b22e-4b3c847996f3','劉欽貢元第一百一十二','文天祥','宋','宋诗','song-poetry','','[]','文章日自負，去家死路傍。',24,'全唐诗/poet.song.239000.json','["文章日自負，去家死路傍。", "高視見霸王，感子故意長。"]'),
('56270231-b7f3-407c-8b6b-197066b27266','呂武第一百一十三','文天祥','宋','宋诗','song-poetry','','[]','疾惡懷剛腸，世人皆欲殺。',24,'全唐诗/poet.song.239000.json','["疾惡懷剛腸，世人皆欲殺。", "魂魄猶正直，回首肝肺熱。"]'),
('f6bbf131-c6eb-4b87-a2bd-2d66c84ad093','鞏宣使信第一百一十四','文天祥','宋','宋诗','song-poetry','','[]','壯士血相視，斯人已云亡。',24,'全唐诗/poet.song.239000.json','["壯士血相視，斯人已云亡。", "哀哀失木狖，夜深經戰場。"]'),
('f9d687a0-1dad-4ccd-9ef8-2c7937580467','張秘撰汴第一百一十五','文天祥','宋','宋诗','song-poetry','','[]','入幕旌旗動，揮翰綺繡揚。',24,'全唐诗/poet.song.239000.json','["入幕旌旗動，揮翰綺繡揚。", "煙霧蒙玉質，斯人今則亡。"]'),
('5ee110e7-12aa-40ea-9b77-83d83818353b','繆朝宗第一百一十六','文天祥','宋','宋诗','song-poetry','','[]','空荒咆熊羆，摧殘沒藜莠。',24,'全唐诗/poet.song.239000.json','["空荒咆熊羆，摧殘沒藜莠。", "平生江海心，其人骨已朽。"]'),
('97d7df8c-c426-4cb3-acfc-c92182c8a932','閩三士第一百一十七','文天祥','宋','宋诗','song-poetry','','[]','俊逸鮑參軍，優游謝康樂。',24,'全唐诗/poet.song.239000.json','["俊逸鮑參軍，優游謝康樂。", "豺虎正縱橫，南行道彌惡。"]'),
('f8122a19-54dc-4918-86e7-070d9737cd85','諸幕客第一百一十八','文天祥','宋','宋诗','song-poetry','','[]','入幕未展才，辛苦在道路。',24,'全唐诗/poet.song.239000.json','["入幕未展才，辛苦在道路。", "回首一茫茫，風悲浮雲去。"]'),
('6cdf5709-8b84-44ab-b534-b289955ee2ed','趙大監時賞第一百一十九','文天祥','宋','宋诗','song-poetry','','[]','豪傑貴勳業，宗支神堯後。',24,'全唐诗/poet.song.239000.json','["豪傑貴勳業，宗支神堯後。", "平生白羽扇，欝結回我首。"]'),
('0ea6644e-00b7-4bc9-821b-5d613bccd86e','劉沐第一百二十','文天祥','宋','宋诗','song-poetry','','[]','王翰願卜鄰，嵇康不得死。',24,'全唐诗/poet.song.239000.json','["王翰願卜鄰，嵇康不得死。", "落月滿屋梁，悲風爲我起。"]'),
('ba465804-fca9-49c2-bb57-9d3a019b655b','孫𣓨第一百二十一','文天祥','宋','宋诗','song-poetry','','[]','故人有孫宰，義均骨肉地。',24,'全唐诗/poet.song.239000.json','["故人有孫宰，義均骨肉地。", "連爲糞土叢，揮手灑衰泪。"]'),
('18790a46-9d3b-4abb-bebc-520fc6aca0ac','彭司令震龍第一百二十二','文天祥','宋','宋诗','song-poetry','','[]','堂上會親戚，可憐馬上郎。',24,'全唐诗/poet.song.239000.json','["堂上會親戚，可憐馬上郎。", "呻吟更流血，干戈浩茫茫。"]'),
('1517b58e-bff2-4ae8-92d4-9fa44b12d661','蕭從事燾夫第一百二十三','文天祥','宋','宋诗','song-poetry','','[]','灑翰銀鈎連，翩躚山顛鶴。',24,'全唐诗/poet.song.239000.json','["灑翰銀鈎連，翩躚山顛鶴。", "慘淡鬭龍蛇，及茲歎冥漠。"]'),
('543b95c7-2574-4083-a342-9c3a27591978','蕭架閣第一百二十四','文天祥','宋','宋诗','song-poetry','','[]','諸生舊短褐，張目視寇讎。',24,'全唐诗/poet.song.239000.json','["諸生舊短褐，張目視寇讎。", "高義終焉在，白骨更何憂。"]'),
('353cc6d2-b2c9-458e-ba50-a6276e92d1fd','陳督幹第一百二十五','文天祥','宋','宋诗','song-poetry','','[]','挺身艱難際，虎穴連里閭。',24,'全唐诗/poet.song.239000.json','["挺身艱難際，虎穴連里閭。", "高天意悽惻，同盡隨丘墟。"]'),
('d47b0586-05ca-4e16-9e90-036d8a20dee7','陳少卿第一百二十六','文天祥','宋','宋诗','song-poetry','','[]','卿月昇金掌，老氣橫九州。',24,'全唐诗/poet.song.239000.json','["卿月昇金掌，老氣橫九州。", "前輩復誰紀，吾道長悠悠。"]'),
('6016cb7f-97f3-4c59-8fb9-41f3967880c9','鄒處置第一百二十七','文天祥','宋','宋诗','song-poetry','','[]','東郊暗長戟，死地脫斯須。',24,'全唐诗/poet.song.239000.json','["東郊暗長戟，死地脫斯須。", "庾公興不淺，居然屈壯圖。"]'),
('c930e642-c0e0-44d1-9eeb-7d59ba5ad803','鄒處置第一百二十八','文天祥','宋','宋诗','song-poetry','','[]','方當節鉞用，不返舊征魂。',24,'全唐诗/poet.song.239000.json','["方當節鉞用，不返舊征魂。", "凄凉餘部曲，發聲爲爾吞。"]'),
('cfb1635c-2a03-4f77-b46d-4661cfaef0a0','劉監簿第一百二十九','文天祥','宋','宋诗','song-poetry','','[]','艱難奮長戟，高義薄曾雲。',24,'全唐诗/poet.song.239000.json','["艱難奮長戟，高義薄曾雲。", "死爲殊方鬼，三夜頻夢君。"]'),
('070d2ac5-35e0-44cd-a1fb-33c668ff43cc','劉監簿第一百三十','文天祥','宋','宋诗','song-poetry','','[]','秀氣衝星斗，壯筆過飛泉。',24,'全唐诗/poet.song.239000.json','["秀氣衝星斗，壯筆過飛泉。", "舊遊易磨滅，魂傷山寂然。"]'),
('4f47a8d5-463b-417f-8766-0854582b1620','蕭資第一百三十一','文天祥','宋','宋诗','song-poetry','','[]','主當風雲會，謝爾從者勞。',24,'全唐诗/poet.song.239000.json','["主當風雲會，謝爾從者勞。", "感恩義不小，塊獨委蓬蒿。"]'),
('ce963a16-6231-4af2-8e31-b49f8bf181d9','杜大卿滸第一百三十二','文天祥','宋','宋诗','song-poetry','','[]','昔沒賊中時，中夜間道歸。',24,'全唐诗/poet.song.239000.json','["昔沒賊中時，中夜間道歸。", "辛苦救衰朽，微爾人盡非。"]'),
('600b9ba5-a8d7-402d-96b0-f4e5c41164ac','杜大卿滸第一百三十三','文天祥','宋','宋诗','song-poetry','','[]','高隨海上查，子豈無扁舟。',24,'全唐诗/poet.song.239000.json','["高隨海上查，子豈無扁舟。", "白日照執袂，埋骨已經秋。"]'),
('74fbcbbd-a0e9-44a3-8383-40bf76be48b8','徐榛第一百三十四','文天祥','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.239000.json','["無正文。"]'),
('d12805fc-1668-438c-87ef-84c8a82ed11b','林檢院琦第一百三十五','文天祥','宋','宋诗','song-poetry','','[]','時危挹佳士，慘淡隨回鶻。',24,'全唐诗/poet.song.239000.json','["時危挹佳士，慘淡隨回鶻。", "佯狂真可哀，死淚終映睫。"]'),
('6fb4c189-4f62-474a-b154-df954e273ced','曾先生第一百三十六','文天祥','宋','宋诗','song-poetry','','[]','江海日凄凉，賢聖盡蕭索。',24,'全唐诗/poet.song.239000.json','["江海日凄凉，賢聖盡蕭索。", "西河共風味，顧步涕橫落。"]'),
('990bbee3-3f11-4db0-a5b7-43e0ac7916d3','鄧禮部第一百三十七','文天祥','宋','宋诗','song-poetry','','[]','南宮吾故人，才名三十年。',24,'全唐诗/poet.song.239000.json','["南宮吾故人，才名三十年。", "江城秋日落，此別意蒼然。"]'),
('ecc21df8-3d9c-4358-ab4c-cf7f76ab0de2','家樞密鉉翁第一百三十八','文天祥','宋','宋诗','song-poetry','','[]','出處同世網，高誼邁等倫。',24,'全唐诗/poet.song.239000.json','["出處同世網，高誼邁等倫。", "異方驚會面，慰此貞良臣。"]'),
('0e1dd542-bb12-44c3-95d7-a25b0ac6468a','墳墓第一百三十九','文天祥','宋','宋诗','song-poetry','','[]','別離已五年，不及祖父塋。',24,'全唐诗/poet.song.239000.json','["別離已五年，不及祖父塋。", "霜露晚凄凄，痛哭松聲迴。"]'),
('4e83d97d-60cb-4956-a619-11fb18df0801','宗族第一百四十','文天祥','宋','宋诗','song-poetry','','[]','西江接錦城，山陰一茅宇。',24,'全唐诗/poet.song.239000.json','["西江接錦城，山陰一茅宇。", "宗族忍相遺，乾坤此深阻。"]'),
('e0f02a4d-3928-4012-8020-b2b7720a90ff','母第一百四十一','文天祥','宋','宋诗','song-poetry','','[]','何時太夫人，上天回哀眷。',24,'全唐诗/poet.song.239000.json','["何時太夫人，上天回哀眷。", "墓久狐兔鄰，嗚呼淚如霰。"]'),
('69b7582b-4fba-4681-8fcc-e7b95c48c89a','舅第一百四十二','文天祥','宋','宋诗','song-poetry','','[]','萱草秋已死，歲暮有嚴霜。',24,'全唐诗/poet.song.239000.json','["萱草秋已死，歲暮有嚴霜。", "落日渭陽明，涕淚濺我裳。"]'),
('18afae6a-03d1-4c86-b2cc-d05aba9df19d','妻第一百四十三','文天祥','宋','宋诗','song-poetry','','[]','結髮爲妻子，倉皇避亂兵。',24,'全唐诗/poet.song.239000.json','["結髮爲妻子，倉皇避亂兵。", "生離與死別，回首淚縱橫。"]'),
('994beca6-d373-4437-934c-30866825c808','二女第一百四十四','文天祥','宋','宋诗','song-poetry','','[]','床前兩小女，各在天一涯。',24,'全唐诗/poet.song.239000.json','["床前兩小女，各在天一涯。", "所愧爲人父，風物長年悲。"]'),
('a494aaed-d9cd-4950-b8b2-8f8abae2ec22','次子第一百四十五','文天祥','宋','宋诗','song-poetry','','[]','渥洼騏驥兒，衆中見毛骨。',24,'全唐诗/poet.song.239000.json','["渥洼騏驥兒，衆中見毛骨。", "別來忽三歲，殘害爲異物。"]'),
('7cb0585c-7d1b-47ca-aa13-3af11bfd4c05','妻子第一百四十六','文天祥','宋','宋诗','song-poetry','','[]','妻子隔絕久，飄颻若埃塵。',24,'全唐诗/poet.song.239000.json','["妻子隔絕久，飄颻若埃塵。", "漠漠世間黑，性命由他人。"]'),
('370466c1-e439-4709-aabb-cbd0c29ad3a6','妻子第一百四十七','文天祥','宋','宋诗','song-poetry','','[]','世亂遭飄蕩，飛藿共徘徊。',24,'全唐诗/poet.song.239000.json','["世亂遭飄蕩，飛藿共徘徊。", "十口隔風雪，反畏消息來。"]'),
('6d20e01b-ec85-4ab1-b2c1-f117835e4326','長妹第一百四十八','文天祥','宋','宋诗','song-poetry','','[]','近聞韋氏妹，零落依草木。',24,'全唐诗/poet.song.239000.json','["近聞韋氏妹，零落依草木。", "深負鶺鴒詩，臨風欲痛哭。"]'),
('3fd36049-bde0-473f-8656-21daf3d8fecb','長子第一百四十九','文天祥','宋','宋诗','song-poetry','','[]','大兒聰明到，青歲已摧頹。',24,'全唐诗/poet.song.239000.json','["大兒聰明到，青歲已摧頹。", "回風吹獨樹，吾寧舍一哀。"]'),
('ce5d7db8-8c56-4a0b-aa14-58d234b2f47d','二女第一百五十','文天祥','宋','宋诗','song-poetry','','[]','癡女饑咬我，鬰沒一悲魂。',24,'全唐诗/poet.song.239000.json','["癡女饑咬我，鬰沒一悲魂。", "不得收骨肉，痛哭蒼烟根。"]'),
('6edb2af1-906f-4ead-a6cf-ac17da28c163','弟第一百五十一','文天祥','宋','宋诗','song-poetry','','[]','兄弟分離苦，凄凉憶去年。',24,'全唐诗/poet.song.239000.json','["兄弟分離苦，凄凉憶去年。", "何以有羽翼，飛去墮爾前。"]'),
('8550fc9b-d8b2-43fd-b75a-99f3924786fc','弟第一百五十二','文天祥','宋','宋诗','song-poetry','','[]','棣華晴雨好，風急手足寒。',24,'全唐诗/poet.song.239000.json','["棣華晴雨好，風急手足寒。", "百戰今誰在，羈棲見汝難。"]'),
('ae0de9be-c278-4a7d-b972-de2a5ecc3d66','弟第一百五十三','文天祥','宋','宋诗','song-poetry','','[]','沙晚鶺鴒寒，風吹紫荆樹。',24,'全唐诗/poet.song.239000.json','["沙晚鶺鴒寒，風吹紫荆樹。", "忍淚獨含情，江湖春欲暮。"]'),
('23cc7130-ad3e-42cc-b565-46b441c9b808','弟第一百五十四','文天祥','宋','宋诗','song-poetry','','[]','不見江東弟，急難心炯然。',24,'全唐诗/poet.song.239000.json','["不見江東弟，急難心炯然。", "念君經世亂，卧病海雲邊。"]'),
('9949f1f5-a080-44a5-ace3-bfdb82226b70','次妹第一百五十五','文天祥','宋','宋诗','song-poetry','','[]','天際傷愁別，江山憔悴人。',24,'全唐诗/poet.song.239000.json','["天際傷愁別，江山憔悴人。", "團圓思弟妹，傳語故鄉春。"]'),
('508242b8-11b8-4dd6-8329-9034bc2f67a1','思故鄉第一百五十六','文天祥','宋','宋诗','song-poetry','','[]','天地西江遠，無家問死生。',24,'全唐诗/poet.song.239000.json','["天地西江遠，無家問死生。", "凉風起天末，萬里故鄉情。"]'),
('ae023eac-21ae-4e2a-9f13-f5672f609bad','第一百五十七','文天祥','宋','宋诗','song-poetry','','[]','江漢故人少，東西消息稀。',24,'全唐诗/poet.song.239000.json','["江漢故人少，東西消息稀。", "異花開絕域，野風吹征衣。"]'),
('f3c7e262-c89d-4d9d-b67b-480f64acf528','第一百五十八','文天祥','宋','宋诗','song-poetry','','[]','老夫悲暮年，天涯故人少。',24,'全唐诗/poet.song.239000.json','["老夫悲暮年，天涯故人少。", "每望東南雲，决眥入歸鳥。"]'),
('3f1dab94-2701-4c74-9d4b-c105088b1feb','第一百五十九','文天祥','宋','宋诗','song-poetry','','[]','人生無家別，親故傷老醜。',24,'全唐诗/poet.song.239000.json','["人生無家別，親故傷老醜。", "剪紙招我魂，何時一樽酒。"]'),
