('f75e46dc-ecb0-488a-b4cf-c7a79c1afef2','歎世道第一百九十二','文天祥','宋','宋诗','song-poetry','','[]','古來遭喪亂，丈夫多英雄。',24,'全唐诗/poet.song.239000.json','["古來遭喪亂，丈夫多英雄。", "悠悠委薄俗，豈非吾道東。"]'),
('4549807b-d3ae-4f2c-8bca-2f46f38ff5f1','第一百九十三','文天祥','宋','宋诗','song-poetry','','[]','蝮蛇暮偃蹇，猛虎憑其威。',24,'全唐诗/poet.song.239000.json','["蝮蛇暮偃蹇，猛虎憑其威。", "真宰意茫茫，六合人煙稀。"]'),
('60b4825a-f912-4218-83c6-8ac3fd057d12','第一百九十四','文天祥','宋','宋诗','song-poetry','','[]','黎民困逆節，殘孽駐艱虞。',24,'全唐诗/poet.song.239000.json','["黎民困逆節，殘孽駐艱虞。", "孰云網恢恢，自及梟獍徒。"]'),
('90f7419b-eb2a-4465-9b10-79a0288b50c2','第一百九十五','文天祥','宋','宋诗','song-poetry','','[]','眼中萬少年，得志行所爲。',24,'全唐诗/poet.song.239000.json','["眼中萬少年，得志行所爲。", "白馬蹴微雪，追隨燕薊兒。"]'),
('ae5b2e78-c10a-43f3-8788-73bdeebeb16b','第一百九十六','文天祥','宋','宋诗','song-poetry','','[]','客從何鄉來，挾矢射漢月。',24,'全唐诗/poet.song.239000.json','["客從何鄉來，挾矢射漢月。", "殺身傍權要，門戶有旌節。"]'),
('b62a5f16-fa52-4e80-9ed9-16168aae706f','第一百九十七','文天祥','宋','宋诗','song-poetry','','[]','關河霜雪清，故人亦流落。',24,'全唐诗/poet.song.239000.json','["關河霜雪清，故人亦流落。", "夷歌奉玉盤，悲君隨燕雀。"]'),
('a7ea4942-8260-49e1-9a4c-fc1b2488e0d8','第一百九十八','文天祥','宋','宋诗','song-poetry','','[]','漁陽豪俠地，北里富熏天。',24,'全唐诗/poet.song.239000.json','["漁陽豪俠地，北里富熏天。", "快馬金纏轡，但遇新少年。"]'),
('5be771ca-2c32-43c3-9bc5-903a3ba9ddf9','第一百九十九','文天祥','宋','宋诗','song-poetry','','[]','南北逃世難，始聞蕃漢殊。',24,'全唐诗/poet.song.239000.json','["南北逃世難，始聞蕃漢殊。", "天下今一家，中原有驅除。"]'),
('f0597742-f77d-48fe-97ba-fdca6c5ec4a0','第二百','文天祥','宋','宋诗','song-poetry','','[]','茫茫天造間，高岸尚爲谷。',24,'全唐诗/poet.song.239000.json','["茫茫天造間，高岸尚爲谷。", "百川日東流，勢閲人代速。"]'),
('90ce2b32-287f-4d84-b4f4-2542e4f0a6bd','宴交代寧國孟知府致語口號','文天祥','宋','宋诗','song-poetry','','[]','玉堂學士催班鷺，粉省潛郎趣佩麟。',64,'全唐诗/poet.song.239000.json','["玉堂學士催班鷺，粉省潛郎趣佩麟。", "來往神仙同碧落，後先岳牧總詞人。", "陽坡共喜瓜時及，朝路相期柳色新。", "握手論交拚一醉，東風散作滿城春。"]'),
('3bfb078e-c5a8-40ce-80af-a140c4c51be1','宴交代湖南提刑李運使致語口號','文天祥','宋','宋诗','song-poetry','','[]','河漢雙星會使槎，分明徹夜照長沙。',64,'全唐诗/poet.song.239000.json','["河漢雙星會使槎，分明徹夜照長沙。", "轡絲曉轉全龜影，衣繡春隨錦鵲花。", "雲杏舊陰凉綠凈，野萍新韵度朱華。", "明年共侍蓬萊宴，回首丹墀日未斜。"]'),
('c4aa7bea-3934-4750-8e21-ab2a77cdbb8e','宴朱衡守致語口號','文天祥','宋','宋诗','song-poetry','','[]','翩翩紫馬絢銀潢，春入梅花新雨香。',64,'全唐诗/poet.song.239000.json','["翩翩紫馬絢銀潢，春入梅花新雨香。", "牛斗劍芒浮翼軫，岷峨佩影度瀟湘。", "東南麾節精神合，上下風雲意氣長。", "且爲綠醽拚一醉，傳呼聯轡覲明光。"]'),
('28f8e637-331c-44e0-a39d-4873fa9818e2','宴湖南董提舉致語口號','文天祥','宋','宋诗','song-poetry','','[]','西風八月楚江濱，爭看星槎會漢津。',64,'全唐诗/poet.song.239000.json','["西風八月楚江濱，爭看星槎會漢津。", "露濕紅綾旗影舊，雲連翠簜轡華新。", "東西杜若洲連月，先後瑞芝堂上春。", "回首瓊林拚一醉，使還總是鳳池人。"]'),
('b17301a5-75ee-4c53-a9bb-157cfcb6c2ce','宴交代權贛州孫提刑致語口號  其一','文天祥','宋','宋诗','song-poetry','','[]','麾節東南會一堂，蘭亭昨日記流觴。',64,'全唐诗/poet.song.239000.json','["麾節東南會一堂，蘭亭昨日記流觴。", "六絲星度銀潢影，五綵春浮玉翠香。", "院柳舊雲懷燕語，野華新雨挹虹光。", "鳳池對秉他年事，佇看天街接佩淚。"]'),
('e8bc2d44-1c21-4178-bd60-f13b34a6b85e','宴交代權贛州孫提刑致語口號  其二','文天祥','宋','宋诗','song-poetry','','[]','簾影晴絲落舞茵，崆峒雲晚聚星辰。',64,'全唐诗/poet.song.239000.json','["簾影晴絲落舞茵，崆峒雲晚聚星辰。", "翠虹光度樓臺月，香燕先浮霄漢春。", "一道清風華轡遠，雙江綠水綵衣新。", "相逢屢有朝花約，又看貂蟬會紫宸。"]'),
('29c66455-910c-49a7-9419-e338ff8a2017','題古磵','文天祥','宋','宋诗','song-poetry','','[]','市腰石有千年磵，石眼泉無一日乾。',32,'全唐诗/poet.song.239000.json','["市腰石有千年磵，石眼泉無一日乾。", "天下蒼生應有望，不知龍向此中蟠。"]'),
('71619788-3cc2-4514-8d5e-87619c925813','懷友人二首  其一','文天祥','宋','宋诗','song-poetry','','[]','久要何落落，末路重依依。',48,'全唐诗/poet.song.239000.json','["久要何落落，末路重依依。", "風雨連兵幕，泥途滿客衣。", "人間龍虎變，天外燕鴻違。", "死矣煩公傳，北方人是非。"]'),
('2daeca62-c19f-4518-8e70-dcae3d79ca2e','懷友人二首  其二','文天祥','宋','宋诗','song-poetry','','[]','涯海真何地，驅來坐戰場。',48,'全唐诗/poet.song.239000.json','["涯海真何地，驅來坐戰場。", "家人半分合，國事决存亡。", "一死不足道，百憂何可當。", "故人髯似戟，起舞爲君傷。"]'),
('ef0af8ce-bc36-4bb1-a40c-3077e03ebef7','寄題琴高臺','文天祥','宋','宋诗','song-poetry','','[]','涇水紺以深，古有神人潛。',96,'全唐诗/poet.song.239000.json','["涇水紺以深，古有神人潛。", "靈鮪煦春藻，微波漾幽瀾。", "朝岑翳長嵐，暮汛暖蒼烟。", "回首宋康王，子今定何年。", "飛僊已高邁，遺蹤落清淵。", "至今空山夜，泠泠琴上絃。", "西瞻晻靄中，霞光輝遠天。", "何當駕長風，一睨涇水漣。"]'),
('8c883ada-d8b7-4a1c-a04e-641a95530cea','揚州城下賦','文天祥','宋','宋诗','song-poetry','','[]','黯雲霜霧暗扶桑，半壁東南盡雪霜。',32,'全唐诗/poet.song.239000.json','["黯雲霜霧暗扶桑，半壁東南盡雪霜。", "壯氣不隨天地變，笑騎飛鶴入維揚。"]'),
('f28f73f4-7b70-4541-956d-28fbd710c288','書汪水雲詩後','文天祥','宋','宋诗','song-poetry','','[]','南風之薰兮琴無弦，北風其凉兮詩無傳。',36,'全唐诗/poet.song.239000.json','["南風之薰兮琴無弦，北風其凉兮詩無傳。", "雲之漢兮水之淵，佳哉斯人兮水雲之仙。"]'),
('55dce46e-52c4-4ba9-9835-5d91ef202664','明堂慶成詩  其一','文天祥','宋','宋诗','song-poetry','','[]','曉移天仗入思成，雨脚先驅御路清。',64,'全唐诗/poet.song.239000.json','["曉移天仗入思成，雨脚先驅御路清。", "虹影倒垂雲氣卷，日輪飛上衮衣明。", "韶音九奏真游格，酌獻三行福酒傾。", "景命有開知未艾，萬年孫子慶純精。"]'),
('ae81fa7f-5fea-464f-8375-b339b75c9d0f','明堂慶成詩  其二','文天祥','宋','宋诗','song-poetry','','[]','清廟嚴更夜未央，珠星璧月璨殊光。',64,'全唐诗/poet.song.239000.json','["清廟嚴更夜未央，珠星璧月璨殊光。", "香飄黄道移天步，燭引紅紗轉殿廊。", "祼薦交神諸室醉，駿奔執豆庶羞芳。", "都人報道君王喜，凈覩和鑾入建章。"]'),
('b41ed38f-cbf8-413f-8cdd-a564800c17e0','明堂慶成詩  其三','文天祥','宋','宋诗','song-poetry','','[]','淳熙稽古再明禋，制作規模汶上新。',64,'全唐诗/poet.song.239000.json','["淳熙稽古再明禋，制作規模汶上新。", "未植羽旄朝萬國，首將玉幣薦三神。", "靈車欲下天先雨，御幄虛張帝在茵。", "熙事告成中外賀，與民同樂霈恩均。"]'),
('0cb41bd1-a433-4357-be1c-ea43350000c2','明堂慶成詩  其四','文天祥','宋','宋诗','song-poetry','','[]','皇心寅畏格皇天，旱歲俄書大有年。',64,'全唐诗/poet.song.239000.json','["皇心寅畏格皇天，旱歲俄書大有年。", "報本愈嚴陽館祀，慶成復第從臣篇。", "祠官瑞紀靈光燭，太史星占貫索捐。", "黼座正中圖貢上，萬方歸德更乾乾。"]'),
('7702721a-5c9d-4fda-920d-90db154c3094','至溫州','文天祥','宋','宋诗','song-poetry','','[]','晏歲著脚來東甌，始覺坤軸東南浮。',240,'全唐诗/poet.song.239000.json','["晏歲著脚來東甌，始覺坤軸東南浮。", "百川同歸無異脈，有如天子朝諸侯。", "何年飛落兩巨石，孤撐骯髒分江流。", "初疑鍊失女媧手，又疑釣脫任公鈎。", "馮夷海若不敢有，涌出精舍如蓮舟。", "樓高百尺蜃吐氣，塔聳雙角龍昂頭。", "蒲牢撞撞鼉坎坎，潮聲滾滾風颼颼。", "沙高峰頂德門住，海門山上焦公留。", "長淮在望鐵甕近，大浪不洗英雄愁。", "孰知隸古百粵地，今爲禮樂衣冠州。", "池塘芳草年年綠，謝公勝事遺江樓。", "藍田無纇蟾架夜，黄金作顆人家秋。", "客帆渺茫拂宸極，漁舠散漫輕鳬鷗。", "麗天紅日起初浴，五雲扶上烟氛收。", "孤臣涕泗如此水，恨不從帝崆峒遊。"]'),
('a166f10d-a5f5-40b2-a34e-37fa84edd35f','送河間晁寺丞','文天祥','宋','宋诗','song-poetry','','[]','公孫富文墨，名字世多知。',48,'全唐诗/poet.song.239000.json','["公孫富文墨，名字世多知。", "談笑取高第，弦歌當此時。", "臨河薪石費，近塞繭絲移。", "緩急當愁此，看君有所爲。"]'),
('18aa0930-e567-4d78-af54-3e1643f0548c','太白樓  其一','文天祥','宋','宋诗','song-poetry','','[]','高城蘸雲根，聊可慰心跡。',48,'全唐诗/poet.song.239000.json','["高城蘸雲根，聊可慰心跡。", "長風萬里來，如對騎鯨客。", "監州好事者，樹此樓與石。", "隆鼻號金仙，更長漫嗟惜。"]'),
('00188cae-6b6d-4ed9-9b20-8376696c7564','太白樓  其二','文天祥','宋','宋诗','song-poetry','','[]','揚子江心第一泉，南金來此鑄文淵。',32,'全唐诗/poet.song.239000.json','["揚子江心第一泉，南金來此鑄文淵。", "男兒斬却樓蘭首，閑品茶經拜羽仙。"]'),
('1df0f693-6d75-41b2-8231-e3ef88edc1f9','臨岐餞別','文天祥','宋','宋诗','song-poetry','','[]','聖恩優許力求田，把酒臨岐餞一杯。',64,'全唐诗/poet.song.239000.json','["聖恩優許力求田，把酒臨岐餞一杯。", "臺閣是非遠已矣，乾坤俯仰愧何哉。", "竟追范蠡歸湖去，不管胡兒放馬來。", "强圉倘殷如孔棘，也應定策救時危。"]'),
('264cf130-0a40-4876-b15c-951a78763c5d','夜宿青原寺感懷','文天祥','宋','宋诗','song-poetry','','[]','松風一榻雨蕭蕭，萬里封疆夜寂寥。',32,'全唐诗/poet.song.239000.json','["松風一榻雨蕭蕭，萬里封疆夜寂寥。", "獨坐瑶琴悲世慮，君恩猶恐壯懷消。"]'),
('24ad9e58-8c13-402c-9570-287766db9744','贈黄終晦','文天祥','宋','宋诗','song-poetry','','[]','釣魚船上聽吹笛，煨芋爐頭看下棋。',64,'全唐诗/poet.song.239000.json','["釣魚船上聽吹笛，煨芋爐頭看下棋。", "賸有晚愁歸別浦，已無春夢到端闈。", "去年尚憶桃紅處，好景重逢橘綠時。", "珍重山人招隠意，猿啼鶴嘯白雲飛。"]'),
('7c3e089a-cdd5-48ab-807b-11570aa0b800','句','文天祥','宋','宋诗','song-poetry','','[]','一片黄雲萬頃田，江南父老慶豐年。',16,'全唐诗/poet.song.239000.json','["一片黄雲萬頃田，江南父老慶豐年。"]'),
('b22854c0-77d4-48d8-979a-be6592730d84','黄山聽琴','文天祐','宋','宋诗','song-poetry','','[]','歲晏抱琴入室處，榾柮燒殘聽風雨。',96,'全唐诗/poet.song.239000.json','["歲晏抱琴入室處，榾柮燒殘聽風雨。", "有客五弦彈太古，掃空恩怨不兒女。", "汙樽抔飲擊土鼓，如與羲軒相對語。", "又如重華坐舜皋，萬物長養不苦窳。", "聞君澹然太古音，感君悠悠太古心。", "古心古音誰能識，應向松濤處處尋。"]'),
('b07ebdb1-42e7-4f20-abc5-ec9383dc46a1','別黄山','文天祐','宋','宋诗','song-poetry','','[]','黄山別去恨綿綿，華表重尋第幾巔。',64,'全唐诗/poet.song.239000.json','["黄山別去恨綿綿，華表重尋第幾巔。", "馬跡苔肥連碧漢，龍潭水暖漲靈泉。", "斷無花逐桃溪外，別有春留藥圃邊。", "鶗鴂一聲人亦老，鬢絲驚笑玉顔仙。"]'),
('37422e6b-da02-4b10-9f40-b59948028d1a','存目','文天祐','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','詩題：送人往湖南首句：雁抱秋月洞庭邊。',19,'全唐诗/poet.song.239000.json','["詩題：送人往湖南首句：雁抱秋月洞庭邊。"]'),
('724e6800-72e1-4f2c-95d9-998160865639','漁父醉  其一','黄今是','宋','宋诗','song-poetry','','[]','青烟何處淡孤洲，有客經年業一鈎。',32,'全唐诗/poet.song.239000.json','["青烟何處淡孤洲，有客經年業一鈎。", "芳草渡頭新貰酒，碧雲天際已歸舟。"]'),
('c70b2581-8444-4034-8796-4052c3c51a20','漁父醉  其二','黄今是','宋','宋诗','song-poetry','','[]','丹楓萬點照人緋，鱸鱠千絲带水肥。',32,'全唐诗/poet.song.239000.json','["丹楓萬點照人緋，鱸鱠千絲带水肥。", "花影芙蓉江上酒，佳人誰喚醉翁歸。"]'),
('a0f379a3-8212-4ad4-8ce4-9b84f40e42c5','漁父醉  其三','黄今是','宋','宋诗','song-poetry','','[]','天淡瀟湘南北家，花隨流水水流花。',32,'全唐诗/poet.song.239000.json','["天淡瀟湘南北家，花隨流水水流花。", "一竿明月何人會，又逐虛船過白沙。"]'),
('0d39d243-5957-4408-b984-a0cf558bf4df','漁父詞','黄今是','宋','宋诗','song-poetry','','[]','簑衣箬笠更無華，蓼岸蘋洲亦有家。',32,'全唐诗/poet.song.239000.json','["簑衣箬笠更無華，蓼岸蘋洲亦有家。", "風雨滿天愁不動，隔江猶唱後庭花。"]'),
('3ccbb772-92a3-4c51-b8ac-7e473f07d534','歸建溪','鄢玉庭','宋','宋诗','song-poetry','','[]','歸去寒溪覓舊盟，相逢詩酒足娛情。',32,'全唐诗/poet.song.239000.json','["歸去寒溪覓舊盟，相逢詩酒足娛情。", "閒雲不礙青山好，物外風高夢自清。"]'),
('cb09e28e-97fd-4ab9-93c8-cdc86343294a','臨終口占','趙孟僴','宋','宋诗','song-poetry','','[]','王室之懿，文山之客。',20,'全唐诗/poet.song.239000.json','["王室之懿，文山之客。", "持此寸心，千古忠赤。"]'),
('bb59582b-82ad-4deb-9905-f2dbcf87dc35','句','蕭敬夫','宋','宋诗','song-poetry','','[]','八風捲地翻雷雨，萬甲從天驟雪騣。',16,'全唐诗/poet.song.239000.json','["八風捲地翻雷雨，萬甲從天驟雪騣。"]'),
('a50c0c59-2b90-4a37-bef1-9a2558bdcbd1','句','杜抑之','宋','宋诗','song-poetry','','[]','雷霆真自地中出，河漢莫從天上翻。',16,'全唐诗/poet.song.239000.json','["雷霆真自地中出，河漢莫從天上翻。"]'),
('7b0ac0a2-7481-4a54-a104-e7f970be638f','詩美校書郎彭方迥','黄莊','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','廬陵間氣歐陽公，宗主文脈魁蘭宮。',272,'全唐诗/poet.song.239000.json','["廬陵間氣歐陽公，宗主文脈魁蘭宮。", "給札詔來簡眷濃，職居館閣譽望隆。", "聖明天子是仁宗，拔賢招俊萃羣工。", "希文何爲去匆匆，諫官不言祗蔽蒙。", "惟公壁立秉精忠，獨抱鯾論心忡忡。", "顯責若訥極匪躬，飄然夷陵凜高風。", "高風凜冽誰能同，地靈人傑國不空。", "魁名自見六一翁，翱翔天祿名尤崇。", "忠肝義膽何其雄，憤彼陰邪後內訌。", "崇論宏議要力攻，責彼諫者達四聰。", "摧姦擊佞深有功，吁嗟衆目昏如蒙。", "劃然見此光瞳瞳，吁嗟衆耳塞如聾。", "轟然聞此聲渢渢，丹心一片對穹窿。", "名齊歐老壓岱宗，頼有諫臣鑒由中。", "賢相意與公議融，全名不作夷陵窮。", "公心豈計窮與通，使我躍起激懦衷。", "賢哉兩魁碩且洪，仁山突兀文水淙。"]'),
('268ff7b3-da7e-4585-a987-05a48c7b389e','送文安撫出師','文天祥士友','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','出師自古尚張皇，何况長江恣擾攘。',64,'全唐诗/poet.song.239000.json','["出師自古尚張皇，何况長江恣擾攘。", "聞道義旗離漕口，已驅北騎走池陽。", "先將十萬來迎敵，最好諸軍自裹糧。", "說與無知饒舌者，文魁元不是猖狂。"]'),
('514e4128-7e73-47d6-a3e7-d4e1125a4c8e','美文文山劾董宋臣','開慶太學生','宋','宋诗','song-poetry','','["\u897f\u6e56"]','撥轉天綱回地紀，中興又自庚申始。',304,'全唐诗/poet.song.239000.json','["撥轉天綱回地紀，中興又自庚申始。", "掃除陰類誰之功，有硬脊梁擔得起。", "鯫生曾作茶嶺詩，已學希夷不願仕。", "逢人見說太平時，擔書來領西湖水。", "幽陰何物號閻羅，汙我青天莫敢指。", "國人咸懼妖復來，天子自知忠可使。", "履齋泉下不伏款，帝謂董賢人切齒。", "未聞蔡筆頌余公，但見歐書責高子。", "揚揚顔面見士夫，不知世間有羞耻。", "吁嗟今世負大名，祿重忠言類如是。", "一身富貴盡有餘，何况明明今在邇。", "中書雖有空頭敕，其奈諸名都唯唯。", "五更魁宿炳光精，吐出忠肝涕盈紙。", "心懷寸鐵飛上天，願剔剛腸開帝視。", "彷徨竈婢爲主驚，慷慨書生爲國喜。", "吾皇英斷似孝宗，覿有天誅終棄死。", "當時頼有政府賢，彈淚妖狐與羸豕。", "家奴猥瑣何足云，中丞舉動可惜爾。", "慶曆諸公聞此詩，勿謂予禍始於此。"]'),
('21155d35-6daa-4681-8595-581d1ee9ca93','挽文丞相','黄繼善','宋','宋诗','song-poetry','','[]','三百餘年樂育恩，晚從科目得斯人。',64,'全唐诗/poet.song.239000.json','["三百餘年樂育恩，晚從科目得斯人。", "崎嶇嶺海期年國，零落氈毛萬死身。", "諸葛未亡猶有漢，包胥欲泣更無秦。", "挑燈忼慨歌梁父，鬢髮蕭森悚鬼神。"]'),
('ca98fb27-a2b3-446d-bc4e-83614d796774','出鄉','陳炎','宋','宋诗','song-poetry','','[]','筍輿摇兀去程賒，嶺路羊腸狹且斜。',64,'全唐诗/poet.song.239000.json','["筍輿摇兀去程賒，嶺路羊腸狹且斜。", "祇見萬山迷眼界，正無多地看人家。", "當庭鋤土栽桑柘，成級開田種麥麻。", "可喜此邦皆務實，學儒學稼是生涯。"]'),
('e6c72838-020d-4103-b391-68d9009a5159','辭家廟','趙淮','宋','宋诗','song-poetry','','[]','祖父有功王室，德澤沾及子孫。',56,'全唐诗/poet.song.239000.json','["祖父有功王室，德澤沾及子孫。", "今淮計窮被執，誓以一死報君。", "刀鋸置之不問，萬折忠義常存。", "急告先靈速引，庶幾不辱家門。"]'),
('08e57924-60d7-40cb-9952-e2090e6375fe','挽族子老成','陳公榮','宋','宋诗','song-poetry','','[]','邊城將星落，浩蕩烟塵黄。',120,'全唐诗/poet.song.239000.json','["邊城將星落，浩蕩烟塵黄。", "我亦在行陣，生死未可量。", "涕滂感永訣，激烈摧肝腸。", "昔爾仗雄劍，志在清八荒。", "神武埒頗牧，奇計如平良。", "遇賊奮英果，逐殺何其强。", "氣數乖人事，竟向鋒刃僵。", "忠魂薄日月，耿耿萬古光。", "雖云獲死所，國恥猶未忘。", "便應作厲鬼，虜酋罄殺傷。"]'),
('99d0463e-3c3e-4ea8-8b23-f5b724e9fc3c','紀游','張庭薦','宋','宋诗','song-poetry','','[]','馬行諳舊路，鷄唱認層巔。',48,'全唐诗/poet.song.239000.json','["馬行諳舊路，鷄唱認層巔。", "洞口有桃處，江村欲雪天。", "熏爐香琬刻，洗杓汲靈泉。", "我愛長留此，山深日似年。"]'),
('f66acee3-bca0-44b3-bd1d-bf3745d0187d','山居','陳某','宋','宋诗','song-poetry','','[]','白雲護危屋，遥隔世人家。',48,'全唐诗/poet.song.239000.json','["白雲護危屋，遥隔世人家。", "野逕不多竹，幽蘭自作花。", "敝衣僧說法，枯葉樹成槎。", "門外禽相狎，雙雙浴晚沙。"]'),
('2c99e2a8-c254-4ce9-b9ca-c58926aea841','湘靈鼓瑟','陳某','宋','宋诗','song-poetry','','[]','蒼梧雲杳杳，湘浦月沈沈。',60,'全唐诗/poet.song.239000.json','["蒼梧雲杳杳，湘浦月沈沈。", "誰將竹間淚，彈成絲上音。", "如怨復如訴，可聽不可尋。", "乃知二帝子，尚懷千載心。", "君臣等天地，死生空古今。"]'),
('268a0853-dccf-4651-b6c9-7f35525948b0','貧居','陳某','宋','宋诗','song-poetry','','[]','秋風山木飛，秋日獨行時。',48,'全唐诗/poet.song.239000.json','["秋風山木飛，秋日獨行時。", "身共衣冠老，妻嫌富貴遲。", "自分澆菊水，閒寫咏貧詩。", "此意不可說，夜窗明月知。"]'),
('2680e6b3-492c-48a4-b69a-7b28791c7d63','江心寺','陳某','宋','宋诗','song-poetry','','[]','誰把袈裟築半峰，倚雲樓閣打天鐘。',64,'全唐诗/poet.song.239000.json','["誰把袈裟築半峰，倚雲樓閣打天鐘。", "東西塔上自分嶼，風雨聲中忽見龍。", "隔岸愁吹孤戍角，歸鴉寒立夕陽松。", "舊時行殿成荒土，烟草萋萋暝色重。"]'),
('915d3262-aef5-4cbc-ab9e-15205b46d7e2','閩嶠軍中','陳某','宋','宋诗','song-poetry','','[]','翠華齊擁霍嫖姚，却向青山說豹韜。',64,'全唐诗/poet.song.239000.json','["翠華齊擁霍嫖姚，却向青山說豹韜。", "兵馬夜行殘月下，弓旌寒響朔風高。", "壺漿故老愁啼血，野飯將軍猛茹毛。", "自笑書生隨玉帳，也腰刀劍束征袍。"]'),
('459d34cf-f3bc-4d3a-aeb7-cac8a67d9721','秋興','陳某','宋','宋诗','song-poetry','','[]','禾黍離離雨滿村，望中兵火幾家存。',64,'全唐诗/poet.song.239000.json','["禾黍離離雨滿村，望中兵火幾家存。", "荒城半是征人骨，秋月偏驚旅客魂。", "豈意戰塵臨老見，不知心事向誰論。", "抱茅蓋得青山屋，多種桃花映酒樽。"]'),
('f26e3044-e1e4-4521-9d37-c7a0dca1ceea','王宗起城南溪屋','陳某','宋','宋诗','song-poetry','','[]','水上小亭清更新，綠陰紈扇白綸巾。',64,'全唐诗/poet.song.239000.json','["水上小亭清更新，綠陰紈扇白綸巾。", "豈無修竹娛佳客，却有清風來故人。", "老樹秋聲凉入骨，澄江波影玉生鱗。", "讀書偏愛虛窗靜，不管門前庾亮塵。"]'),
('790906d7-fd60-4819-ad1d-b70b736d2b12','泉南滿歸過省下呈友人','陳某','宋','宋诗','song-poetry','','[]','二月泉南驛騎回，亂離懷抱爲君開。',64,'全唐诗/poet.song.239000.json','["二月泉南驛騎回，亂離懷抱爲君開。", "雙鳬暫假王喬力，百里空淹蔣琬才。", "省幙薇陰遮案靜，溪船山色入樓來。", "應知別後遥相憶，清夜吹簫月滿臺。"]'),
('20a0b47f-d0ee-480a-8c1a-978040c64dcf','訪陳彥太不遇','陳某','宋','宋诗','song-poetry','','[]','每憶可人陳太丘，不辭山路遠追遊。',64,'全唐诗/poet.song.239000.json','["每憶可人陳太丘，不辭山路遠追遊。", "清霜拂鬢雞聲早，白鶴橫江月影浮。", "豈爲開樽無北海，虛聞懸榻待南州。", "題詩興盡空歸去，回首梅花百尺樓。"]'),
('ac376b6a-b16c-4b27-b0ec-60300891dbfe','九日次王善夫韻','陳某','宋','宋诗','song-poetry','','[]','道路多荆棘，塵埃滿客衣。',48,'全唐诗/poet.song.239000.json','["道路多荆棘，塵埃滿客衣。", "西風九日至，往事百年非。", "王粲思何切，馮驩嘆未歸。", "只因江漢遠，却使雁鴻稀。"]'),
('c0ccdb01-f28c-470e-9bc6-1a19926d6ab5','小景','陳某','宋','宋诗','song-poetry','','[]','山迥雲垂野，江空水接天。',48,'全唐诗/poet.song.239000.json','["山迥雲垂野，江空水接天。", "西風陶令宅，落日季鷹船。", "愁緒丹心外，歸心白雁前。", "如何倦遊客，猶是未歸年。"]'),
('f66ca70a-cca9-40b5-992a-fa8663579e40','宋奧寄友','陳某','宋','宋诗','song-poetry','','[]','落日猶未落，青山還自青。',48,'全唐诗/poet.song.239000.json','["落日猶未落，青山還自青。", "鳥飛雲外見，泉過竹邊聽。", "童子求新汲，先生守舊扃。", "相看不相見，應註太玄經。"]'),
('1378174c-3afa-4820-8a04-160f078dce00','病中聞歌有感','陳某','宋','宋诗','song-poetry','','[]','伏枕已三月，清明節已過。',48,'全唐诗/poet.song.239000.json','["伏枕已三月，清明節已過。", "光陰流水去，風雨落花多。", "病久難禁酒，愁深懶聽歌。", "門前舟楫動，無奈客懷何。"]'),
('4f38332d-b2c3-4f6d-a5e6-a12bb699cf32','趙仲瑜小景  其一','陳某','宋','宋诗','song-poetry','','[]','遠水望不極，斷雲低復連。',48,'全唐诗/poet.song.239000.json','["遠水望不極，斷雲低復連。", "青山秋樹屋，野渡夕陽船。", "幽思滄洲上，歸心白雁前。", "異鄉非隠地，聊欲寄林泉。"]'),
('8625f830-84e1-4d5d-80e1-c977144f32b6','趙仲瑜小景  其二','陳某','宋','宋诗','song-poetry','','[]','老樹依巖壑，危橋隔遠村。',48,'全唐诗/poet.song.239000.json','["老樹依巖壑，危橋隔遠村。", "桃花春滿岸，雲氣曉當門。", "白鳥來書屋，青山落酒樽。", "漁舟忽相過，疑是武陵源。"]'),
('57cc93c0-7200-4094-bd38-2d2e0da0dd19','官舍有感','陳某','宋','宋诗','song-poetry','','[]','臘近衣方授，山深寒愈嚴。',48,'全唐诗/poet.song.239000.json','["臘近衣方授，山深寒愈嚴。", "病將書卷廢，愁伏酒杯添。", "故里風塵隔，微官歲月淹。", "思歸歸未得，低首愧陶潛。"]'),
('64271dba-cbfd-4def-b6f1-2158611e341e','王生小景','陳某','宋','宋诗','song-poetry','','[]','何處佳山水，依稀類輞川。',48,'全唐诗/poet.song.239000.json','["何處佳山水，依稀類輞川。", "春風摩詰畫，夜月剡溪船。", "雲樹鄉心外，鶑花客淚邊。", "不嫌茅屋小，應喜是歸年。"]'),
('f400d4be-017a-454d-a436-b2986d212297','秋夜風雨次韻','陳某','宋','宋诗','song-poetry','','[]','獨卧苦不寐，燈殘知夜深。',48,'全唐诗/poet.song.239000.json','["獨卧苦不寐，燈殘知夜深。", "青氈猶是客，白髮最關心。", "遶屋鳥三匝，隔江龍一吟。", "誰家催寄遠，孤淚滴清砧。"]'),
('138cd158-29da-4fcf-8f14-3f7aa5ed0b56','中秋客邸感懷','陳某','宋','宋诗','song-poetry','','[]','今夜天邊月，誰期海上看。',48,'全唐诗/poet.song.239000.json','["今夜天邊月，誰期海上看。", "家山雖間隔，兒女暫團欒。", "露重銀蟾濕，風清玉宇寒。", "年年長是客，强把一樽歡。"]'),
('f0a1f202-7c3d-460c-b130-9184673e5071','偶成  其一','陳某','宋','宋诗','song-poetry','','[]','滑滑春泥塞路途，漫漫新水漲江湖。',32,'全唐诗/poet.song.239000.json','["滑滑春泥塞路途，漫漫新水漲江湖。", "出門世路皆行險，只好山林聽鷓鴣。"]'),
('e1981f81-84f0-451c-9fb8-e5d0a856f49d','偶成  其二','陳某','宋','宋诗','song-poetry','','[]','南山作雨北山雲，野哭村歌處處聞。',32,'全唐诗/poet.song.239000.json','["南山作雨北山雲，野哭村歌處處聞。", "淮岱十年多盜賊，誰知一半是官軍。"]'),
('e807d208-c04d-43da-99ea-10ab66ae83e6','偶成  其三','陳某','宋','宋诗','song-poetry','','[]','城南春深草亂飛，門前流水沒漁磯。',32,'全唐诗/poet.song.239000.json','["城南春深草亂飛，門前流水沒漁磯。", "百年此地踏青客，今歲從軍猶未歸。"]'),
('fa321d80-45d4-4405-b4a6-d1305c7fc5e7','回回僧','陳某','宋','宋诗','song-poetry','','[]','秋風響耳環，古怪聚人看。',48,'全唐诗/poet.song.239000.json','["秋風響耳環，古怪聚人看。", "赤脚行霜地，腥身禮月壇。", "儋齋猶買肉，掛帛不遮寒。", "亦有西來意，相逢欲語難。"]'),
('f5c60b75-4eb5-427c-ba13-5cbd18b4b00f','羅浮山','陳某','宋','宋诗','song-poetry','','[]','乾坤未失鹿，滄海欲飛灰。',48,'全唐诗/poet.song.239000.json','["乾坤未失鹿，滄海欲飛灰。", "人已逃時去，山猶擇地來。", "寒流清有影，怪木老非梅。", "西有龍翔寺，禪門徹夜開。"]'),
('3d8a6e7b-2e9b-40a2-b2ca-31c08414a918','夜歸','陳某','宋','宋诗','song-poetry','','[]','青松行未盡，林外一鐘聞。',48,'全唐诗/poet.song.239000.json','["青松行未盡，林外一鐘聞。", "小雨不傷月，西風忽破雲。", "棹歸秋水遠，鄰語夜燈分。", "稚子能無寐，空齋讀古文。"]'),
('4cf8d663-a44b-4185-8322-92607c771d8b','相士俞方塘','江愷','宋','宋诗','song-poetry','','[]','方塘之鑒形可識，方諸之鑑心始得。',51,'全唐诗/poet.song.239000.json','["方塘之鑒形可識，方諸之鑑心始得。", "相形何如更論心，以貌取人當有失。", "君不見虞皇項籍兩重瞳，成湯曹交皆九尺。"]'),
('f6e400fb-3262-47e5-8604-a3771f58374b','題泖居','殷澄','宋','宋诗','song-poetry','','[]','國破不共天，軍行却掃地。',24,'全唐诗/poet.song.239000.json','["國破不共天，軍行却掃地。", "一言活萬人，三泖終吾志。"]'),
('535ebff4-43be-4269-8a69-0bed832c7b02','水國','皇甫明子','宋','宋诗','song-poetry','','[]','水國凄凉住，秋宵爛熳眠。',48,'全唐诗/poet.song.239000.json','["水國凄凉住，秋宵爛熳眠。", "歸雲猶带雨，墮月忽明船。", "社稷資長算，髭鬚近莫年。", "亂離棲不定，百口託浮田。"]'),
('a138d5f3-c81a-4bc8-a421-658dc7fb3070','海口','皇甫明子','宋','宋诗','song-poetry','','[]','窮島迷孤青，颶風盪頑寒。',96,'全唐诗/poet.song.239000.json','["窮島迷孤青，颶風盪頑寒。", "不知是海口，萬里空波瀾。", "蛟龍恃幽沈，怒氣雄屈蟠。", "崢嶸抉秋陰，挂席潮如山。", "熒惑表南紀，天去何時還。", "雲旗光慘澹，腰下青琅玕。", "誰能居甬東，一死諒非難。", "嗚呼朝宗意，會見桑土乾。"]'),
('47958306-21a9-49c1-ba06-6e0cfbe27e4c','京口行','皇甫明子','宋','宋诗','song-poetry','','[]','京口兵可用，酒可飲。',58,'全唐诗/poet.song.239000.json','["京口兵可用，酒可飲。", "一語參差族成血，忠賊相持各凜凜。", "豈知好醜隔形骸，父爲孔鸞子爲鴆。", "人衆天定理則那，遺臭流芳且高枕。"]'),
('0c5064be-7fdd-4f76-92a2-e923ed762e8d','雙頭蘭和吳應奉韻','金似孫','宋','宋诗','song-poetry','','[]','手種盆蘭香滿庭，閒來趣味獨幽深。',64,'全唐诗/poet.song.239000.json','["手種盆蘭香滿庭，閒來趣味獨幽深。", "敢誇雙萼鍾奇氣，祇恨孤根出晚林。", "長倩生男不得力，滕公有女謾縈心。", "援琴欲和春風曲，却對騷魂費苦吟。"]'),
('697ce98b-9182-4677-95d2-3d74c2c0623e','句','寶祐士人','宋','宋诗','song-poetry','','[]','空使蜀人思董永，恨無漢劍斬丁公。',16,'全唐诗/poet.song.239000.json','["空使蜀人思董永，恨無漢劍斬丁公。"]'),
('9123c0f6-3fb1-4216-baab-bcdc29e590d2','嚴峙釣臺','朱清','宋','宋诗','song-poetry','','[]','誰著羊裘探故人，客星炯炯照天文。',32,'全唐诗/poet.song.239000.json','["誰著羊裘探故人，客星炯炯照天文。", "嚴陵磯下桐江水，流到東山一色清。"]'),
('5e5ca948-4e32-43c0-be5c-6255b5ed6e09','瓜橋競渡','朱清','宋','宋诗','song-poetry','','[]','東吳霸業已成然，渡口瓜畦澤未乾。',32,'全唐诗/poet.song.239000.json','["東吳霸業已成然，渡口瓜畦澤未乾。", "爲問曩時仙在否，何堪雲樹鶴蹁躚。"]'),
('bee0cc89-7298-404e-90aa-bf3b7d521d88','題秩巴寨','朱汝賢','宋','宋诗','song-poetry','','[]','十大曲破寰海知，六么對舞纖腰肢。',256,'全唐诗/poet.song.239000.json','["十大曲破寰海知，六么對舞纖腰肢。", "秩巴古寨士解圍，譜傳建業隆興時。", "天匏作腔豺臠皮，竹撩裊繞疊指麾。", "慢曲出入和柘枝，四部中分聲遞隨。", "行齊氣勇拍趁吹，妙伎那教呈健兒。", "忽然錦袖左抱持，伸拳俯拜當階墀。", "三臺撾皷徹送之，我聞此樂來西陲。", "恩濃四沐需雲期，君仁先祝慈闈慈。", "壽崇蟠桃慶瑶池，乾會佳節等翼箕。", "國安磐石民恬熙，不忘武事功平夷。", "臣微鰲抃同熊羆，附庸此日江之西。", "時人入耳鄭衛漓，播鼗擊磬今奚師。", "舊樂之半見絕稀，十有二數存音儀。", "紅裙擲毬顔忸怩，採蓮况欲追耶溪。", "樂明美報意遠而，兩宮睿筭南山齊。", "偶然問答成歌詩，於萬斯年陪壽巵。"]'),
('86df295f-0aed-45b4-9763-fc033b5c90e4','樓臺烟雨亭','朱汝賢','宋','宋诗','song-poetry','','[]','神息馭兮龍岡，殿金仙兮廟傍，結軒楹兮受釐舉觴。',93,'全唐诗/poet.song.239000.json','["神息馭兮龍岡，殿金仙兮廟傍，結軒楹兮受釐舉觴。", "發山川兮秘藏，覽旴源兮一方，臺突兀兮樓棟翔。", "人祀神兮敬將，神福民兮簡穰，晴烟晦雨兮相爾農桑。", "繫平西兮桐鄉，吾去留兮敢忘，願培嘉植兮松虬竹蒼。"]'),
('6ce193a0-a20a-42fa-9eee-486c70611aaf','題素女石','朱汝賢','宋','宋诗','song-poetry','','[]','舊聞素女出天井，坐石曉梳青髻絲。',64,'全唐诗/poet.song.239000.json','["舊聞素女出天井，坐石曉梳青髻絲。", "碧湫一笑入深窈，靈篆朱書來命遲。", "冷鐘晨夢聽飄灑，愛物不遣雷車隨。", "陰雲未駁潤澤廣，民豈能忘心已知。"]'),
('d7a553b5-443a-4850-a450-7fdb3c13ffa0','憶梅','虞薦發','宋','宋诗','song-poetry','','[]','不見疏花久，悽然恨滿襟。',48,'全唐诗/poet.song.239000.json','["不見疏花久，悽然恨滿襟。", "相逢當歲晚，一別又春深。", "冷落山中約，凄凉月下心。", "期君須待雪，把酒候前林。"]'),
('f98b17c0-520d-49c2-83c1-29c450b71da9','武夷山','范師孔','宋','宋诗','song-poetry','','[]','幾與溪山絕世緣，重來猿鳥只依然。',64,'全唐诗/poet.song.239000.json','["幾與溪山絕世緣，重來猿鳥只依然。", "懸崖野瀑飄成雪，近午嵐飛暗盡天。", "水尚未疏須識禹，山如深入定逢仙。", "洞中石鼎烹雲處，此夜還來借榻眠。"]'),
('c69859b2-aba3-418b-b1f2-102981365cf8','高樓','范師孔','宋','宋诗','song-poetry','','[]','高樓高登天，美人美如玉。',96,'全唐诗/poet.song.239000.json','["高樓高登天，美人美如玉。", "美人坐高樓，更彈天上曲。", "飛聲落人間，誰不注耳目。", "安知妾此心，長恐晝夜促。", "莫羨高樓高，莫羨美女美。", "樓頭瞻明月，樓下看流水。", "月明圓易缺，水流去如駛。", "獨愛山中蘭，幽香抱枝死。"]'),
('adf31869-b8a9-4a1b-af7a-fd488f547935','小漿舖','范師孔','宋','宋诗','song-poetry','','[]','一路經行處，盤溪繞僻原。',24,'全唐诗/poet.song.239000.json','["一路經行處，盤溪繞僻原。", "蜂喧花外塢，犬吠竹邊門。"]'),
('dd320833-16e8-4502-9035-39cfee4c8114','宿橫金延慶寺','呂江','宋','宋诗','song-poetry','','[]','水路通城近，人家與寺連。',48,'全唐诗/poet.song.239000.json','["水路通城近，人家與寺連。", "西風漁市鼓，落日野橋船。", "塵土非吾事，湖山似去年。", "今宵禪榻夢，定是到鷗邊。"]'),
('58fc4425-6607-4008-a8fd-fee586ab19f5','姑蘇懷古','呂江','宋','宋诗','song-poetry','','[]','臺成知費幾金槌，回首荒蕪走鹿麛。',64,'全唐诗/poet.song.239000.json','["臺成知費幾金槌，回首荒蕪走鹿麛。", "自是誤君由宰嚭，孰云亡國爲西施。", "春風蝶夢迷香徑，秋水龍文冷劍池。", "四顧湖山烟雨裏，倚闌新恨入支頤。"]'),
('d2d74235-3f2b-42de-b6cd-d105afaeee35','春晚二絕  其一','呂江','宋','宋诗','song-poetry','','[]','春來脚不踏青青，夢裏還家夢又醒。',32,'全唐诗/poet.song.239000.json','["春來脚不踏青青，夢裏還家夢又醒。", "一樹垂楊樓外綠，鶑聲不似故園聽。"]'),
('21559467-0d6c-48f8-8c7d-078562edcb4a','春晚二絕  其二','呂江','宋','宋诗','song-poetry','','[]','年華冉冉暗中移，倦客傷春只自知。',32,'全唐诗/poet.song.239000.json','["年華冉冉暗中移，倦客傷春只自知。", "雨後桃花紅未減，人情早自向荼䕷。"]'),
('4547d6fc-1eff-4df8-b570-3fd2614e8b36','中秋前一日諸生携酒見過對月同賦','呂江','宋','宋诗','song-poetry','','[]','半生道路鬢雙皤，又是中秋客裏過。',64,'全唐诗/poet.song.239000.json','["半生道路鬢雙皤，又是中秋客裏過。", "別業可憐荒杜曲，羈懷最怕聽商歌。", "不知明月幾時有，如此清風良夜何。", "勝概無詩可收拾，九原喚起老東坡。"]'),
('6ea89d28-9eae-4590-a57f-d1cc565aefd3','秋思','呂江','宋','宋诗','song-poetry','','[]','一葉江頭楓葉丹，秋容慘淡客悲酸。',64,'全唐诗/poet.song.239000.json','["一葉江頭楓葉丹，秋容慘淡客悲酸。", "蛩聲雨後長門怨，雁影風前行路難。", "無處著愁嫌地窄，有時舒眺見天寬。", "最憐人道蘇州月，三度中秋一度看。"]'),
('aeb880af-3005-4e6d-94f0-767aba4338eb','石湖懷老仙','呂江','宋','宋诗','song-poetry','','[]','覓得宸奎扁，歸尋農圃師。',48,'全唐诗/poet.song.239000.json','["覓得宸奎扁，歸尋農圃師。", "湖山吳子國，花草范村詩。", "步屨行春遍，綸巾带雨欹。", "百年無此老，合配雪灘祠。"]'),
('25be7623-e6ff-42c3-af2a-f489ff7e22c3','江陰即事','楊蟠','宋','宋诗','song-poetry','','[]','海上帆來何處客，煙中犬吠幾人家。',32,'全唐诗/poet.song.24000.json','["海上帆來何處客，煙中犬吠幾人家。", "雲寒雁影翻紅照，水落鷗群占白沙。"]'),
('8b777277-a448-405d-b71f-8e5fb1f8e248','詩一首','楊蟠','宋','宋诗','song-poetry','','[]','誰與畫圖傳勝跡，忽從詩字得清暉。',32,'全唐诗/poet.song.24000.json','["誰與畫圖傳勝跡，忽從詩字得清暉。", "江山歷歷皆堪數，不記當年幾醉歸。"]'),
('6b0bb062-7a33-48fc-9a52-c59e952eb122','澄江門','楊蟠','宋','宋诗','song-poetry','','[]','獨上高樓望海門，青山幾點送歸船。',64,'全唐诗/poet.song.24000.json','["獨上高樓望海門，青山幾點送歸船。", "寒光淡淡浮紅日，曉色冥冥散白煙。", "浦外落霞爭倦燒，池中流水自鳴弦。", "扶欄下見蓬萊影，一半仙魂在月邊。"]'),
('294acfd6-52c3-47e9-83db-bd86094862d1','玉水堂','楊蟠','宋','宋诗','song-poetry','','[]','小池鷗鷺不成群，池畔蕭然一史君。',32,'全唐诗/poet.song.24000.json','["小池鷗鷺不成群，池畔蕭然一史君。", "時霎醉眠春雨足，覺來衣上有閒雲。"]'),
('ba4e19d0-ee93-4fae-a042-21df84cd8a87','余襄公祠','楊蟠','宋','宋诗','song-poetry','','[]','功業終令萬古傳，豈惟文采動當年。',32,'全唐诗/poet.song.24000.json','["功業終令萬古傳，豈惟文采動當年。", "曲江相繼成雙廟，慶曆同稱有四賢。"]'),
('4df8ae70-574b-43b4-a024-d6923b478c59','吳江長橋','楊蟠','宋','宋诗','song-poetry','','[]','八十丈晴虹卧影，一千頃碧玉無瑕。',32,'全唐诗/poet.song.24000.json','["八十丈晴虹卧影，一千頃碧玉無瑕。", "幾多風月輸詩客，無限葦蘆屬酒家。"]'),
('2e6b8017-6737-4016-816c-bf84861a5d21','長橋','楊蟠','宋','宋诗','song-poetry','','[]','皎皎冰壺里，天寒六月風。',24,'全唐诗/poet.song.24000.json','["皎皎冰壺里，天寒六月風。", "水仙來往處，三島忽相通。"]'),
('1d0cd6d7-eb07-48dd-8c80-d0eaf8bffc4f','孤山','楊蟠','宋','宋诗','song-poetry','','[]','裊裊雲中路，滄浪四面開。',24,'全唐诗/poet.song.24000.json','["裊裊雲中路，滄浪四面開。", "詩人吟不得，喚作小蓬萊。"]'),
('ed5096db-7e9b-4f1e-9f97-71961a9c9764','柏堂','楊蟠','宋','宋诗','song-poetry','','[]','零落雪霜後，猶含千載春。',24,'全唐诗/poet.song.24000.json','["零落雪霜後，猶含千載春。", "一株化爲石，誰是種時人。"]'),
('d5deeb2a-5dbf-4f5b-9cf9-de3d205d3554','金沙井','楊蟠','宋','宋诗','song-poetry','','[]','細細沙痕落，流金在井泉。',24,'全唐诗/poet.song.24000.json','["細細沙痕落，流金在井泉。", "山人邀我飲，化骨共爲仙。"]'),
('81b0d0a6-d772-40a7-9ae6-db7cd863bd4d','巢居閣','楊蟠','宋','宋诗','song-poetry','','[]','昔日巢居客，今爲天上仙。',24,'全唐诗/poet.song.24000.json','["昔日巢居客，今爲天上仙。", "文章流海內，几杖葬山前。"]'),
('83ff821f-4e6b-4a5f-ada3-706801d4b493','瑪瑙坡','楊蟠','宋','宋诗','song-poetry','','[]','石徑生光怪，傳流瑪瑙坡。',24,'全唐诗/poet.song.24000.json','["石徑生光怪，傳流瑪瑙坡。", "天人曾布地，此物至今多。"]'),
('a6ddb559-1418-4324-81f1-8e2613079305','巾子峰','楊蟠','宋','宋诗','song-poetry','','[]','首出群山內，晴窗幾處看。',24,'全唐诗/poet.song.24000.json','["首出群山內，晴窗幾處看。", "不因風雨折，開檻滿溪寒。"]'),
('748eac0c-ddf8-4af5-8c91-af1f11290b7b','南屏山','楊蟠','宋','宋诗','song-poetry','','[]','日落遊人散，山寒起樹聲。',24,'全唐诗/poet.song.24000.json','["日落遊人散，山寒起樹聲。", "玲瓏石上穴，處處有雲生。"]'),
('2ad696e5-f948-40b7-8f6b-a322a44930a5','飛來峰','楊蟠','宋','宋诗','song-poetry','','[]','飛來天竺遠，山秀已含春。',24,'全唐诗/poet.song.24000.json','["飛來天竺遠，山秀已含春。", "不遇名僧識，千年豈有神。"]'),
('699459f0-c5cf-4203-af7a-f88e685dbb71','連巖','楊蟠','宋','宋诗','song-poetry','','[]','岌岌青松外，安知鳥翼孤。',24,'全唐诗/poet.song.24000.json','["岌岌青松外，安知鳥翼孤。", "寒猿三叫罷，便是蜀州圖。"]'),
('ddc285bb-5c56-4179-83bc-26396ab47810','伏龍濺','楊蟠','宋','宋诗','song-poetry','','[]','靜久波濤散，溪深涌亂絲。',24,'全唐诗/poet.song.24000.json','["靜久波濤散，溪深涌亂絲。", "悠悠山下客，將見水停時。"]'),
('e493a06b-a39f-491c-82fd-5adbdb71ffd1','葛塢','楊蟠','宋','宋诗','song-poetry','','[]','此塢久無色，何年朝太真。',24,'全唐诗/poet.song.24000.json','["此塢久無色，何年朝太真。", "曉耕雲下路，猶恐是仙民。"]'),
('a5c7d3bd-b5d5-406d-a655-c25c3cfb6907','朱墅','楊蟠','宋','宋诗','song-poetry','','[]','白雲今不去，惆悵昔人非。',24,'全唐诗/poet.song.24000.json','["白雲今不去，惆悵昔人非。", "葉落風前響，猶疑踏雪歸。"]'),
('cd1f3176-45ef-4b22-8068-b2f6206feeb1','青林巖','楊蟠','宋','宋诗','song-poetry','','[]','鳥外無行迹，寒林引薜蘿。',24,'全唐诗/poet.song.24000.json','["鳥外無行迹，寒林引薜蘿。", "山中僧已老，不信雪霜多。"]'),
('092d6c0d-0a75-4599-83d4-c013d12063a3','理公巖','楊蟠','宋','宋诗','song-poetry','','[]','日月巖前鳥，秋來不復聞。',24,'全唐诗/poet.song.24000.json','["日月巖前鳥，秋來不復聞。", "達人今已化，名繫此山雲。"]'),
('2e7b6352-5b69-43b9-b75f-95fa442c4bd7','呼猿洞','楊蟠','宋','宋诗','song-poetry','','[]','青松愁絕澗，日夜白猿吟。',24,'全唐诗/poet.song.24000.json','["青松愁絕澗，日夜白猿吟。", "掌握多相就，安知世上心。"]'),
('21895dd8-0488-49de-8d01-5f32dfb09c8e','龍泓洞','楊蟠','宋','宋诗','song-poetry','','[]','六月千里旱，偷泉心亦卑。',24,'全唐诗/poet.song.24000.json','["六月千里旱，偷泉心亦卑。", "不煩山老祝，神物久無思。"]'),
('96a001b6-8c3e-4f7c-914a-a48ae150863f','北高峰','楊蟠','宋','宋诗','song-poetry','','[]','杳杳孤峰上，寒陰带遠城。',24,'全唐诗/poet.song.24000.json','["杳杳孤峰上，寒陰带遠城。", "不知山下雨，奎斗自分明。"]'),
('44ccc5bf-4cf2-4846-ad12-f03c19ba48f6','白雲峰','楊蟠','宋','宋诗','song-poetry','','[]','萬頃田間雨，多從頂上生。',24,'全唐诗/poet.song.24000.json','["萬頃田間雨，多從頂上生。", "野人猶不足，常擬鑿爲平。"]'),
('1aee1a1f-f828-4a48-af37-d7120493fb71','南高峰','楊蟠','宋','宋诗','song-poetry','','[]','日氣層層秀，連山萬丈孤。',24,'全唐诗/poet.song.24000.json','["日氣層層秀，連山萬丈孤。", "崔嵬天上影，一半入江湖。"]'),
('2c80b7d7-6041-4176-9a49-9432ed47935b','慈雲嶺','楊蟠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','落日愁飛雨，雲中一綫明。',24,'全唐诗/poet.song.24000.json','["落日愁飛雨，雲中一綫明。", "西湖將盡處，忽見大江橫。"]'),
('5862c50f-4f3f-4694-a130-e3cb3059c608','歌樵嶺','楊蟠','宋','宋诗','song-poetry','','[]','衣冠仁義少，敢忽嶺邊人。',24,'全唐诗/poet.song.24000.json','["衣冠仁義少，敢忽嶺邊人。", "亦恐修榮達，行歌自負薪。"]'),
('39d0b439-56e6-47cd-998d-912972f7bf70','香林洞','楊蟠','宋','宋诗','song-poetry','','[]','百年樵斧外，留得挂寒猿。',24,'全唐诗/poet.song.24000.json','["百年樵斧外，留得挂寒猿。", "不奈西溪水，流香出洞門。"]'),
('90d36986-f993-49cc-84ba-5bd1802d752a','卧龍山','楊蟠','宋','宋诗','song-poetry','','[]','歲旱須神物，皆疑石有名。',24,'全唐诗/poet.song.24000.json','["歲旱須神物，皆疑石有名。", "卧龍今不起，長負澤邊情。"]'),
('644a6f24-6462-4d93-bb9b-ec91e95662ab','石橋','楊蟠','宋','宋诗','song-poetry','','[]','突兀臨飛鳥，溪僧慣往來。',24,'全唐诗/poet.song.24000.json','["突兀臨飛鳥，溪僧慣往來。", "雲山多樂處，且入小天臺。"]'),
('7d45b0fe-ce5c-4a5e-a1bc-4ad77e0ffbc6','楊梅塢','楊蟠','宋','宋诗','song-poetry','','[]','夏日紅相照，天晴塢自開。',24,'全唐诗/poet.song.24000.json','["夏日紅相照，天晴塢自開。", "襄陽多稚子，摘贈故人來。"]'),
('fe8ad2b5-74dd-45c4-8af8-8f44957c99ca','楓木塢','楊蟠','宋','宋诗','song-poetry','','[]','太平雲外客，行采老山中。',24,'全唐诗/poet.song.24000.json','["太平雲外客，行采老山中。", "莫嘆秋霜早，君看世上楓。"]'),
('64e6e196-e69b-4ed5-9cff-80bd1e584d21','保叔塔','楊蟠','宋','宋诗','song-poetry','','[]','寂寥千古事，今日有誰登。',24,'全唐诗/poet.song.24000.json','["寂寥千古事，今日有誰登。", "落日雲間合，空中露幾層。"]'),
('22358270-501c-4ee7-86f9-b16a73bce2a5','辟支塔','楊蟠','宋','宋诗','song-poetry','','[]','佛心隨處見，層出更分明。',24,'全唐诗/poet.song.24000.json','["佛心隨處見，層出更分明。", "不用催燈火，天高月自生。"]'),
('c0a4e4e5-11b7-4fdf-bcd4-b03072eb258a','東崗古塔','楊蟠','宋','宋诗','song-poetry','','[]','東崗人不識，野寺在樵漁。',24,'全唐诗/poet.song.24000.json','["東崗人不識，野寺在樵漁。", "落葉年年滿，春風爲掃除。"]'),
('9d423691-d52d-4cf6-8e34-5e418e8f6fbd','華嚴塔','楊蟠','宋','宋诗','song-poetry','','[]','石下有靈骨，千年生玉芝。',24,'全唐诗/poet.song.24000.json','["石下有靈骨，千年生玉芝。", "山神每藏護，不使世人知。"]'),
('63ad8262-58cf-4945-a6aa-8e8cd4405da7','翠樾堂','楊蟠','宋','宋诗','song-poetry','','[]','野鳥久不去，清風長近人。',24,'全唐诗/poet.song.24000.json','["野鳥久不去，清風長近人。", "山間豈有曆，祇見四時春。"]'),
('9f569c3b-d1fb-433e-8933-47618d7b754e','瑪瑙寶勝寺','楊蟠','宋','宋诗','song-poetry','','[]','昔日巖棲處，松花落草根。',24,'全唐诗/poet.song.24000.json','["昔日巖棲處，松花落草根。", "瓦中匪是我，棺槨任乾坤。"]'),
('8cf3ea97-4183-4fd5-a9a9-94f08fce2b8c','華蓋山','楊蟠','宋','宋诗','song-poetry','','[]','七山如北斗，城鎖幾重重。',24,'全唐诗/poet.song.24000.json','["七山如北斗，城鎖幾重重。", "斗口在何處，正當華蓋峰。"]'),
('a86c57c9-a5c2-4cba-a494-0e83ffcbadc3','石橋','楊蟠','宋','宋诗','song-poetry','','[]','金毫五百幾龍尊，隠隠香山聖迹存。',64,'全唐诗/poet.song.24000.json','["金毫五百幾龍尊，隠隠香山聖迹存。", "方廣寺開無俗路，優曇花現有靈根。", "一峰突岸臨天壁，雙澗淙橋透石門。", "今日不將心洗盡，更從何處覓真源。"]'),
('8d354e4c-a5b3-4976-a113-ccb87792db79','雜題','楊蟠','宋','宋诗','song-poetry','','[]','猿驚鶴怨不知處，虎據龍蟠空見山。',32,'全唐诗/poet.song.24000.json','["猿驚鶴怨不知處，虎據龍蟠空見山。", "芳草路隨流水遠，老僧心共白雲閑。"]'),
('1047f70b-80e9-4737-a960-b1b1b335b3e2','白沙泉','楊蟠','宋','宋诗','song-poetry','','[]','不見泉來穴，沙平落細聲。',24,'全唐诗/poet.song.24000.json','["不見泉來穴，沙平落細聲。", "夜高寒月漾，銀漢太分明。"]'),
('9720b4d2-502a-4657-911d-b1abdfabec2c','涌金池','楊蟠','宋','宋诗','song-poetry','','[]','涌金春色晚，吹落碧桃花。',24,'全唐诗/poet.song.24000.json','["涌金春色晚，吹落碧桃花。", "一片何人得，流經十萬家。"]'),
('986780d4-64f6-4d8d-9402-0f1e1dd43773','法安院','楊蟠','宋','宋诗','song-poetry','','[]','寂寞庵前草，春深鹿自耕。',24,'全唐诗/poet.song.24000.json','["寂寞庵前草，春深鹿自耕。", "老僧垂白髪，山下不知名。"]'),
('9a8cdbb7-bbf0-4d6c-ad38-53793cce9941','錢塘江上','楊蟠','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','一氣連江色，寥寥萬古清。',48,'全唐诗/poet.song.24000.json','["一氣連江色，寥寥萬古清。", "客心兼浪涌，時事與潮生。", "路轉青山出，沙空白鳥行。", "幾年滄海夢，吟罷獨含情。"]'),
('e0d655b5-6fd2-4fac-a345-8cfffe56e7c9','詩一首','楊蟠','宋','宋诗','song-poetry','','[]','詩魂躔斗壁，醉力撼蓬萊。',24,'全唐诗/poet.song.24000.json','["詩魂躔斗壁，醉力撼蓬萊。", "剖山無鵲印，傾廄盡龍媒。"]'),
('163e7d33-7e01-42fb-b28e-3f52e4db7efd','地爐','楊蟠','宋','宋诗','song-poetry','','[]','天地風霜日夜新，地爐穩坐暖如春。',32,'全唐诗/poet.song.24000.json','["天地風霜日夜新，地爐穩坐暖如春。", "筋骸已暢心無用，轉愧窗間映雪人。"]'),
('7b6a5dcb-28e0-4d89-83d0-ce7dc85c5bf0','松江','楊蟠','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','帆落帆開兩渡頭，洞庭木葉擾離愁。',64,'全唐诗/poet.song.24000.json','["帆落帆開兩渡頭，洞庭木葉擾離愁。", "青山带日低平野，白浪隨風過別洲。", "月靜沙寒知雁宿，雲深水暖羨魚游。", "畫橋隠隠橫天漢，人度空中影倒流。"]'),
('62c1ac44-51e5-49f4-8963-78e361d0c3af','甘露寺','楊蟠','宋','宋诗','song-poetry','','[]','滄江萬里對朱欄，白鳥群飛去復還。',64,'全唐诗/poet.song.24000.json','["滄江萬里對朱欄，白鳥群飛去復還。", "雲捧樓臺出天上，風飄鐘磬落人間。", "銀河倒瀉分雙月，錦水西來轉幾山。", "今古冥冥誰借問，且持玉爵破愁顔。"]'),
('a1ed4f53-6052-4316-a866-aa8b721f4a32','朝宗門','楊蟠','宋','宋诗','song-poetry','','[]','百尺樓高四望中，雲深一雁度長空。',64,'全唐诗/poet.song.24000.json','["百尺樓高四望中，雲深一雁度長空。", "人間砧杵催寒事，郭外簫笙逐土風。", "天带江山元自好，地流河漢忽相通。", "丹心直北看飛雪，往往隨花入帝宮。"]'),
('7b70869d-774f-48fb-932c-f6dc50ec35cc','清心堂','楊蟠','宋','宋诗','song-poetry','','[]','前後坐亭上，飲水皆自持。',24,'全唐诗/poet.song.24000.json','["前後坐亭上，飲水皆自持。", "其間賢太守，誰復畏人知。"]'),
('7d4bf009-a130-4894-8947-1022f9da5bab','虎跑泉','楊蟠','宋','宋诗','song-poetry','','[]','天藏物啟有靈根，玉乳銀漿豈易分。',64,'全唐诗/poet.song.24000.json','["天藏物啟有靈根，玉乳銀漿豈易分。", "浄鑑當空寒自照，流珠落澗遠先聞。", "潤生冉冉雙林雨，香出濛濛一井雲。", "今日石魚行酒地，次山重爲勒銘文。"]'),
('ae2e7c94-a0c5-4e66-9113-5ce7d0f7f96d','華胥臺','楊蟠','宋','宋诗','song-poetry','','[]','歌舞飄飄百尺臺，半天龍麝散香煤。',64,'全唐诗/poet.song.24000.json','["歌舞飄飄百尺臺，半天龍麝散香煤。", "初愁翠袖凌風去，却騎飛鸞下月來。", "雲杪一聲聞玉笛，露華千點落金杯。", "我緣衆樂狂方盛，園鎖從教日日開。"]'),
('7bc7b920-efb5-4b94-94bd-1ea980653348','時燕堂','楊蟠','宋','宋诗','song-poetry','','[]','吏隠盂城九十旬，豐年日日是佳辰。',64,'全唐诗/poet.song.24000.json','["吏隠盂城九十旬，豐年日日是佳辰。", "賦成席上猶飛雪，歌動梁間已落塵。", "此地誰爲愛酒伴，他時儻憶種花人。", "五壇芍藥齊教放，何處揚州更覓春。"]'),
('8ff8920d-b790-4f53-b316-807268431e0c','春草池','楊蟠','宋','宋诗','song-poetry','','[]','寂寂綠巖畔，相期無數人。',24,'全唐诗/poet.song.24000.json','["寂寂綠巖畔，相期無數人。", "不知康樂後，池草幾回春。"]'),
('00940990-bee0-447a-bda2-75d179f2b83e','西山','楊蟠','宋','宋诗','song-poetry','','[]','雲引踏青客，尋山西出城。',24,'全唐诗/poet.song.24000.json','["雲引踏青客，尋山西出城。", "始知圖畫上，今日有人行。"]'),
('df15ae6f-8f79-493d-b543-ddfe33debce1','白雲嶺','楊蟠','宋','宋诗','song-poetry','','[]','白雲出山去，摇曳或西東。',24,'全唐诗/poet.song.24000.json','["白雲出山去，摇曳或西東。", "人住白雲下，安然心已空。"]'),
('964e7751-f0e2-442e-b430-2f6dc0792c15','鹿端山','楊蟠','宋','宋诗','song-poetry','','[]','千年白鹿地，今有佛樓臺。',24,'全唐诗/poet.song.24000.json','["千年白鹿地，今有佛樓臺。", "昨日到山下，啣花猶出來。"]'),
('fc454b5d-b22d-4c3b-a31c-7bcf75dd4171','五馬坊','楊蟠','宋','宋诗','song-poetry','','[]','相傳有五馬，曾此立踟躇。',24,'全唐诗/poet.song.24000.json','["相傳有五馬，曾此立踟躇。", "人愛使君好，換鵝非俗書。"]'),
('62777db9-2071-441e-af25-b08fdcb61395','衆樂園','楊蟠','宋','宋诗','song-poetry','','[]','昨日折花者，又隨蜂蝶來。',24,'全唐诗/poet.song.24000.json','["昨日折花者，又隨蜂蝶來。", "思量妨底事，紅蕊續還開。"]'),
('ed8fe039-7735-4f93-ac84-4a415efc4c11','蓮花莊','楊蟠','宋','宋诗','song-poetry','','[]','會昌湖上客，今已化爲塵。',24,'全唐诗/poet.song.24000.json','["會昌湖上客，今已化爲塵。", "一束青芻奠，空思如玉人。"]'),
('bb575877-fa41-412b-b7b0-6116382c9fd9','西堂','楊蟠','宋','宋诗','song-poetry','','[]','謝公何所憶，白日看雲眠。',24,'全唐诗/poet.song.24000.json','["謝公何所憶，白日看雲眠。", "忽夢惠連弟，遂得春草篇。"]'),
('82afa1a1-ca29-4c3f-b64c-6c5529a097c3','海月堂','楊蟠','宋','宋诗','song-poetry','','[]','杳杳璧沉水，亭亭珠在淵。',24,'全唐诗/poet.song.24000.json','["杳杳璧沉水，亭亭珠在淵。", "落潮流不去，還向定中圓。"]'),
('c240e708-25e1-4900-8050-40fe9c20e39b','翠幄軒','楊蟠','宋','宋诗','song-poetry','','[]','海榕樹倒出，皮幹亦輪囷。',24,'全唐诗/poet.song.24000.json','["海榕樹倒出，皮幹亦輪囷。", "或問壽幾許，千年爲一春。"]'),
('f59857f5-cb69-4a7e-9d3a-e968495628b4','紅雲閣','楊蟠','宋','宋诗','song-poetry','','[]','重重風日透，花氣滿池塘。',24,'全唐诗/poet.song.24000.json','["重重風日透，花氣滿池塘。", "誰把紅雲比，紅雲無此香。"]'),
('b0b5fdf9-420e-4738-a149-c6f74b32c1af','滄浪閣','楊蟠','宋','宋诗','song-poetry','','[]','萍實祗如斗，練江都熨開。',24,'全唐诗/poet.song.24000.json','["萍實祗如斗，練江都熨開。", "水清當自鑑，無爲濯纓來。"]'),
('32ae59c6-620e-4c63-b2c1-31b489211828','冷翠閣','楊蟠','宋','宋诗','song-poetry','','[]','山杪一泉迸，俯窺臨日崖。',24,'全唐诗/poet.song.24000.json','["山杪一泉迸，俯窺臨日崖。", "明珠不待拾，自濺入人來。"]'),
('5e8a2052-9a58-404a-8eeb-686a9e8cbe2e','永嘉','楊蟠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一片繁華海上頭，從來喚作小杭州。',64,'全唐诗/poet.song.24000.json','["一片繁華海上頭，從來喚作小杭州。", "水如棋局分街陌，山似屏幃繞畫樓。", "是處有花迎我笑，何時無月逐人遊。", "西湖宴賞爭標日，多少珠簾不下鈎。"]'),
('8e598de0-525b-4ae3-92a4-f79e9dd6886a','登孤嶼','楊蟠','宋','宋诗','song-poetry','','[]','把麾何所往，海上有名山。',48,'全唐诗/poet.song.24000.json','["把麾何所往，海上有名山。", "潮落魚堪拾，雲低雁可攀。", "一城仙島外，雙塔畫圖間。", "當路誰知己，天應賜我閑。"]'),
('45aa7ed6-89ab-422b-8217-5c026e85dacd','後永嘉百詠 放生池','楊蟠','宋','宋诗','song-poetry','','[]','悠然已更樂，知是鼎中餘。',24,'全唐诗/poet.song.24000.json','["悠然已更樂，知是鼎中餘。", "有海尚可往，慎毋重見漁。"]'),
('c0e5c4d0-6844-4db5-b450-11fa154d253a','後永嘉百詠 南塘','楊蟠','宋','宋诗','song-poetry','','[]','出門日已晚，棹短路何長。',24,'全唐诗/poet.song.24000.json','["出門日已晚，棹短路何長。", "頼有風相送，荷花十里香。"]'),
('ed10c155-c7c7-468b-a863-352596ceb7d6','贈仰孝子','楊蟠','宋','宋诗','song-poetry','','[]','思親廬墓隠西山，竹屋蕭然月塢間。',64,'全唐诗/poet.song.24000.json','["思親廬墓隠西山，竹屋蕭然月塢間。", "有道自高塵世外，無心得共野雲閑。", "姓名達遠邦符奏，束帛榮霑帝澤頒。", "不見孝廉人已久，東嘉今喜識曾顔。"]'),
('da19d969-fdcb-4d5c-9c8d-726142c4c1f4','去郡後作','楊蟠','宋','宋诗','song-poetry','','[]','爲官一十政，宦游五十秋。',72,'全唐诗/poet.song.24000.json','["爲官一十政，宦游五十秋。", "平生憶何處，最憶是溫州。", "思遠城南曲，西岑古渡頭。", "綠觴春送酒，紅燭夜行舟。", "不敢言遺愛，惟應念舊遊。", "憑君將此句，寄寫謝公樓。"]'),
('059d21f3-5cbc-43d1-a3e3-fb030a5f903b','熙春園','楊蟠','宋','宋诗','song-poetry','','[]','桃源未識恐微茫，每坐青林慣日長。',64,'全唐诗/poet.song.24000.json','["桃源未識恐微茫，每坐青林慣日長。", "魚鳥自同千里樂，風煙漫逐一城香。", "竹圍月色來深院，花引春情過短牆。", "人世定知何處好，且勤詩酒惜年光。"]'),
('029ccbe8-cae0-4b58-8e71-67755fc8ab8f','客兒亭','楊蟠','宋','宋诗','song-poetry','','[]','昔日林間興，風流謝客兒。',24,'全唐诗/poet.song.24000.json','["昔日林間興，風流謝客兒。", "春山花又發，不見屐來時。"]'),
('f8e8cd95-bc4d-4499-bd49-728a02594dad','除夕次東坡守歲韵','楊蟠','宋','宋诗','song-poetry','','[]','人生無百年，誰問嶺龜蛇。',96,'全唐诗/poet.song.24000.json','["人生無百年，誰問嶺龜蛇。", "容顔鏡水換，老醜不可遮。", "殷勤守此歲，來歲復如何。", "南鄰祭竈喧，北里驅儺譁。", "須臾罷無爲，但聽樓鼓撾。", "明朝四十過，暮景真易斜。", "初心自慷慨，白首還蹉跎。", "寄語少年子，雖强不足誇。"]'),
('cdc6c3c4-2441-4375-8275-14ebbebc109c','句  其一','楊蟠','宋','宋诗','song-poetry','','[]','吏退更無人迹到，一天魂夢任遊揚。',16,'全唐诗/poet.song.24000.json','["吏退更無人迹到，一天魂夢任遊揚。"]'),
('e06c3b61-04a0-42c9-96c9-59984604d76f','句  其二','楊蟠','宋','宋诗','song-poetry','','[]','中原今仗老臣安。',8,'全唐诗/poet.song.24000.json','["中原今仗老臣安。"]'),
('23cd3988-84a7-4bf8-bf59-dd69883d7243','句  其三','楊蟠','宋','宋诗','song-poetry','','[]','許國莫疑勳業大。',8,'全唐诗/poet.song.24000.json','["許國莫疑勳業大。"]'),
('df9644dd-c32c-4625-a831-5e3cbd211c1f','句  其四','楊蟠','宋','宋诗','song-poetry','','[]','兩州城郭青煙起，千里江山白鷺飛。',16,'全唐诗/poet.song.24000.json','["兩州城郭青煙起，千里江山白鷺飛。"]'),
('870c7ba6-c984-4d80-b659-db84c5a323b4','句  其五','楊蟠','宋','宋诗','song-poetry','','[]','三峽江聲流筆下，六朝山影滿樽前。',16,'全唐诗/poet.song.24000.json','["三峽江聲流筆下，六朝山影滿樽前。"]'),
('d153dd77-a286-4263-b576-87bcaa888e4e','句  其六','楊蟠','宋','宋诗','song-poetry','','[]','動摇臘信隨征使，勾引春情出苑牆。',16,'全唐诗/poet.song.24000.json','["動摇臘信隨征使，勾引春情出苑牆。"]'),
('d5eed71c-e564-46e2-b3ce-51c6c10a93fd','句  其七','楊蟠','宋','宋诗','song-poetry','','[]','仲□嘗三逐，將軍老數奇。',12,'全唐诗/poet.song.24000.json','["仲□嘗三逐，將軍老數奇。"]'),
('dd519280-4725-4dc5-ab2f-3978db54ecc8','句  其八','楊蟠','宋','宋诗','song-poetry','','[]','看山坐石亭。',6,'全唐诗/poet.song.24000.json','["看山坐石亭。"]'),
('d2c46aa3-fa75-47f3-a180-9f0b91507b27','句  其九','楊蟠','宋','宋诗','song-poetry','','[]','浮生同是客。',6,'全唐诗/poet.song.24000.json','["浮生同是客。"]'),
('b7942565-1866-4630-b4d7-93c266f478cb','句  其一○','楊蟠','宋','宋诗','song-poetry','','[]','花濕轉分明。',6,'全唐诗/poet.song.24000.json','["花濕轉分明。"]'),
('23f531f8-6b51-47e2-a359-92692368675c','句  其一一','楊蟠','宋','宋诗','song-poetry','','[]','杖藜林下去。',6,'全唐诗/poet.song.24000.json','["杖藜林下去。"]'),
('78c4240a-8939-4753-963c-fd498560ad18','遊廣福寺','胡志康','宋','宋诗','song-poetry','','[]','蘭若幽深與世違，酒闌重覓未斜暉。',64,'全唐诗/poet.song.24000.json','["蘭若幽深與世違，酒闌重覓未斜暉。", "籃輿繞入花邊路，布衲趨迎竹下扉。", "清籟敲風和梵奏，獨槐籠榻漲烟霏。", "吟欄倚遍詩成處，不覺金蓮映月輝。"]'),
('76e5c381-c05e-4575-bb08-b13689294b28','默山小潭','胡楚材','宋','宋诗','song-poetry','','[]','分落銀河一派清，源深流遠旱常盈。',64,'全唐诗/poet.song.24000.json','["分落銀河一派清，源深流遠旱常盈。", "蛟龍潛處魚蝦少，日月中時表裏明。", "插岸好山青潑黛，倚波醜石勢奔鯨。", "幽奇信是神仙窟，上有浮雲散又生。"]'),
('a7d67f3c-cd8f-4809-8511-9ff6ecb0ce7b','青山懷古','胡楚材','宋','宋诗','song-poetry','','[]','樵獵識冠裳，何言志四方。',48,'全唐诗/poet.song.24000.json','["樵獵識冠裳，何言志四方。", "離秦風日冷，過楚薜蘿長。", "夢野違徵詔，時衰枉薦章。", "故山隈且僻，應種秫爲糧。"]'),
('e3004fcf-074b-4bd9-aaf4-723b7d300f26','白艾溪','胡楚材','宋','宋诗','song-poetry','','[]','澎湃白艾溪，源恐從天落。',132,'全唐诗/poet.song.24000.json','["澎湃白艾溪，源恐從天落。", "灘石劍戟列，噴怒波勢惡。", "篙工手眼親，飛舫過如籜。", "達阻有長橋，輕虹□寥廓。", "參天樹列幢，夾岸如山削。", "中有釣魚郎，扁舟□寂寞。", "俗眼急勢利，問此何足樂。", "不釣滄海鰲，須膾潮州鱷。", "胡爲持一竿，默在艾溪脚。", "我且笑不答，自歌還自酌。", "日暮鼓枻歸，風埃滿城郭。"]'),
('88316c39-58b0-4002-8737-0942af223d0c','仙池巖','胡楚材','宋','宋诗','song-poetry','','[]','崚嶒插天山，仙池在絕頂。',132,'全唐诗/poet.song.24000.json','["崚嶒插天山，仙池在絕頂。", "無源水自溢，泓澄照天鏡。", "魚依藻荇深，龍藏密穴靜。", "天意欲爲雨，烟霧如爐甑。", "至今山下田，勢不憂旱橫。", "劃然霽景開，仰看飛泉迸。", "一道翠微間，長劍倚天凈。", "群山列畫屏，高下相輝映。", "安得丹青手，寫此絕勝境。", "挂我草堂中，吟望免延頸。", "不負山水心，永謝利名阱。"]'),
('4f359e94-b0c0-4ff0-bc2f-d677dba4981a','憶彭頭山','胡楚材','宋','宋诗','song-poetry','','[]','久客倦行役，故山安在哉。',48,'全唐诗/poet.song.24000.json','["久客倦行役，故山安在哉。", "松竹讀書室，水石釣魚臺。", "明月照歸夢，西風吹酒杯。", "亭亭籬下菊，寂寞爲誰開。"]'),
('dd3a64c5-ee3e-453c-91fe-60316bce2bb0','凉軒','柳說','宋','宋诗','song-poetry','','[]','瀟灑幽軒好，清閒令尹才。',48,'全唐诗/poet.song.24000.json','["瀟灑幽軒好，清閒令尹才。", "庭虛走泉響，門靜對山開。", "夏可捐班扇，風如到楚臺。", "羨君成吏隠，終日遠紛埃。"]'),
('dfb789d5-e992-4c79-b484-a6e3dbd68718','臨封雜咏  其一','田開','宋','宋诗','song-poetry','','[]','我愛臨封好，人烟十里賒。',48,'全唐诗/poet.song.24000.json','["我愛臨封好，人烟十里賒。", "秋風三釀酒，風景四時花。", "竹屋無貧子，漁村足富家。", "守官真吏隠，謾放日高衙。"]'),
('cfab8eeb-917a-49e2-baa1-1fb441a6e8d6','臨封雜咏  其二','田開','宋','宋诗','song-poetry','','[]','我愛臨封好，詩人興味長。',48,'全唐诗/poet.song.24000.json','["我愛臨封好，詩人興味長。", "嶺南蕉子國，海上荔枝莊。", "民有百年壽，家藏十種糧。", "宦遊無遠近，樂處是仙鄉。"]'),
('c5819199-0993-40fc-b020-d8fe7ec394e7','臨封雜咏  其三','田開','宋','宋诗','song-poetry','','[]','我愛臨封好，江流壓水濱。',48,'全唐诗/poet.song.24000.json','["我愛臨封好，江流壓水濱。", "東山畫屏展，北阜翠虬馴。", "十里長松道，三春解佩人。", "乘閒狂太守，屐齒往來頻。"]'),
('3495d5bb-3db1-4e49-b4ff-d4c4c424ff6d','臨封雜咏  其四','田開','宋','宋诗','song-poetry','','[]','我愛臨封好，賓朋日往還。',48,'全唐诗/poet.song.24000.json','["我愛臨封好，賓朋日往還。", "年來甘白酒，老去益朱顔。", "引鶴遊西寺，携琴上北山。", "君恩雖未報，公外且偷閑。"]'),
('6116f38f-5180-4153-a328-6dac40d97396','臨封雜咏  其五','田開','宋','宋诗','song-poetry','','[]','我愛臨封好，江樓四望遥。',48,'全唐诗/poet.song.24000.json','["我愛臨封好，江樓四望遥。", "賓朋須共賞，風月故相邀。", "清興拚成癖，詩狂不礙條。", "謾勞爭自潔，適意樂偏饒。"]'),
('18d2e7d2-0bdf-4630-be7f-58f4e3fa75ff','臨封雜咏  其六','田開','宋','宋诗','song-poetry','','[]','我愛臨封好，迎門水繞流。',48,'全唐诗/poet.song.24000.json','["我愛臨封好，迎門水繞流。", "名山稱濯錦，勝境說靈洲。", "嫩草青連座，奇花香入樓。", "公餘無一事，携酒任遨遊。"]'),
('0014c21c-bf9b-4818-8119-ca0c228cb056','句  其一','田開','宋','宋诗','song-poetry','','[]','吏民相共樂，渾不記相關。',12,'全唐诗/poet.song.24000.json','["吏民相共樂，渾不記相關。"]'),
('b0e294c6-1d74-4668-913c-582e44080323','句  其二','田開','宋','宋诗','song-poetry','','[]','山近臨軒翠，花開入座紅。',12,'全唐诗/poet.song.24000.json','["山近臨軒翠，花開入座紅。"]'),
('e6fdc753-ff14-4909-b97a-0f255e777f54','句  其三','田開','宋','宋诗','song-poetry','','[]','我愛臨封好，從來禮義鄉。',24,'全唐诗/poet.song.24000.json','["我愛臨封好，從來禮義鄉。", "江山足形勝，風物半冠裳。"]'),
('54cd1d56-48b1-457d-b647-cb9c5a7c26d8','題凈土寺','劉扶','宋','宋诗','song-poetry','','[]','物外蕭然釋子宮，樓臺雄壓郡城東。',64,'全唐诗/poet.song.24000.json','["物外蕭然釋子宮，樓臺雄壓郡城東。", "江迴澄練浸碧落，山答疏鐘飄遠風。", "隔岸櫓聲喧暮角，卧沙橋影轉晴虹。", "可憐千里無窮景，盡屬高僧吟笑中。"]'),
('6c3570e5-51ff-43ab-8600-5db12e0c4180','游爛柯山','錢顗','宋','宋诗','song-poetry','','[]','春郊雜遝擁紅旌，共訪仙蹤嘯傲行。',64,'全唐诗/poet.song.24000.json','["春郊雜遝擁紅旌，共訪仙蹤嘯傲行。", "雲徑直從深崦入，石梁宛在半空橫。", "巖邊瑶圃新開出，洞裏芝田舊種成。", "羽客一枰無復見，青山留得爛柯名。"]'),
('d7ed38c7-2861-4f0f-9113-eb84881c7093','黄鶴樓','張顒','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','崔顥題詩在上頭，登臨何必更冥搜。',48,'全唐诗/poet.song.24000.json','["崔顥題詩在上頭，登臨何必更冥搜。", "樓前黄鶴不重見，檻外長江空自流。", "萬頃煙雲連夢澤，一川風景借西州。"]'),
('ca252291-cf73-472c-ab7f-ac230cfa886a','句','張顒','宋','宋诗','song-poetry','','[]','兩州花萼競相輝，間斷紅塵一水涯。',16,'全唐诗/poet.song.24000.json','["兩州花萼競相輝，間斷紅塵一水涯。"]'),
('9cd83606-cb74-4df6-8799-5d94dbeb3ce0','昭惠廟黄柏歌','王該','宋','宋诗','song-poetry','','[]','四明之山東南雄，中有古柏高巃嵷。',174,'全唐诗/poet.song.24000.json','["四明之山東南雄，中有古柏高巃嵷。", "霜凌雪犯勢不屈，幹直不與凡柯同。", "幾十圍，幾千尺，踞隆巖兮盤巨石。", "有時狂風盲雨嗥長巔，上徹天心下地脊。", "樵奴與牧子，慣見却辟易。", "不知何洞出神翁，採芝去踏嶄巖峰。", "蒸嵐焙翠入靈藥，意欲服餌顔如童。", "仙翁仙翁愛無獨，天産此材同衆欲。", "小將條剖治民盲，大可柱分支帝屋。", "神翁神翁莫輕藐，植物雖微功不小。", "些須片葉價千金，能使塵寰人不老。"]'),
('f8c88c4d-c427-47c1-93b3-f525478ffdda','瑞巖寺靈芝閣','李撫辰','宋','宋诗','song-poetry','','[]','高閣玲瓏倚半空，秋來凈掃白雲蹤。',32,'全唐诗/poet.song.24000.json','["高閣玲瓏倚半空，秋來凈掃白雲蹤。", "無人寫此天然景，十二闌干十二峰。"]'),
('9d65bdfb-794c-408f-8386-24fc27a02058','句  其一','譚黌','宋','宋诗','song-poetry','','[]','水腹魚龍宅，山腰鼓吹衙。',12,'全唐诗/poet.song.24000.json','["水腹魚龍宅，山腰鼓吹衙。"]'),
('e71bde8c-1d37-4c67-b45f-3148c238c591','句  其二','譚黌','宋','宋诗','song-poetry','','[]','齊安無一事，臺榭若天成。',12,'全唐诗/poet.song.24000.json','["齊安無一事，臺榭若天成。"]'),
('6835bfc8-555f-4a02-aa37-1ba0a66980e0','金精山','高照','宋','宋诗','song-poetry','','[]','金精寂寂真勝境，門鎖松杉風月冷。',32,'全唐诗/poet.song.24000.json','["金精寂寂真勝境，門鎖松杉風月冷。", "跨鶴仙姬去不來，白雲一片封丹井。"]'),
('6bc7cf7f-88c9-495d-92fa-bbec1416e8ae','句','齊術','宋','宋诗','song-poetry','','[]','零陵太守吟情逸，惟過浯溪未有詩。',16,'全唐诗/poet.song.24000.json','["零陵太守吟情逸，惟過浯溪未有詩。"]'),
('c4637d9a-c502-4e43-9068-5323e6dc4e37','書仙臺觀壁','周敦頤','宋','宋诗','song-poetry','','[]','到官處處須尋勝，惟此合陽無勝尋。',32,'全唐诗/poet.song.24000.json','["到官處處須尋勝，惟此合陽無勝尋。", "赤水有山仙甚古，躋攀聊足到官心。"]'),
('421da361-8834-4e52-9e2b-242dca020aa0','游山上一道觀三佛寺','周敦頤','宋','宋诗','song-poetry','','[]','琳宮金剎接林巒，一徑潛通竹樹寒。',32,'全唐诗/poet.song.24000.json','["琳宮金剎接林巒，一徑潛通竹樹寒。", "是處塵埃皆可息，時清終未忍辭官。"]'),
('cb61ebf9-d422-47bd-a208-1389ae171d56','喜同費君長官游','周敦頤','宋','宋诗','song-poetry','','[]','尋山尋水侶尤難，愛利愛名心少閒。',32,'全唐诗/poet.song.24000.json','["尋山尋水侶尤難，愛利愛名心少閒。", "此亦有君吾甚樂，不辭高遠共躋攀。"]'),
('fdf4ed6f-8ed8-4838-8114-2cfc16ae4099','和費君樂游山之什','周敦頤','宋','宋诗','song-poetry','','[]','雲樹巖泉景盡奇，登臨深恨訪尋遲。',32,'全唐诗/poet.song.24000.json','["雲樹巖泉景盡奇，登臨深恨訪尋遲。", "長樓未得於何記，猶有君能雅和詩。"]'),
('1dfdab4a-1273-45fb-ba44-081c95b0ac22','劍門','周敦頤','宋','宋诗','song-poetry','','[]','劍立溪峰信險深，吾皇大道正天心。',32,'全唐诗/poet.song.24000.json','["劍立溪峰信險深，吾皇大道正天心。", "百年外戶都無閉，空有關名點貢琛。"]'),
('4cdfe33a-704f-4aaa-bbfb-fbff73f7e5e3','萬安香城寺別虔守趙公','周敦頤','宋','宋诗','song-poetry','','[]','公暇頻陪塵外游，朝天仍得送行舟。',64,'全唐诗/poet.song.24000.json','["公暇頻陪塵外游，朝天仍得送行舟。", "軒車更共入山脚，旌旆且從留渡頭。", "精舍泉聲清㶁㶁，高林雲色淡悠悠。", "談終道奧愁言去，明日瞻思上郡樓。"]'),
('22d8a8c7-e51e-420c-b6db-64c15c78d900','行縣至雩都邀餘杭錢建侯拓四明沈幾聖希顔同游羅巖','周敦頤','宋','宋诗','song-poetry','','[]','聞有山巖即去尋，亦躋雲外入松陰。',32,'全唐诗/poet.song.24000.json','["聞有山巖即去尋，亦躋雲外入松陰。", "雖然未是洞中境，且異人間名利心。"]'),
('3bd6cb3e-5b5a-42ce-b56f-8a540b7e26ba','同石守游','周敦頤','宋','宋诗','song-poetry','','[]','朝市誰知世外游，杉松影裏入吟幽。',64,'全唐诗/poet.song.24000.json','["朝市誰知世外游，杉松影裏入吟幽。", "爭名逐利千繩縛，度水登山萬事休。", "野鳥不驚如得伴，白雲無語似相留。", "傍人莫笑憑闌久，爲戀林居作退謀。"]'),
('2a2482a6-4c13-4aad-8d71-1c6bf610d0bb','江上別石郎中','周敦頤','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','落葉蟬聲古渡頭，渡頭人擁欲行舟。',32,'全唐诗/poet.song.24000.json','["落葉蟬聲古渡頭，渡頭人擁欲行舟。", "別離情似長江水，遠亦隨公日夜流。"]'),
('6a7bf036-063b-4712-9da9-519333414479','憶江西提刑何仲容','周敦頤','宋','宋诗','song-poetry','','[]','蘭自香爲友，松何枯尚春。',48,'全唐诗/poet.song.24000.json','["蘭自香爲友，松何枯尚春。", "榮來天澤重，歿去綉衣新。", "盡作百年夢，終歸一窖塵。", "痛心雙淚下，無復見賢人。"]'),
('970ac34d-5f92-4e04-bd92-ad032e9d535e','治平乙巳暮春十四日同宋復古游山巔至大林寺書四十字','周敦頤','宋','宋诗','song-poetry','','[]','三月山方暖，林花互照明。',48,'全唐诗/poet.song.24000.json','["三月山方暖，林花互照明。", "路盤層頂上，人在半空行。", "水色雲含白，禽聲谷應清。", "天風拂襟袂，縹緲覺身輕。"]'),
('7879574b-178e-4daa-b413-b6df2493337a','題冠順之道院壁','周敦頤','宋','宋诗','song-poetry','','[]','一日復一日，一杯復一杯。',48,'全唐诗/poet.song.24000.json','["一日復一日，一杯復一杯。", "青山無限好，俗客不曾來。", "往事已如此，朱顔安在哉。", "寄語地上客，歷亂竟誰催。"]'),
('1555855a-20f4-4e7a-9ec1-373032ec30a4','題浩然閣','周敦頤','宋','宋诗','song-poetry','','[]','劉侯戴武弁，政則心吾儒。',48,'全唐诗/poet.song.24000.json','["劉侯戴武弁，政則心吾儒。", "士茂先興學，子賢勤讀書。", "猷爲莫不善，才力蓋有餘。", "西北方求帥，浩然寧久居。"]'),
('cd81a8e2-db1e-43ab-8f08-043d795e055c','題酆都觀 仙都觀','周敦頤','宋','宋诗','song-poetry','','[]','山盤江上虬龍活，殿倚雲中洞府深。',32,'全唐诗/poet.song.24000.json','["山盤江上虬龍活，殿倚雲中洞府深。", "欽想真風杳何在，偃松喬柏共蕭森。"]'),
('04c0d998-2773-477b-b3c1-c790ca6f664e','題酆都觀 讀英真君丹訣','周敦頤','宋','宋诗','song-poetry','','[]','始觀丹訣信希夷，蓋得陰陽造化機。',32,'全唐诗/poet.song.24000.json','["始觀丹訣信希夷，蓋得陰陽造化機。", "子自母生能致主，精神合後更知微。"]'),
('0f613602-43ab-4bf8-bdee-b538dffb167d','題酆都觀 宿山房','周敦頤','宋','宋诗','song-poetry','','[]','久厭塵坌樂靜元，俸微猶乏買山錢。',32,'全唐诗/poet.song.24000.json','["久厭塵坌樂靜元，俸微猶乏買山錢。", "徘徊真境不能去，且寄雲房一榻眠。"]'),
('25b960e8-c2d0-4f5f-add7-5036c139b91d','按部至潮州題大顛堂壁','周敦頤','宋','宋诗','song-poetry','','[]','退之自謂如夫子，原道深排釋老非。',32,'全唐诗/poet.song.24000.json','["退之自謂如夫子，原道深排釋老非。", "不識大顛何似者，數書珍重更留衣。"]'),
('6c4f990d-4b25-42a1-8ad7-362b2a995baa','按部至春州','周敦頤','宋','宋诗','song-poetry','','[]','按部廣東經數郡，若言嵐瘴更無春。',64,'全唐诗/poet.song.24000.json','["按部廣東經數郡，若言嵐瘴更無春。", "度山煙鎖埋清晝，爲國天終護吉人。", "萬里詔音頻降下，一方恩惠盡均勻。", "丈夫才略逢時展，倉廩皆無亟富民。"]'),
('f2e55871-dba7-4092-8b86-a0a2bf7f6828','題惠州羅浮山','周敦頤','宋','宋诗','song-poetry','','[]','紅塵白日無閒人，况有魚緋繫此身。',32,'全唐诗/poet.song.24000.json','["紅塵白日無閒人，况有魚緋繫此身。", "關上羅浮閒送目，浩然心意復吾真。"]'),
('54e654c8-63cf-4557-93d4-ecaff151c139','贈虞部員外郎譚公昉致仕','周敦頤','宋','宋诗','song-poetry','','[]','清時望郎貴，白首故鄉歸。',48,'全唐诗/poet.song.24000.json','["清時望郎貴，白首故鄉歸。", "有子紆藍綬，將孫著綵衣。", "松喬新道院，鶴老舊漁磯。", "知止自高德，寧爲遁者肥。"]'),
('3fef3f1c-bd3d-4772-a4e2-c76141e7d70f','瀼溪書堂','周敦頤','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','元子溪曰瀼，詩傳到於今。',192,'全唐诗/poet.song.24000.json','["元子溪曰瀼，詩傳到於今。", "此俗良易化，不欺顧相欽。", "廬山我久愛，買田山之陰。", "田間有流水，清泚出山心。", "山心無塵土，白石磷磷沈。", "潺湲來數里，到此始澄深。", "有龍不可測，岸木寒森森。", "書堂構其上，隠几看雲岑。", "倚梧或欹枕，風月盈中襟。", "或吟或冥默，或酒或鳴琴。", "數十黄卷軸，聖賢談無音。", "窗前即疇囿，囿外桑麻林。", "芋蔬可卒歲，絹布足衣衾。", "飽煖大富貴，康寧無價金。", "吾樂蓋易足，名濂朝暮箴。", "元子與周子，相邀風月尋。"]'),
('a078131e-cbca-4d41-a60f-e35c28f968b4','思歸舊隠','周敦頤','宋','宋诗','song-poetry','','[]','靜思歸舊隠，日出半山晴。',48,'全唐诗/poet.song.24000.json','["靜思歸舊隠，日出半山晴。", "醉榻雲籠潤，吟窗瀑瀉清。", "閑方爲達士，忙只是勞生。", "朝市誰頭白，車輪未曉鳴。"]'),
('aac01d1f-31fa-477c-9f29-11e737483cda','夜雨書窗','周敦頤','宋','宋诗','song-poetry','','[]','秋風拂盡熱，半夜雨淋漓。',36,'全唐诗/poet.song.24000.json','["秋風拂盡熱，半夜雨淋漓。", "繞屋是芭蕉，一枕萬響圍。", "恰似釣魚船，篷底睡覺時。"]'),
('1092a8fa-4783-46bc-b188-c2f89b8e977e','石塘橋晚釣','周敦頤','宋','宋诗','song-poetry','','[]','舊隠濂溪上，思歸復思歸。',36,'全唐诗/poet.song.24000.json','["舊隠濂溪上，思歸復思歸。", "釣魚船好睡，寵辱不相隨。", "肯爲爵祿重，白髪猶羈縻。"]'),
('80f180ed-53f4-4fb0-b659-bbf09b85418b','書舂陵門扉','周敦頤','宋','宋诗','song-poetry','','[]','有風還自掩，無事晝常關。',24,'全唐诗/poet.song.24000.json','["有風還自掩，無事晝常關。", "開闔從方便，乾坤在此閒。"]'),
('947a2a4b-1102-49ad-ae5e-f0894707fd33','任所寄鄉關故舊','周敦頤','宋','宋诗','song-poetry','','[]','老子生來骨性寒，宦情不改舊儒酸。',64,'全唐诗/poet.song.24000.json','["老子生來骨性寒，宦情不改舊儒酸。", "停杯厭飲香醪味，舉筯常餐淡菜盤。", "事冗不知筋力倦，官清贏得夢魂安。", "故人欲問吾何況，爲道舂陵只一般。"]'),
('9ee15429-ba50-43c5-a589-fc241ce06584','春晚','周敦頤','宋','宋诗','song-poetry','','[]','花落柴門掩夕暉，昏鴉數點傍林飛。',32,'全唐诗/poet.song.24000.json','["花落柴門掩夕暉，昏鴉數點傍林飛。", "吟餘小立闌干外，遥見樵漁一路歸。"]'),
('c4409583-481e-4bde-ad28-bb2fd1f955a8','牧童','周敦頤','宋','宋诗','song-poetry','','[]','東風放牧出長坡，誰識阿童樂趣多。',32,'全唐诗/poet.song.24000.json','["東風放牧出長坡，誰識阿童樂趣多。", "歸路轉鞭牛背上，笛聲吹老太平歌。"]'),
('80073f9c-7357-442d-8c49-a407000c4bcf','天池','周敦頤','宋','宋诗','song-poetry','','[]','斯須暮雲合，白日無餘暉。',48,'全唐诗/poet.song.24000.json','["斯須暮雲合，白日無餘暉。", "金波從地涌，寶燄穿林飛。", "僧言自雄誇，俗駭無因依。", "安知本地靈，發見隨天機。"]'),
('bbd81148-f51a-4df7-8cbc-0bb8552cffaa','宿崇聖','周敦頤','宋','宋诗','song-poetry','','[]','公程無暇日，暫得宿清幽。',48,'全唐诗/poet.song.24000.json','["公程無暇日，暫得宿清幽。", "始覺空門客，不生浮世愁。", "溫泉喧古洞，晚磬度危樓。", "徹曉都忘寐，心疑在沃洲。"]'),
('07c79d7a-9e36-4f8d-8f57-34367dee1134','暮春即事','周敦頤','宋','宋诗','song-poetry','','[]','雙雙瓦雀行書案，點點楊花入硯池。',32,'全唐诗/poet.song.24000.json','["雙雙瓦雀行書案，點點楊花入硯池。", "閒坐小窗讀周易，不知春去幾多時。"]'),
('d40f6287-7ca8-4f3b-b27f-832ba7561098','讀易象','周敦頤','宋','宋诗','song-poetry','','[]','書房兀坐萬機休，日暖風和草色幽。',32,'全唐诗/poet.song.24000.json','["書房兀坐萬機休，日暖風和草色幽。", "誰道二千年遠事，而今只在眼前頭。"]'),
('915acfb4-54e0-4a58-8318-dc03d1f36811','題清芬閣','周敦頤','宋','宋诗','song-poetry','','[]','風雅久淪落，哇淫肆自陳。',144,'全唐诗/poet.song.24000.json','["風雅久淪落，哇淫肆自陳。", "波瀾嗟已靡，汗漫□無津。", "紛葩混仙蕊，誰可識清真。", "先生李鄭輩，□態非擬倫。", "後生不識事，愈非句愈珍。", "至今桐廬水，相與流清新。", "蟬聯十一世，奕葉扶陽春。", "十年問御史，邂逅章江濱。", "自慚無所有，衰嘆徒欣欣。", "樽酒發狂笑，微言入典墳。", "稍稍窺緒餘，每每露經綸。", "因知相有術，源委本清淳。"]'),
('7ed5ba58-98ea-424c-a05a-b4ffb37c3f3a','贈周茂叔','何平仲','宋','宋诗','song-poetry','','[]','及物仁心稱物情，更將和氣助春榮。',64,'全唐诗/poet.song.24000.json','["及物仁心稱物情，更將和氣助春榮。", "智深大易知幽賾，樂本咸池得正聲。", "竹箭生來元有節，冰壺此外更無清。", "幾年天下聞名久，今日逢君眼倍明。"]'),
('54fbb00f-b209-427b-ad26-4068816da819','聞周茂叔中年有嗣以詩賀之','何平仲','宋','宋诗','song-poetry','','[]','慶門崇構已多時，五百年方是此期。',64,'全唐诗/poet.song.24000.json','["慶門崇構已多時，五百年方是此期。", "樹長瓊枝生較晚，珠根驪頷得來遲。", "桓溫貴骨天然別，韋相傳經道不衰。", "衡岳維高湘水闊，共知長與福爲基。"]'),
('46884b20-70d2-49bb-b5fd-ea5f26daa23b','題周茂叔拙賦','何平仲','宋','宋诗','song-poetry','','[]','僞者勞其心，關機有時闕。',36,'全唐诗/poet.song.24000.json','["僞者勞其心，關機有時闕。", "誠者任其真，安知拙爲拙。", "捨僞以存誠，何須俟詞說。"]'),
('7e8f99d3-34b3-4211-96ee-8ac89a8c667d','郊祀慶成詩','陳襄','宋','宋诗','song-poetry','','[]','皇帝即位，厲精求治。',210,'全唐诗/poet.song.24000.json','["皇帝即位，厲精求治。", "翼翼兢兢，以畏天異。", "乃見宗廟，乃嚴郊祭。", "赫赫烈祖，陟配上帝。", "皇帝肇祀，心虔誠至。", "齋居撤膳，夙興弗寐。", "不履黄道，不御小次。", "出宿于廟，陰雨翳翳。", "既其徂郊，日出晰晰。", "登丘奏假，天地澄霽。", "禮終樂闋，神貺來暨。", "皇帝還蹕，千乘萬騎。", "雷動天旋，臣民欣慰。", "御樓肆赦，躬冊丹地。", "恩流澤洽，周匝無際。", "惟誠感神，惟德銷沴。", "皇帝能饗，時賜坐致。", "臣願皇帝，事天寅畏。", "左右惟賢，安民惟惠。", "無咈忠諫，無輕政事。", "日新一日，庶答天意。"]'),
('58aa1c76-29ce-4f74-a183-b171e35400e3','洛陽曲','陳襄','宋','宋诗','song-poetry','','[]','有客頓征轡，暮宿洛陽堤。',120,'全唐诗/poet.song.24000.json','["有客頓征轡，暮宿洛陽堤。", "洛陽繁華地，慨然心傷悲。", "憶昔季倫家，朱門鼎貴時。", "錦步四十里，冠蓋相追隨。", "寵移百琲珠，醉擊珊瑚枝。", "一旦委溝壑，身隨朝露晞。", "綺樓自顛仆，金谷無人歸。", "綠珠千古魂，散作香塵飛。", "荒榛塞中道，惟有寒螿啼。", "嗟哉百世後，驕奢徒爾爲。"]'),
('3080fd12-39f2-4809-a135-c7bd04c4978e','人生天地間','陳襄','宋','宋诗','song-poetry','','[]','天無私覆心，地無私載德。',72,'全唐诗/poet.song.24000.json','["天無私覆心，地無私載德。", "人生天地間，榮辱何相隔。", "農者不釋耒，朱門列鼎食。", "巧婦不下機，公子羅紈飾。", "富貴豈勞心，饑寒空努力。", "惟有北邙山，冢墓皆荆棘。"]'),
('998194c9-e9c5-4b6f-afe1-07a16a2421ab','天道不可躋','陳襄','宋','宋诗','song-poetry','','[]','天道不可躋，以其高且危。',60,'全唐诗/poet.song.24000.json','["天道不可躋，以其高且危。", "地道不可尋，以其幽且深。", "土圭測日影，可以分照臨。", "桐魚擊石鼓，可以求聲音。", "嗟夫世之人，不知方寸心。"]'),
('56771ffe-5c4b-401e-955a-a7c8b9317a57','古劍謝李惟肖示所業','陳襄','宋','宋诗','song-poetry','','[]','天工鑄劍挺鋒鋩，洪爐百鍊金爲剛。',160,'全唐诗/poet.song.24000.json','["天工鑄劍挺鋒鋩，洪爐百鍊金爲剛。", "閃鑠神鎚飛電光，磨礪七彩成文章。", "豐城地僻淪精久，紫氣雄雄射星斗。", "未得神功倚天外，一朝誤入張華手。", "青霜爲鍔寶爲環，有時捧出黄金盤。", "萬靈照灼妖氛走，天地無光秋水寒。", "聞道華陰有奇土，試拭繁星袖中舞。", "風胡側目觀如堵，一唱人間萬金賈。", "夜來幾度風雷嗔，雌雄出沒光如神。", "來年决定化平津，坐中有客攀龍鱗。"]'),
('b7bb8d29-dbac-4961-86da-32539e7a5885','送鄭洙赴舉','陳襄','宋','宋诗','song-poetry','','[]','天上奎星專主文，地下嵩嶽惟降神。',160,'全唐诗/poet.song.24000.json','["天上奎星專主文，地下嵩嶽惟降神。", "含靈孕粹五百載，挺然間出非常人。", "滎陽才子東山客，滿腹精神太英特。", "掞天辭藻駕曹王，炙地聲華壓元白。", "等閒奮筆摛鸞龍，烟霄凜凜橫辭鋒。", "稷下千人摧勁敵，昂頭不敢爭英雄。", "吾皇新命招宏博，紫宙風清飛一鶚。", "驪龍卧起滄海空，燦燦靈珠光滿握。", "明年二月春水來，桃花浪起龍門開。", "青雲岐路無多地，定須迅擊狂風雷。"]'),
('d061923a-364a-44d9-bbab-9350c494f36e','苦熱謠','陳襄','宋','宋诗','song-poetry','','[]','瑶姬不下巫陽臺，山屏曙色連雲開。',106,'全唐诗/poet.song.24000.json','["瑶姬不下巫陽臺，山屏曙色連雲開。", "瞥見羲和整朝馭，放出金烏天上來。", "炎炎六月方凝暑，天地生成渴霖雨。", "呼號縮手太無端，憔悴群芳不爲主。", "吾當化出沖天羽，上與天公振雷鼓。", "迴却日輪，叱開水府。", "六龍驅下飲洪濤，大作寒霖濟區宇。"]'),
('7d7338b8-851b-4a8f-87cc-54c0c0865af0','喜雪','陳襄','宋','宋诗','song-poetry','','[]','有客何方來，粲然游我庭。',156,'全唐诗/poet.song.24000.json','["有客何方來，粲然游我庭。", "推戶出見之，顔色如瑶英。", "問之不吾語，微風若聞聲。", "曰予朔方士，飲子南方名。", "萬里不相識，修塗一來經。", "聞子官大府，高車塵冥冥。", "有言未嘗吐，低頭斂光精。", "西人趨向異，念予孤蒙行。", "我欲友其德，顧己鴻毛輕。", "予起謝不敏，過辭非予聆。", "感子虛白德，來化純愚誠。", "高風激萬世，凜如伯夷清。", "留子永今日，願言報英瓊。"]'),
('2a97da17-ed99-45bf-8d91-5b5cc650d44d','通判國博命賦假山','陳襄','宋','宋诗','song-poetry','','[]','去年水潦百穀死，居民無食食糟秕。',288,'全唐诗/poet.song.24000.json','["去年水潦百穀死，居民無食食糟秕。", "州之餓者數千人，黄巖之民猶倍蓰。", "携持老少出城郭，盡撤牆屋無居止。", "鬻妻棄子人不售，價例不復論羊豕。", "白日市井聞號叫，夜堆廊廡如蟲豸。", "縣官哀憐發賑救，一飯纔得一盂爾。", "出門未暇充喉咽，已有數十填溝水。", "我時過之不忍顧，往往悲咽胸填委。", "豈無智慮裨萬一，遠地不得號君耳。", "錢侯作倅忠且仁，悲憐餓殍如親子。", "日開官廩與之食，又令豪右發儲峙。", "昨日馳書白轉運，披陳肝腎獻金矢。", "更乞兵儲二萬斛，民之大命方有倚。", "侯從新年作假山，自聞民饑不得視。", "非無泉石可般樂，人今方瘁何能喜。", "願侯勿遽愛此山，念此膢臘存狐蟻。", "天無疫癘五穀熟，生者保聚歸田里。", "此山之石堅不堅，將與侯德無窮已。"]'),
('47367527-6c23-4077-a839-49514c50c3a4','送李惟肖尉尤溪','陳襄','宋','宋诗','song-poetry','','[]','朝廷厭煩苛，往還按察詔。',288,'全唐诗/poet.song.24000.json','["朝廷厭煩苛，往還按察詔。", "四方小大官，政惡日無譙。", "悲哉窮遠民，天耳不可嘂。", "訟爭細毛髪，吏議舉烽爝。", "追胥煩閭里，符牒紛以炤。", "利手肆拂攖，百巧鑿孔竅。", "齊氓一擾攘，沸若烹鮮銚。", "上下漫不省，鰥寡日相弔。", "咨嗟夢得材，連蹇十銓調。", "今復欎不施，一尉濱海嶠。", "蠢茲尤溪民，習俗攻險僄。", "尺表易爲直，長戈固難掉。", "吾聞政無小，媺惡出號召。", "雖爾主盜官，操權寧非要。", "近歲民艱食，群小屢軒趒。", "揮刀力誅鋤，加以原火燎。", "政令務寬簡，威肅宜震曜。", "武事戒不習，賤策貴前料。", "山林剔逋逃，道路剪攻剽。", "食禁寧疏網，私兵勿容鞘。", "嘗聞伍保法，慎置理宜妙。", "法至姦可革，無事省巡徼。", "勿嗟厥位淹，十室聊歌笑。", "往矣有吾民，瘡痍方爾療。"]'),
('e300a570-f493-4f35-a51e-7829838a7da4','病驥','陳襄','宋','宋诗','song-poetry','','[]','騏驥出大野，天姿非權奇。',144,'全唐诗/poet.song.24000.json','["騏驥出大野，天姿非權奇。", "俄然病槽廄，筋力不克施。", "世人不識馬，共以駑駘期。", "芻菽不得飽，膏砭不得醫。", "伯樂聞驥病，中心始懷疑。", "及觀果無妄，引銜脫其羈。", "騏驥心感激，雙瞳雨淋離。", "懷恩未能報，舉聲一鳴悲。", "馬得起此疾，上爭靈烏馳。", "朝出扶桑野，暮扳鄧林枝。", "追隨日月下，獨立寒且饑。", "此力豈足詫，願酬主人知。"]'),
('4d2c5e0b-d3a5-4824-a0f0-265ae5f8c2e7','幽菊燕貢士  其一','陳襄','宋','宋诗','song-poetry','','[]','有幽斯菊，濯濯其芳。',38,'全唐诗/poet.song.24000.json','["有幽斯菊，濯濯其芳。", "烝爾髦士，惟其修兮，有美於鄉。", "燕，予無以說兮，惟醴之觴。"]'),
('6d0374cc-7efa-4329-8871-ad2944c78c50','幽菊燕貢士  其二','陳襄','宋','宋诗','song-poetry','','[]','有幽斯菊，燁燁其華。',38,'全唐诗/poet.song.24000.json','["有幽斯菊，燁燁其華。", "烝爾髦士，惟其施兮，有顯於家。", "往，予無以將兮，惟古之歌。"]'),
('ead85199-3616-4db2-b669-0cb0d9062f5e','送關都官致仕  其一','陳襄','宋','宋诗','song-poetry','','[]','鴻鳥于飛，歸戾于澤。',30,'全唐诗/poet.song.24000.json','["鴻鳥于飛，歸戾于澤。", "君子于田，亦適維則。", "旅力不愆，曷云其極。"]'),
('e1d9e72f-720c-4f10-be69-ecc4f5dd6ef2','送關都官致仕  其二','陳襄','宋','宋诗','song-poetry','','[]','庶民之耋，職自爲愚。',30,'全唐诗/poet.song.24000.json','["庶民之耋，職自爲愚。", "君子之耋，其德有濡。", "旅力不愆，曷云其劬。"]'),
('fea4fae0-058f-4f1d-af71-050eaac8af8a','送關都官致仕  其三','陳襄','宋','宋诗','song-poetry','','[]','有堅松柏，君子斧之。',30,'全唐诗/poet.song.24000.json','["有堅松柏，君子斧之。", "有實秠稷，農夫有之。", "天子有老，曷其與歸。"]'),
('30cac000-3d58-4f91-9c50-85b4e8b1dd2e','送關都官致仕  其四','陳襄','宋','宋诗','song-poetry','','[]','野有白駒，來食我麰。',30,'全唐诗/poet.song.24000.json','["野有白駒，來食我麰。", "君子之往，胡爲不留。", "我心悠悠，爲天子憂。"]'),
('b93bad0b-0faa-49ff-ac6f-c0a21be7dac4','祈雨','陳襄','宋','宋诗','song-poetry','','[]','慶曆甲申歲，旱極憂民田。',216,'全唐诗/poet.song.24000.json','["慶曆甲申歲，旱極憂民田。", "農夫不得耕，相顧愁凶年。", "帝心恐民憂，詔遣祈山川。", "郡國舉祀典，齋戒陳豆籩。", "望祭復雩龍，禱之必精虔。", "經旬杳無報，旱氣增于前。", "菑田揚飛塵，井谷無寸泉。", "炎炎天地中，草木皆欲燃。", "俗云有鰻魚，靈異古所傳。", "太守順民心，命駕而迎焉。", "樂以鐘鼓音，薰以沈檀烟。", "儵驚西郊寒，靄靄離山巔。", "急雨下滂沱，迅雷亦填填。", "須臾畎畝盈，一境皆欣然。", "始爲穴中魚，竊弄陰陽權。", "山川豈無神，不能通于天。", "蛟龍豈無靈，不能興於淵。", "有若賞罰柄，反使奸臣專。"]'),
('1c2e494c-582c-46f5-add7-e2c1c40df240','寄弟衮','陳襄','宋','宋诗','song-poetry','','[]','作詩寄弟衮，寫我心之幽。',288,'全唐诗/poet.song.24000.json','["作詩寄弟衮，寫我心之幽。", "比聞堂上安，讀書可優游。", "昨者得兄書，言汝看蔡侯。", "蔡侯實君子，小善固所收。", "知汝言可否，果聞書相酬。", "蔡侯讀吾策，言語何贅疣。", "吾言至草略，聞說畏可羞。", "昨又得汝書，嗟汝誠拙謀。", "自言已可進，曾知易春秋。", "人不患無位，患己德不修。", "古人亦有言，富貴焉可求。", "吾初將移任，將白高與劉。", "恐人不我知，自後遽止休。", "前時陸通判，令我速置郵。", "吾誠欲求之，豈自無舌喉。", "奈何不爲耳，死且垂直鈎。", "自吾到山冶，于物無侵牟。", "小民得辛苦，稍稍知饒優。", "官家足厚利，私亦不怨尤。", "福哥賣銀礦，軍人却首偷。", "案成被官杖，鞭箠見血流。", "私恩重血肉，官法難庇庥。", "此奴實癡戇，教誨不轉頭。", "吾心不樂此，疾病苦未瘳。"]'),
('06173a78-7b5a-4cfa-adaf-488b58fad607','送章舍人知汝州','陳襄','宋','宋诗','song-poetry','','[]','神馬産渥洼，舉世蓋云罕。',120,'全唐诗/poet.song.24000.json','["神馬産渥洼，舉世蓋云罕。", "使之循蟻封，曾不逮駑款。", "丈夫懷義命，所學務充滿。", "惟憂用捨非，富貴庸可算。", "吾君優輔郡，責任地非散。", "牛刀久投虛，足以導大窾。", "孟軻言仁術，民事戒毋緩。", "矧茲凋瘵餘，食餒衣不暖。", "厚生爲政先，聚斂吾徒短。", "歸來奏優課，行道非遲晚。"]'),
('bb3ca263-197f-4f42-80a6-4b3e93d22a9c','樓上曲','陳襄','宋','宋诗','song-poetry','','[]','金徒抱箭寒更起，寂寞孤城一千里。',129,'全唐诗/poet.song.24000.json','["金徒抱箭寒更起，寂寞孤城一千里。", "姮娥擎出月華來，白玉樓臺瑩如水。", "上有佳人紅粉妝，妙年學得吹霓裳。", "呼兒將出紫玉笛，一聲天外流宮商。", "清商欲盡何幽咽，曲調不成聲斷絕。", "羅衣掩淚愁向天，手把瑶華歌一闋。", "寒蟾出兮明星稀，良人阻兮天一涯。", "憑軒遥望兮心傷悲，願隨鴻鵠兮高飛。"]'),
('df731a1d-89ea-4d2b-a428-93fc52bad496','荔枝歌','陳襄','宋','宋诗','song-poetry','','[]','番禺地僻嵐烟鎖，萬樹纍纍産嘉果。',192,'全唐诗/poet.song.24000.json','["番禺地僻嵐烟鎖，萬樹纍纍産嘉果。", "漢宮墜落金莖露，秦城散起驪山火。", "炎炎六月朱明天，映日仙枝紅欲燃。", "自古清芬不能遏，留得嘉名爲椹仙。", "上皇西去楊妃死，蠻海迢迢千萬里。", "華清宮闕闃無人，南來不見紅塵起。", "至今榮植遍閩州，離離朱實繁星稠。", "一日爲君空變色，千里憑誰速置郵。", "可憐錦幄神仙侶，爲飲凝漿滌煩暑。", "綺筵不惜十千錢，酩酊秦樓桂花醑。", "秦樓女子繡羅裳，鳳簫嗚咽流宮商。", "醉歌一曲荔枝香，席上少年皆斷腸。"]'),
('a762cbc7-ce44-4751-b7ae-493015ae57f8','對酒歌','陳襄','宋','宋诗','song-poetry','','[]','我聞靈鰲萬丈居海宮，峨峨頭戴三神峰。',117,'全唐诗/poet.song.24000.json','["我聞靈鰲萬丈居海宮，峨峨頭戴三神峰。", "匣有神刀刃如雪，便欲鱠之雕俎中。", "又聞銀濤一派天上來，寒光湛湛浸瑶魁。", "心有窮愁萬餘斛，便欲沃爲三兩杯。", "無人爲把天關叩，不放金烏飛、玉兔走。", "大嚼一臠肉，滿酌十分酒。", "然後酩酊歸醉鄉，不問其天之高、地之厚。"]'),
('b50bfd5d-bee4-409d-beda-1e24e65439b3','古靈山試茶歌','陳襄','宋','宋诗','song-poetry','','[]','乳源淺淺交寒石，松花墜粉愁無色。',130,'全唐诗/poet.song.24000.json','["乳源淺淺交寒石，松花墜粉愁無色。", "明星玉女跨神雲，鬥剪輕羅縷殘碧。", "我聞巒山二月春方歸，苦霧迷天新雪飛。", "仙鼠潭邊蘭草齊，露牙吸盡香龍脂。", "轆轤繩細井花暖，香塵散碧琉璃椀。", "玉川冰骨照人寒，瑟瑟祥風滿眼前。", "紫屏冷落沈水烟，山月堂軒金鴨眠。", "麻姑癡煮丹巒泉，不識人間有地仙。"]'),
('e0e28f11-d54a-4850-9fa9-246cd51de0ea','登彼公堂燕貢士  其一','陳襄','宋','宋诗','song-poetry','','[]','登彼公堂，維水湯湯。',20,'全唐诗/poet.song.24000.json','["登彼公堂，維水湯湯。", "君子燕湑，其言有章。"]'),
('30d9a1ed-37ec-422e-a6be-cda3b9452c36','登彼公堂燕貢士  其二','陳襄','宋','宋诗','song-poetry','','[]','登彼公堂，有松有柏。',20,'全唐诗/poet.song.24000.json','["登彼公堂，有松有柏。", "君子燕湑，其儀孔特。"]'),
('7a65d936-eb2e-4092-a457-7d7bf8dc0966','登彼公堂燕貢士  其三','陳襄','宋','宋诗','song-poetry','','[]','登彼公堂，維山崔嵬。',20,'全唐诗/poet.song.24000.json','["登彼公堂，維山崔嵬。", "君子燕湑，其志不回。"]'),
('8f6a3799-12d0-4be9-8b94-8ac8becff315','登彼公堂燕貢士  其四','陳襄','宋','宋诗','song-poetry','','[]','登彼公堂，鴻飛戾止。',20,'全唐诗/poet.song.24000.json','["登彼公堂，鴻飛戾止。", "君子燕湑，維其不已。"]'),
('5112cc0b-b322-4fa6-a694-51fad14986ec','游宜興法藏院觀桂紫菊花','陳襄','宋','宋诗','song-poetry','','[]','山茶花開菊花紫，青桂童童立花裏。',64,'全唐诗/poet.song.24000.json','["山茶花開菊花紫，青桂童童立花裏。", "柔姿翠幹已可憐，更傍幽叢看花蕊。", "山僧揖我臨階坐，眼到欄邊心即喜。", "便欲携歸種郡齋，忍令此地風烟埋。"]'),
('0f55be3d-ab18-47a2-b978-01e61e95c396','潘家山同章衡諸生飲次行令探得隠君子爲章衡搜出故賦詩云','陳襄','宋','宋诗','song-poetry','','[]','吾聞隠君子，大隠廛市間。',48,'全唐诗/poet.song.24000.json','["吾聞隠君子，大隠廛市間。", "道義充諸中，測度非在顔。", "堯帝神且智，知人亦孔艱。", "勉哉二秘閣，賢行如高山。"]'),
('0b2384c3-1543-46a3-bbdf-665d8ae3bd72','瀑布','陳襄','宋','宋诗','song-poetry','','[]','靈源寂寂何杳寞，先天後天誰疏鑿。',32,'全唐诗/poet.song.24000.json','["靈源寂寂何杳寞，先天後天誰疏鑿。", "疑是媧皇功未全，漏泄銀河斜界落。"]'),
('9d70e5d5-859f-4ec4-8016-4a4bd11bcc16','此景','陳襄','宋','宋诗','song-poetry','','[]','晚崿殘霞斷，晴空宿靄收。',48,'全唐诗/poet.song.24000.json','["晚崿殘霞斷，晴空宿靄收。", "綠蕪天共遠，明月水同流。", "落葉填秋望，孤碪答旅愁。", "提壺伴詩筆，獨醉庾公樓。"]'),
('761a1010-a12a-493b-8dee-181ebaf9ddf0','樓上旅懷','陳襄','宋','宋诗','song-poetry','','[]','樓上憶鄉關，憑高獨倚欄。',48,'全唐诗/poet.song.24000.json','["樓上憶鄉關，憑高獨倚欄。", "遠眸天外盡，愁思酒中寬。", "澤國吳蓴老，山城蜀道難。", "客帆歸未得，落日暮江寒。"]'),
('8dd4db1e-95e2-495d-bc87-a5f4d784d201','晚目','陳襄','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','攬景獨凝眸，江城暮雨收。',48,'全唐诗/poet.song.24000.json','["攬景獨凝眸，江城暮雨收。", "長江隔山斷，野水混空流。", "天上一輪月，人間萬古秋。", "感時并怨別，費盡庾郎愁。"]'),
('4b410d6c-50e3-4716-b508-41dc8b70ff31','幽齋','陳襄','宋','宋诗','song-poetry','','[]','幽徑絕塵蹤，莓苔上粉墉。',48,'全唐诗/poet.song.24000.json','["幽徑絕塵蹤，莓苔上粉墉。", "秋聲連夜雨，寒色一溪松。", "學有書千卷，歡無酒萬鍾。", "雲屏孤夢斷，寂寞掩巫峰。"]'),
('567513e8-26a3-43b9-b041-5fae6b3c8e80','驪宮悼往','陳襄','宋','宋诗','song-poetry','','[]','鳳輦情傷別，驪宮信不還。',48,'全唐诗/poet.song.24000.json','["鳳輦情傷別，驪宮信不還。", "雨鈴悲蜀道，金鈿杳蓬山。", "玉笛凉州怨，梨園法部閒。", "西廂人未至，樓閣五雲間。"]'),
('46803f5c-02f0-45d0-8f18-b487f4866fd2','對景偶書','陳襄','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','天角暝光收，空中爽氣流。',48,'全唐诗/poet.song.24000.json','["天角暝光收，空中爽氣流。", "雨迴巫峽暮，波起洞庭秋。", "塞闊歸鴻遠，林疏敗葉稠。", "碧雲音信絕，目斷五城樓。"]'),
('02c3165f-8b1e-4a1c-b495-831dfd7c11b2','金華山人','陳襄','宋','宋诗','song-poetry','','[]','幽居倚翠巒，塵事不相干。',48,'全唐诗/poet.song.24000.json','["幽居倚翠巒，塵事不相干。", "天地醉來小，琴棋靜裏歡。", "雨苔春徑綠，風竹夜窗寒。", "若問長生術，金爐有寶丹。"]'),
('87c67533-70df-4dac-82e1-fa01239043ed','宮辭','陳襄','宋','宋诗','song-poetry','','[]','六六上陽宮，嬋娟被寵封。',48,'全唐诗/poet.song.24000.json','["六六上陽宮，嬋娟被寵封。", "三千香輦路，十二枕屏風。", "紈扇傷秋咏，梅花妒曉容。", "妝臺銀燭盡，寶帳泣芙蓉。"]'),
('2649f3a7-9707-45e9-8c26-ba78a138e94a','荷華','陳襄','宋','宋诗','song-poetry','','[]','翠蓋田田綠，繁華艷艷紅。',48,'全唐诗/poet.song.24000.json','["翠蓋田田綠，繁華艷艷紅。", "有容欺水國，無力舞秋風。", "緩步迎潘后，纖腰學楚宮。", "涉江人不見，兩槳石城東。"]'),
('384d0ebe-3a0f-4c25-9594-50ae74a1fd61','夕霽','陳襄','宋','宋诗','song-poetry','','[]','積雨向宵晴，氛埃蕩杳冥。',48,'全唐诗/poet.song.24000.json','["積雨向宵晴，氛埃蕩杳冥。", "高樓微射月，腐草半流螢。", "電女千嬌斂，雲臺一夢醒。", "上皇歸未得，歌斷雨中鈴。"]'),
('0b62f4af-7404-44c5-a8bf-413c36e99b77','題積善院','陳襄','宋','宋诗','song-poetry','','[]','幽寺訪禪客，煩襟此一開。',48,'全唐诗/poet.song.24000.json','["幽寺訪禪客，煩襟此一開。", "山空有猿鶴，地僻無塵埃。", "烹茶綠雲起，鼓扇清風來。", "覽景不歸去，暮烟生古臺。"]'),
('b5d3cf57-27bc-4769-8fdc-682358da4924','和鄭閎中仙居十一首  其一','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，臨民必以誠。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，臨民必以誠。", "簿書無日暇，獄訟積年生。", "百疾求箴補，千鈞待準平。", "嗟予不如古，斯道未能宏。"]'),
('7c741895-5de2-4751-b656-db559e89716c','和鄭閎中仙居十一首  其二','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，安民去百姦。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，安民去百姦。", "誠心雖照物，政體昧循環。", "喜有綱條立，慚無教令頒。", "三年憂且病，王事豈能閒。"]'),
('26f6e3f0-445a-4fb5-a42e-ff381b15e573','和鄭閎中仙居十一首  其三','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，園池日退居。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，園池日退居。", "馴禽來鶴鶴，野水進徐徐。", "草樹通樵採，桑麻有老鋤。", "猶言民未樂，更待寢刑書。"]'),
('9d0266d9-c7b0-4387-aef1-125f931582b0','和鄭閎中仙居十一首  其四','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，經營盡國工。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，經營盡國工。", "庶民心喜悅，小邑勢尊隆。", "萬瓦如雲合，千題不日礱。", "自非仁惠術，愧子一觀風。"]'),
('976f4e2a-ac60-4f77-8fc1-f3eee69a8dce','和鄭閎中仙居十一首  其五','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，官卑分已盈。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，官卑分已盈。", "才非漢循吏，道似魯狂生。", "擊柝心雖樂，觀民志未平。", "寧如孟夫子，不食去齊卿。"]'),
('d8c541ce-93f0-437a-a908-a7ac94372d2e','和鄭閎中仙居十一首  其六','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，隆儒尠大方。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，隆儒尠大方。", "諸生令講藝，童子俾升堂。", "買地興民學，驅車下黨庠。", "三年邑未化，官滿意彷徨。"]'),
('4d9c30ad-d64a-4511-ab0d-2bfe0d29f7f0','和鄭閎中仙居十一首  其七','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，公餘日在房。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，公餘日在房。", "憂民極反覆，責己未周詳。", "法律行隨手，詩書坐滿箱。", "老來須向學，多病喜平康。"]'),
('14b9dc71-34bd-426c-a3fd-024520d3deb9','和鄭閎中仙居十一首  其八','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，家居十數人。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，家居十數人。", "民窮惟有疾，俸薄不知貧。", "弟妹閒成癖，妻孥老未淳。", "自餘無所恨，寸祿及偏親。"]'),
('8c73cf5a-ff69-4d0f-8a0b-4215db66315c','和鄭閎中仙居十一首  其九','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，慚無德政馨。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，慚無德政馨。", "下車時問疾，治獄日空囹。", "老吏貧歸里，蒼生餒在庭。", "惟憂澤未至，豈敢瀆邦刑。"]'),
('9b1ba6aa-33ff-4dd6-813f-8744e79ea9e3','和鄭閎中仙居十一首  其一○','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，三年理尚寬。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，三年理尚寬。", "民雖離網罟，政未息風瀾。", "憫物刑多省，勞心席少安。", "祗慚無惠術，求配古人難。"]'),
('79b4c1a6-91d5-40af-b0eb-c362f8f9d179','和鄭閎中仙居十一首  其一一','陳襄','宋','宋诗','song-poetry','','[]','我愛仙居好，民純不用拘。',48,'全唐诗/poet.song.24000.json','["我愛仙居好，民純不用拘。", "閭閻興禮讓，囹圄長榛蕪。", "網闊姦逾少，風恬惡自無。", "一年人已信，感激謝張弧。"]'),
('7efbf788-afc0-4478-849c-f9f050b3ef1f','送崔黄臣知廬山縣','陳襄','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','勿嘆廬山遠，天涯總是民。',48,'全唐诗/poet.song.24000.json','["勿嘆廬山遠，天涯總是民。", "還家安老母，去國慕忠臣。", "斜月秦關曉，穠花錦里春。", "臨行無所贈，爲邑莫如仁。"]'),
('782c849c-0d20-4a87-baeb-e96f09821811','仙居縣署巖老亭','陳襄','宋','宋诗','song-poetry','','[]','手持養性書，此地學耕漁。',48,'全唐诗/poet.song.24000.json','["手持養性書，此地學耕漁。", "身似龍蛇蟄，情忘木石居。", "地迷成遠復，政靜得中虛。", "何必求深隠，幽蒙即所廬。"]'),
('a645217c-fb3d-4b26-934b-583cf7298a46','贈剡縣過頊秘丞','陳襄','宋','宋诗','song-poetry','','[]','賢哉過縣尹，德政是吾師。',48,'全唐诗/poet.song.24000.json','["賢哉過縣尹，德政是吾師。", "萬事無鋒穎，一心惟孝慈。", "家貧因客冗，髪白爲民饑。", "誰刻前山石，令人去後思。"]'),
('114735cc-b7fb-4e41-801d-9653b7e4b2e1','和運使兵部秋成','陳襄','宋','宋诗','song-poetry','','[]','重湖收積潦，多稼結盈疇。',48,'全唐诗/poet.song.24000.json','["重湖收積潦，多稼結盈疇。", "貸息移書減，逋租案籍求。", "民情寬蹙頞，歲計上參謀。", "寄語昆堂老，生初早晚修。"]'),
('bb6b81ae-e663-4a79-84fb-21f2c10676fd','皇祐四年春重到浦城縣南峰寺因懷舊遊','陳襄','宋','宋诗','song-poetry','','[]','重到南峰寺，尋思九日遊。',48,'全唐诗/poet.song.24000.json','["重到南峰寺，尋思九日遊。", "黄花何處去，白雪有誰留。", "薄宦三千里，流光四十秋。", "歸來見諸子，林下好相求。"]'),
('9164df99-56ac-407d-9b96-126382ada0aa','重陽席上賦菊花','陳襄','宋','宋诗','song-poetry','','[]','折菊東籬下，携觴爲燕遨。',48,'全唐诗/poet.song.24000.json','["折菊東籬下，携觴爲燕遨。", "閒情秋後放，幽艷靜中高。", "九月陶公酒，三閭楚客騷。", "及時須採掇，忍使棄蓬蒿。"]'),
('1d67e3c0-ec79-490f-8c3f-94d27ee489fb','依韵和酬子直重陽送酒','陳襄','宋','宋诗','song-poetry','','[]','君有雲泉酒，詩來寄我嘗。',48,'全唐诗/poet.song.24000.json','["君有雲泉酒，詩來寄我嘗。", "色過金菊淡，味带木蘭香。", "北固山城秀，東園水榭凉。", "無因陪落帽，孤酌負重陽。"]'),
('15645ee3-f0ef-4762-8683-099a99812705','次韵朱兵部上巳錫宴','陳襄','宋','宋诗','song-poetry','','[]','禊飲開天苑，英遊綴士林。',72,'全唐诗/poet.song.24000.json','["禊飲開天苑，英遊綴士林。", "鹿苹常長養，魚藻遂浮沈。", "和氣春臺暖，恩波曲水深。", "追隨方外樂，歌吹夢中音。", "忽起江湖興，久無軒冕心。", "鶑花應笑我，華髪已盈簪。"]'),
('356a10cd-e6a1-4d21-ba64-0ba01cb560ff','墨崖道中作','陳襄','宋','宋诗','song-poetry','','[]','陰山沙漠外，六月苦行人。',48,'全唐诗/poet.song.24000.json','["陰山沙漠外，六月苦行人。", "水迸金蓮曉，湯回鐵脚春。", "馬饑思漢草，僕病卧胡塵。", "夜夢京華阻，披衣望北辰。"]'),
('510dc992-9d2f-4ed6-8879-a3075f4dae36','水口贈別大吉祖師長老','陳襄','宋','宋诗','song-poetry','','[]','直向此間明，縱橫語論精。',48,'全唐诗/poet.song.24000.json','["直向此間明，縱橫語論精。", "山中曾出世，海上未知名。", "一雨春溪漲，千峰曉雪晴。", "臨分無別說，相送水邊行。"]'),
('1cce4635-a642-48b6-876b-809cf5ba18f7','舟次巴峽','陳襄','宋','宋诗','song-poetry','','[]','江流何險阻，次第入三巴。',48,'全唐诗/poet.song.24000.json','["江流何險阻，次第入三巴。", "崖斷時無路，山深更有家。", "林蔬饒竹笋，鄉果足枇杷。", "况有荆州酒，淹留不用嗟。"]'),
('ce7e551a-4372-4760-a37c-7340070c8aa9','哭倪氏女弟亡兒傳孫','陳襄','宋','宋诗','song-poetry','','[]','骨肉天涯別，風塵客子悲。',48,'全唐诗/poet.song.24000.json','["骨肉天涯別，風塵客子悲。", "孟州新喪妹，夔峽繼亡兒。", "燭暗猿啼夜，城空日落時。", "肝腸已無淚，只是腦中脂。"]'),
('c3ac858c-0023-4934-8eb9-8c24f7e73f8d','觀海','陳襄','宋','宋诗','song-poetry','','[]','天柱支南極，蓬山壓巨鼇。',49,'全唐诗/poet.song.24000.json','["天柱支南極，蓬山壓巨鼇。", "雲崩石道險，潮落海門高。", "客館聞鼉鼓，秋風憶蟹螯。", "倚欄望鄉墅，千里楚江拜皋。"]'),
('b8b60b00-e3f1-449a-8bcf-98ea87e9d37a','咏雪','陳襄','宋','宋诗','song-poetry','','[]','三日連綿雪，豐年預可占。',288,'全唐诗/poet.song.24000.json','["三日連綿雪，豐年預可占。", "陰寒驅瘴毒，刑殺助天殲。", "片片尋衣袂，花花飣屋檐。", "來時須浩漫，到地即微纖。", "狼籍無由掃，虛空不易拈。", "溪流成瀺灂，野色變青黔。", "洗硯冰霜合，烹茶氣味甜。", "行人留趾跡，村老上髭髯。", "只被交加惑，寧爲冷凍厭。", "價高龜手藥，勢壓酒家帘。", "書案煩收拾，銅鑪減顧瞻。", "先春嬌柳絮，永夜奪銀蟾。", "磵石懸飛瀑，園籬挂織縑。", "山光韜美玉，水鹵出形鹽。", "圓若珠璣剖，輕如鵠鷺燖。", "高疑翻箭浪，碎是擲牙籤。", "蕭灑偏低竹，綢繆更倚蒹。", "絲繩浮井谷，寶鑒照妝奩。", "毫髪吹先起，脂膏著自黏。", "垂枝多綫縷，鬅物利刀鐮。", "粲者詩風美，皤如賁主嫌。", "夷齊羞潔白，郅寧等威嚴。", "草樹多摧折，萌芽苦滯淹。", "霑濡雖近惠，染污劇傷廉。"]'),
('d1bb8132-42e5-49f6-9f1c-af81bdb17429','留題表兄三哥養浩亭','陳襄','宋','宋诗','song-poetry','','[]','華構敞雲扃，人幽境亦靈。',48,'全唐诗/poet.song.24000.json','["華構敞雲扃，人幽境亦靈。", "心閒生浩氣，味薄得真經。", "鑿沼觀魚樂，開樽與酒盟。", "由來知此趣，何暇問攖寧。"]'),
('ad71eeb2-74cf-4372-ac6b-f6136023a4b4','九日與浦城縣學諸生遊南峰院','陳襄','宋','宋诗','song-poetry','','[]','九日黄花節，新樽綠蟻浮。',48,'全唐诗/poet.song.24000.json','["九日黄花節，新樽綠蟻浮。", "投壺鳴魯鼓，歌者似商謳。", "諸子衣冠盛，先儒禮樂修。", "西巖山景好，爲爾作陽秋。"]'),
('dffb578f-21cd-4afa-834d-b7900179150a','遊南塔','陳襄','宋','宋诗','song-poetry','','[]','今日遊南塔，愁還不自勝。',48,'全唐诗/poet.song.24000.json','["今日遊南塔，愁還不自勝。", "年華催鬒髪，身計憶巖稜。", "道業慚諸子，根源畏老僧。", "何當論去就，細問得龜朋。"]'),
('409cf2d8-f3ed-4522-bdad-856e4f4710a1','送別探得南字','陳襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','謫宦情牢落，窮通理更諳。',240,'全唐诗/poet.song.24000.json','["謫宦情牢落，窮通理更諳。", "讀書閒不廢，事道古何慚。", "昔喜鄰州守，嘗陪後乘驂。", "西湖遊未厭，北海飲方酣。", "躡屐登雲嶠，捫蘿訪竹庵。", "鷺濤千頃雪，鷲嶺萬堆藍。", "姤遇時難一，睽離歲忽三。", "陪京方接畛，歸省會同參。", "士子文宗愈，朝廷禮問聃。", "好留君左右，俄領郡東南。", "歲旱錢仍貴，民饑命不堪。", "下車寬賦役，露冕訓田蠶。", "畫舸乘春別，新書卜日覃。", "牙旗風發發，瑞節虎眈眈。", "龍鳳吳王國，烟霞古佛龕。", "荷香輕泛浦，桂子靜飄嵐。", "草澤行吟苦，蘭陔奉養甘。", "子文無慍色，夷甫足清談。", "物外冥天籟，樽前據石楠。", "惟應憐舊尹，漁釣負江潭。"]'),
('a8d9a90d-bdfd-4cc4-8fcc-1361e496a386','英宗皇帝挽詞二首  其一','陳襄','宋','宋诗','song-poetry','','[]','才武真賢主，憂勤出至誠。',48,'全唐诗/poet.song.24000.json','["才武真賢主，憂勤出至誠。", "五年膺大統，一旦享英名。", "鳳駕乘霞遠，龍樓繼日明。", "永言配昭考，陵寢卜周京。"]'),
('1ecd95d3-184c-43d1-8a7e-7439df39b31b','英宗皇帝挽詞二首  其二','陳襄','宋','宋诗','song-poetry','','[]','玉几言猶在，雲天去莫攀。',48,'全唐诗/poet.song.24000.json','["玉几言猶在，雲天去莫攀。", "久長期享國，咫尺忽違顔。", "信默歸元子，遺留暨百蠻。", "孤臣方仗節，無計哭橋山。"]'),
('ffcd2b82-28b6-45b4-bef5-a9ce3223bb45','蘇明允府君挽詞','陳襄','宋','宋诗','song-poetry','','[]','禮閣儀新奏，延英席久虛。',48,'全唐诗/poet.song.24000.json','["禮閣儀新奏，延英席久虛。", "自從掩關卧，無復草玄書。", "東府先生誄，西山孝子廬。", "誰言身後事，文止似相如。"]'),
('a8affc41-a6c8-4dda-929b-d1009b345e5e','故太師中書令曾魯公挽詞二首  其一','陳襄','宋','宋诗','song-poetry','','[]','天錫興王佐，三朝秉化鈞。',48,'全唐诗/poet.song.24000.json','["天錫興王佐，三朝秉化鈞。", "平生清儉節，臨老退閒身。", "赤舄榮封國，緇衣美世臣。", "永陪英廟享，千載德名新。"]'),
('c6f7f08a-2d2f-486a-ab5e-60a57b7774b6','故太師中書令曾魯公挽詞二首  其二','陳襄','宋','宋诗','song-poetry','','[]','南臺沙合後，元宰應時生。',48,'全唐诗/poet.song.24000.json','["南臺沙合後，元宰應時生。", "兩控龍飛馭，三調寶鼎烹。", "築山裴相樂，賜杖孔家榮。", "無復安輿出，兒孫衣綵迎。"]'),
('2b02c306-b9de-47d4-9d56-b9b30948e4d5','濮妃袝廟挽詞二首  其一','陳襄','宋','宋诗','song-poetry','','[]','天子徽柔德，神資鞠育仁。',48,'全唐诗/poet.song.24000.json','["天子徽柔德，神資鞠育仁。", "來歸聲子室，去錫大任身。", "白日佳城啟，黄麾法杖新。", "行觀升袝禮，簫鼓鳳臺春。"]'),
('9c011b37-618c-46b0-b4bb-aed5519cea5b','濮妃袝廟挽詞二首  其二','陳襄','宋','宋诗','song-poetry','','[]','帝位重明久，王儀一品尊。',48,'全唐诗/poet.song.24000.json','["帝位重明久，王儀一品尊。", "詔更神主號，義詘母慈恩。", "老柏遺蕭寺，新陵袝濮園。", "千年嵩洛氣，長發在元孫。"]'),
('89ff414f-262c-474b-843e-def8a2876149','寄謝三井山禱雨二首  其一','陳襄','宋','宋诗','song-poetry','','[]','曾禱神龍井，雲林杳莽間。',48,'全唐诗/poet.song.24000.json','["曾禱神龍井，雲林杳莽間。", "蘋蘩朝薦廟，風雨夜離山。", "百里田疇熟，一年囹圄閒。", "因循失報謝，石險路難攀。"]'),
('f3327ca5-3ff4-43ca-bf99-76537c83bbc5','寄謝三井山禱雨二首  其二','陳襄','宋','宋诗','song-poetry','','[]','何年修廟貌，棟宇已摧殘。',48,'全唐诗/poet.song.24000.json','["何年修廟貌，棟宇已摧殘。", "牲幣三時少，風泉四月寒。", "野僧多稌穥，古木有杉欒。", "深欲重修葺，蹉跎又解官。"]'),
('ef9d8208-f52f-448b-a5aa-4c36c6ff329b','潁州府學釋奠先聖郡中童子亦來拜謁以詩勉之','陳襄','宋','宋诗','song-poetry','','[]','藹藹青衿子，來修謁廟儀。',24,'全唐诗/poet.song.24000.json','["藹藹青衿子，來修謁廟儀。", "憐他眉宇秀，中有起家兒。"]'),
('5ac0838a-5dba-4bd1-8e6a-a702f9b5f85d','慈竹','陳襄','宋','宋诗','song-poetry','','[]','天生爾慈竹，恩義不相分。',48,'全唐诗/poet.song.24000.json','["天生爾慈竹，恩義不相分。", "直節雖然勁，虛心所以群。", "兒孫同約束，霜雪共辛勤。", "我願坐中客，結交同此君。"]'),
('894fff73-4a1a-4d0e-9116-ca86ca670162','經武夷山','陳襄','宋','宋诗','song-poetry','','[]','萬疊層巒接遠空，瑞雲晴靄氣溶溶。',64,'全唐诗/poet.song.24000.json','["萬疊層巒接遠空，瑞雲晴靄氣溶溶。", "高於太華五千仞，秀出巫陽十二峰。", "蕙帳曉寒飛鶴怨，桃源春盡落花穠。", "鸞凰一嘯最深處，仙客樓臺有幾重。"]'),
('96543c0b-3f0f-41df-a938-5860168eeb2a','悼古','陳襄','宋','宋诗','song-poetry','','[]','碧城樓角重凝眸，迤邐平原接古丘。',64,'全唐诗/poet.song.24000.json','["碧城樓角重凝眸，迤邐平原接古丘。", "七國戰爭人不見，六朝興廢水長流。", "遠烟芳草年年事，明月清天夜夜愁。", "范蠡功成在何處，五湖波上一扁舟。"]'),
('cb937da8-851e-451b-8a3e-194c413456c0','春日宴林亭','陳襄','宋','宋诗','song-poetry','','[]','把酒春亭覽衆芳，水精簾箔逗山光。',64,'全唐诗/poet.song.24000.json','["把酒春亭覽衆芳，水精簾箔逗山光。", "孤松冷落千年操，野槿紛華一日香。", "綠圃烟深迷蛺蝶，曲池波暖睡鴛鴦。", "文園莫惜鸘裘費，買取宜城作醉鄉。"]'),
('46e42f80-23e0-4905-8418-834fcdfc7bc2','寄遠','陳襄','宋','宋诗','song-poetry','','[]','飛鵲翩翩暮欲棲，楚天新月射璇題。',64,'全唐诗/poet.song.24000.json','["飛鵲翩翩暮欲棲，楚天新月射璇題。", "袖中已滅三年字，心曲惟通一點犀。", "步障影迷金谷路，桃花香隔武陵溪。", "瑶華好折無人寄，腸斷江樓百尺梯。"]'),
('9d14d1d7-d81d-4032-b66e-d78009fec101','織女','陳襄','宋','宋诗','song-poetry','','[]','明河清淺曙星稀，一夕歡娛一歲違。',64,'全唐诗/poet.song.24000.json','["明河清淺曙星稀，一夕歡娛一歲違。", "不是盈盈隔流水，也應軋軋廢殘機。", "人間累鵲經秋會，天上奔龍逐曉歸。", "期約黄姑重相見，伯勞東翥燕西飛。"]'),
('0b80f7d0-10de-46be-a5c7-de7f885ea59f','寄李惟肖','陳襄','宋','宋诗','song-poetry','','[]','峨峨神嶽吐靈襟，弱冠飛英翰墨林。',64,'全唐诗/poet.song.24000.json','["峨峨神嶽吐靈襟，弱冠飛英翰墨林。", "楚國未登和氏璧，晉人惟重孔家金。", "文高千丈雲霞彩，賦敵三都鼓吹音。", "聖代已招巖穴士，傅生他日定爲霖。"]'),
('3ca95077-6d6a-4087-aaab-9168fdf70102','春日書事','陳襄','宋','宋诗','song-poetry','','[]','三城樓閣半沈烟，雨霽春華鬥逞妍。',64,'全唐诗/poet.song.24000.json','["三城樓閣半沈烟，雨霽春華鬥逞妍。", "萬疊翠茵芳草地，一番輕雪落梅天。", "南園曉色迷蝴蝶，西蜀風光怨杜鵑。", "誰向武陵歸未得，桃花流水路綿綿。"]'),
('203594f4-54cf-4d15-bec8-b3a4a97e3807','夜意','陳襄','宋','宋诗','song-poetry','','[]','薰爐香燼蕙烟沈，凜冽寒生翡翠衾。',64,'全唐诗/poet.song.24000.json','["薰爐香燼蕙烟沈，凜冽寒生翡翠衾。", "月國音塵千里絕，仙山樓閣五雲深。", "離懷暗耿金壺漏，獨夢多驚玉女碪。", "騎省中郎才調逸，擬將文筆賦秋心。"]'),
('63a2a04c-85c4-41b4-b911-3678a240b82b','謁真祠','陳襄','宋','宋诗','song-poetry','','[]','海宮天路杳無涯，萬里星津駐客槎。',64,'全唐诗/poet.song.24000.json','["海宮天路杳無涯，萬里星津駐客槎。", "月下旌旗仙女仗，雲中樓閣羽人家。", "鸞絲緩引霓裳曲，綺席深傾玉酒霞。", "阿母未歸方朔去，碧桃何日重開花。"]'),
('f23b9add-c6fb-4e04-a73e-2dcd3612a362','懷友人陳烈','陳襄','宋','宋诗','song-poetry','','[]','思君苦節直艱難，四十窮經草野間。',64,'全唐诗/poet.song.24000.json','["思君苦節直艱難，四十窮經草野間。", "文爲周衰能力救，禮遭秦禍欲重刪。", "時無正說非楊墨，天與多才繼孔顔。", "吾主聘賢方仄席，好將書幣起東山。"]'),
('dd4fb0a8-330a-4f82-b5c9-a674078091e0','白頭','陳襄','宋','宋诗','song-poetry','','[]','白頭四十未逢知，鍛石裨天已後時。',64,'全唐诗/poet.song.24000.json','["白頭四十未逢知，鍛石裨天已後時。", "正好中行求獨復，豈能上施學顛頤。", "生榮死辱如觀火，吉去凶來莫問龜。", "若有名山歸便隠，一編周易是吾師。"]'),
('45533b59-cee9-42f0-b566-8365aac07666','次韵友人鄭穆病起感懷','陳襄','宋','宋诗','song-poetry','','[]','五老村中會隠時，投梭即是十年期。',64,'全唐诗/poet.song.24000.json','["五老村中會隠時，投梭即是十年期。", "自諳海燕歸巢早，祗恐山桃結實遲。", "伊呂功名何日到，軻揚辭業是人知。", "如君未忍拋簪去，買取青山寄嶺陲。"]'),
('06dfa369-f623-4cef-a736-e3c26e4d446b','和子直聞運使兵部駐節京口寄呈如晦','陳襄','宋','宋诗','song-poetry','','[]','南徐新政煥秋陽，九日登臨喜命觴。',64,'全唐诗/poet.song.24000.json','["南徐新政煥秋陽，九日登臨喜命觴。", "送酒客尋方外士，觀風人是省中郎。", "千家弦管聞謠俗，萬頃湖山入燕堂。", "使節未歸深有意，欲疏涇瀆利吳艎。"]'),
('17d7201f-a478-4c22-931c-a5bbea2422bb','和正辭職方以濬河留滯','陳襄','宋','宋诗','song-poetry','','[]','萬鍤如雲濬禹溝，荀卿橋畔艤行舟。',64,'全唐诗/poet.song.24000.json','["萬鍤如雲濬禹溝，荀卿橋畔艤行舟。", "珠躔合照賢人聚，銀漢無波海客留。", "且作東山携妓樂，未應南浦送君憂。", "辛夷花發春醅熟，只俟郊原雨少休。"]'),
('ef21cb34-e07d-4111-9040-9f053e1d0a8f','依韵和通判徐郎中毗陵重陽','陳襄','宋','宋诗','song-poetry','','[]','自愴宮車別帝臺，寄言籬菊不須開。',64,'全唐诗/poet.song.24000.json','["自愴宮車別帝臺，寄言籬菊不須開。", "心喪忍到行春浦，耳病慵携遲月杯。", "天色陰沈鳴雁過，物華零落暗蛩催。", "却輸小杜憐嘉節，酩酊齊山夜始迴。"]'),
('8bb5bad3-dea5-4ae8-a3a3-16122a99748a','和通判九月望日始見菊花二首  其一','陳襄','宋','宋诗','song-poetry','','[]','月滿霜飛菊始華，幽叢冷落带烟斜。',64,'全唐诗/poet.song.24000.json','["月滿霜飛菊始華，幽叢冷落带烟斜。", "籬邊過却重陽酒，澤畔誰憐野草花。", "湖學先生歸解組，安州司戶老居家。", "皆因晚節無人用，隕涕臨風爲爾嗟。"]'),
('ef275d63-3516-4251-a586-be6173daaea9','和通判九月望日始見菊花二首  其二','陳襄','宋','宋诗','song-poetry','','[]','灼灼秋英綴露華，白衣不見日空斜。',64,'全唐诗/poet.song.24000.json','["灼灼秋英綴露華，白衣不見日空斜。", "細看未減重陽淚，更晚猶勝二月花。", "城裏好山何處寺，門前多竹甚人家。", "直須載酒頻來賞，莫爲衰遲便感嗟。"]'),
('ccb7af91-7be8-4090-9119-03555feb9165','題少述望海樓','陳襄','宋','宋诗','song-poetry','','[]','百尺樓頭水際天，樓東直與海相連。',64,'全唐诗/poet.song.24000.json','["百尺樓頭水際天，樓東直與海相連。", "江山氣古南朝後，風物神清北固前。", "沙鳥晴棲甘露月，布颿時度廣陵烟。", "何年乞得丹陽守，來此登臨養浩然。"]'),
('b815ac70-1829-481a-91f9-a93e97ee3b10','和東玉少卿見遺','陳襄','宋','宋诗','song-poetry','','[]','束芻彌月館行人，白首無殊一面新。',64,'全唐诗/poet.song.24000.json','["束芻彌月館行人，白首無殊一面新。", "朔漠持麾慚未達，東方連騎喜相親。", "卮言坐遣壺中月，物色頻驚塞下春。", "使者不知爲旅意，佳篇猶擬駐征輪。"]'),
('ce01f259-9e4f-4c63-8274-f9cae6468101','和東玉少卿謝春卿防禦新茗','陳襄','宋','宋诗','song-poetry','','[]','嘗陪星使款高牙，三月欣逢試早茶。',64,'全唐诗/poet.song.24000.json','["嘗陪星使款高牙，三月欣逢試早茶。", "綠絹封來溪上印，紫甌浮出社前花。", "休將潔白評雙井，自有清甘薦五華。", "帥府詩翁真好事，春團持作夜光誇。"]'),
('ccf179c0-68ac-442e-9d46-0b8578966bc2','和公序庫部觀孔雀因呈東玉少卿','陳襄','宋','宋诗','song-poetry','','[]','修尾峨冠蜀錦裁，飄流應自玉關來。',64,'全唐诗/poet.song.24000.json','["修尾峨冠蜀錦裁，飄流應自玉關來。", "閒窺水鑒精神出，靜刷金華羽翼開。", "野思未饒鷳灑落，羈栖聊與雁低回。", "不因久在司空館，平日誰憐五客才。"]'),
('faec2911-843c-4b26-991d-7dd34aeaa82a','和東玉少卿後池群雁','陳襄','宋','宋诗','song-poetry','','[]','生意淹留白水塘，樊籠多事豈吾鄉。',64,'全唐诗/poet.song.24000.json','["生意淹留白水塘，樊籠多事豈吾鄉。", "江湖已失秋南望，歲月猶欣塞北凉。", "白日稻粱應飽足，青雲岐路莫思量。", "主人憐爾能鳴久，肯放逍遥物外翔。"]'),
('3e5873d7-2a1e-441e-a5dc-a8c714a08c4d','次韵程少卿暮春','陳襄','宋','宋诗','song-poetry','','[]','纔覺逢春春又還，風光摇蕩客心闌。',64,'全唐诗/poet.song.24000.json','["纔覺逢春春又還，風光摇蕩客心闌。", "宮花不見姚黄蕊，苑茗初嘗葉白團。", "擥照祗驚霜鬢改，尋幽寧放馬蹄乾。", "夜來遍遍韓王宅，猶喜芳菲有百般。"]'),
('93ab0937-a3c9-400c-9712-ae2db08036d8','次韵和程少卿省宿寄齊熙業少卿','陳襄','宋','宋诗','song-poetry','','[]','名卿猶此滯閒曹，賁育何須舉一毫。',64,'全唐诗/poet.song.24000.json','["名卿猶此滯閒曹，賁育何須舉一毫。", "夜直甘泉西掖近，曉趨嶢闕北辰高。", "蒙莊吏隠機心息，老杜詩成筆力豪。", "祗恐多才難久次，不同新進累資勞。"]'),
('a594f5d0-f7b7-4aee-a8bb-21e1433dbd6d','送太君之建昌','陳襄','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','聞說廬山對縣樓，蒲魚聊足奉晨羞。',64,'全唐诗/poet.song.24000.json','["聞說廬山對縣樓，蒲魚聊足奉晨羞。", "寬心便是無聲樂，省事還同不繫舟。", "服藥養真須少病，看經遮眼自忘憂。", "所嗟無計隨親膝，日與兒孫衣綵遊。"]'),
('949c192d-7667-456b-9de9-a174a7405f9b','登雄州南門偶書呈知府張皇城','陳襄','宋','宋诗','song-poetry','','[]','城如銀甕萬兵環，悵望孤城野蓼間。',64,'全唐诗/poet.song.24000.json','["城如銀甕萬兵環，悵望孤城野蓼間。", "池面綠陰通易水，樓頭青靄見狼山。", "漁舟掩映江南浦，使驛差池古北關。", "雅愛六韜名將在，塞垣無事虎貔閒。"]'),
('c8297c06-b3c8-4673-9cf8-8407d0dae9cd','使還咸熙館道中作','陳襄','宋','宋诗','song-poetry','','[]','土曠人稀使驛賒，山中殊不類中華。',64,'全唐诗/poet.song.24000.json','["土曠人稀使驛賒，山中殊不類中華。", "白沙有路鴛鴦泊，芳草無情妯娌花。", "氈館夜燈眠漢節，石梁秋吹動胡笳。", "歸來攬照看顔色，斗覺霜毛兩鬢加。"]'),
('c55ae2db-b7eb-4e49-b737-a42b4640f791','和程公闢大卿遊越山亭','陳襄','宋','宋诗','song-poetry','','[]','荔子園林海日邊，幽亭更在碧雲巔。',64,'全唐诗/poet.song.24000.json','["荔子園林海日邊，幽亭更在碧雲巔。", "江山舊是無諸國，樓殿今爲極樂天。", "五馬如君多暇少，一樽惟我共遊偏。", "須知白首留連意，已有新詩寄北船。"]'),
('dfe911c2-0a5d-4717-9bb7-ad9a51b5a181','春晚賞牡丹奉呈席上諸君','陳襄','宋','宋诗','song-poetry','','[]','逍遥爲吏厭衣冠，花謝還來訪牡丹。',64,'全唐诗/poet.song.24000.json','["逍遥爲吏厭衣冠，花謝還來訪牡丹。", "顔色只留春別後，精神寧似日前看。", "雨餘花萼啼殘粉，風靜奇香噴寶檀。", "祗恐明年開更好，不知誰與并欄干。"]'),
('1bcec39d-4a64-48bd-a212-5b050f27a361','和程公闢遊宿猿洞二首  其一','陳襄','宋','宋诗','song-poetry','','[]','幾年營此草堂棲，施飾名園百卉齊。',64,'全唐诗/poet.song.24000.json','["幾年營此草堂棲，施飾名園百卉齊。", "曾學子真耕谷口，今容摩什老山西。", "龍臺日上千峰出，雁塔雲生一徑迷。", "知有嶺猿猶在否，使君高卧莫教啼。"]'),
('e4016193-9af0-4c2c-8362-df4ab1203aaa','和程公闢遊宿猿洞二首  其二','陳襄','宋','宋诗','song-poetry','','[]','老來歸鞅海邊村，猶喜諸親聚里門。',64,'全唐诗/poet.song.24000.json','["老來歸鞅海邊村，猶喜諸親聚里門。", "漢守朱轓臨祖帳，韓侯清酒滿離樽。", "猿驚出洞時三哭，梅送行人早一番。", "此去蓬萊峰頂月，夢魂應到荔枝園。"]'),
('2efe3457-8daf-471e-8479-594b0a761a18','和程公闢紅梅','陳襄','宋','宋诗','song-poetry','','[]','誰把繁英染絳脂，曉妝紅淡臘前時。',64,'全唐诗/poet.song.24000.json','["誰把繁英染絳脂，曉妝紅淡臘前時。", "栽培上苑無多地，囑付行人第一枝。", "朔雪有情相掩映，東風何事少噓吹。", "莫嫌冷落天涯遠，他日和羹氣味移。"]'),
('fe9a139f-3dc0-410b-a117-5a3a604c3cc9','席上探得隨字送曼叔密學赴太原','陳襄','宋','宋诗','song-poetry','','[]','帝念唐風古未衰，便蕃恩寵命中師。',64,'全唐诗/poet.song.24000.json','["帝念唐風古未衰，便蕃恩寵命中師。", "暫驅太守朱幡去，應有兒童竹馬期。", "塞外烟雲千里靜，帳前貔虎萬兵隨。", "誰憐白髪詩書帥，曾見昭陵坐論時。"]'),
('bd1ca78a-aab4-48db-bf62-b2d0236c8d4c','送彥祖學士赴兖州','陳襄','宋','宋诗','song-poetry','','[]','暫辭天祿請名藩，養志安貧道可尊。',64,'全唐诗/poet.song.24000.json','["暫辭天祿請名藩，養志安貧道可尊。", "南國士歌陽羨政，東州人識翰林孫。", "重興闕里諸生學，好薦徂徠一子恩。", "平日皂囊應草疏，由來忠讜出家門。"]'),
('ae587811-678a-4357-b36d-bc1113e40e5a','和御製賞花釣魚','陳襄','宋','宋诗','song-poetry','','[]','仙蹕傳呼禁苑開，兩班迎拜玉輿來。',64,'全唐诗/poet.song.24000.json','["仙蹕傳呼禁苑開，兩班迎拜玉輿來。", "花圍帝座重張幄，鱗上天鈎曲賜杯。", "鳥散香叢聲睍睆，人觀靈沼樂徘徊。", "君恩更錫回鸞藻，還許儒生給筆陪。"]'),
('91140728-7c9d-4a1d-94d0-2533f9ee4ba3','重陽閣下和同舍','陳襄','宋','宋诗','song-poetry','','[]','君逢佳節憶還家，我亦淹留感歲華。',64,'全唐诗/poet.song.24000.json','["君逢佳節憶還家，我亦淹留感歲華。", "清禁讎書驚白髪，故園吹帽負黄花。", "謝安行有登山屐，揚子居無載酒車。", "何日得歸溪上隠，大收圖史作生涯。"]'),
('c1b8f1d6-4f49-4544-a2c3-a265aea9c561','寒食日常州宴春園','陳襄','宋','宋诗','song-poetry','','[]','曲池收雨靜無塵，結客留連半月春。',64,'全唐诗/poet.song.24000.json','["曲池收雨靜無塵，結客留連半月春。", "洞裏桃花青葉嫩，牆頭杏火綠烟新。", "風光冉冉非前日，物色依依似故人。", "官滿又歸延閣去，忍將詩酒負佳辰。"]'),
('6e32c273-f7eb-4e17-ba62-15876a75265e','依韵和解空長老雪頌','陳襄','宋','宋诗','song-poetry','','[]','片片分明是六花，迷人只見亂如麻。',64,'全唐诗/poet.song.24000.json','["片片分明是六花，迷人只見亂如麻。", "窮閻處士愁穿屐，明眼高僧笑點茶。", "十二玉樓開閬苑，三千銀界遍河沙。", "解空老子能提唱，郢曲幽蘭未足誇。"]'),
('e175c06b-1154-4fb2-a1e2-eddca86487c5','和程大卿遊昇山','陳襄','宋','宋诗','song-poetry','','[]','相逢不及荔枝期，况值千巖雪灑時。',64,'全唐诗/poet.song.24000.json','["相逢不及荔枝期，况值千巖雪灑時。", "南國小棠偏去近，北山逋客獨來遲。", "雲中直有三清路，塵外都如一局棋。", "聞欲引泉添洗藥，未應奪我鳳凰池。"]'),
('5348eb81-4bdb-4ff2-9099-fa20fbb2981a','送鍾離郎中知婺州','陳襄','宋','宋诗','song-poetry','','[]','皓首潘郎少似君，一麾新得浙江濆。',64,'全唐诗/poet.song.24000.json','["皓首潘郎少似君，一麾新得浙江濆。", "神仙窟宅金華近，吳越封疆寶婺分。", "沈約瘦來題八咏，張顛醉後掃千文。", "才高政美應無事，莫厭雙溪卧白雲。"]'),
('b20efd89-5f93-4460-94e5-b5be36670b64','和程大卿遊鳳池院','陳襄','宋','宋诗','song-poetry','','[]','白雲深處一軒開，鳳去池空折野梅。',64,'全唐诗/poet.song.24000.json','["白雲深處一軒開，鳳去池空折野梅。", "山接九龍爭夭矯，路盤千騎久徘徊。", "烟嵐翠入樽前滴，水石深從澗底來。", "誰與忘機此棲息，笑看林鳥下生臺。"]'),
('5e10bac7-3659-4eb4-9aeb-fb048a3305bd','題蒲傳正舍人清風閣','陳襄','宋','宋诗','song-poetry','','[]','清白傳芳奕世居，閬峰華閣峻凌虛。',64,'全唐诗/poet.song.24000.json','["清白傳芳奕世居，閬峰華閣峻凌虛。", "千金不買連城璧，萬卷惟存舊宅書。", "魯邑弦歌興國俗，謝家蘭玉滿庭除。", "今朝已覺孫謀遠，人在西垣直禁廬。"]'),
('3596ebeb-4d01-4698-8ca2-969cc02d5924','觀太原丞相寄惠紫霞園庵新居詩和太素先生','陳襄','宋','宋诗','song-poetry','','[]','翠竹庵前白藕池，修真常惜寸陰移。',64,'全唐诗/poet.song.24000.json','["翠竹庵前白藕池，修真常惜寸陰移。", "別生五氣根原固，妙樂三清出處宜。", "黄閣主人思訪道，絳紗弟子許觀頤。", "興來即到維摩室，豈待留侯脫屣時。"]'),
('fd852b76-6f41-4240-8d9d-78b677678adf','東園觀雪','陳襄','宋','宋诗','song-poetry','','[]','風毛雨絮小園東，天幕低垂慘澹空。',64,'全唐诗/poet.song.24000.json','["風毛雨絮小園東，天幕低垂慘澹空。", "蘋浦萬家雲覆瓦，花蹊千樹玉雕籠。", "穿林已奪春梅早，夾隴潛滋夏麥豐。", "湘酎狐衣雖可賦，豈無捐瘠在溝中。"]'),
('2a4d6a3d-6855-4c02-abde-d8fd7e723d6e','留題天遊閣','陳襄','宋','宋诗','song-poetry','','[]','誰榜天遊向此軒，欲令幽隠味真篇。',64,'全唐诗/poet.song.24000.json','["誰榜天遊向此軒，欲令幽隠味真篇。", "一心泯絕渾無計，萬事攖寧付自然。", "持鉢隨緣朝乞供，閉門扣寂夜安禪。", "如師早契南華旨，即是逍遥物外仙。"]'),
('c3418376-c6b1-4aaa-9436-a31373cec672','次韵李學士勾院海棠','陳襄','宋','宋诗','song-poetry','','[]','幽芳寧貴俗人知，北省仙郎只自奇。',64,'全唐诗/poet.song.24000.json','["幽芳寧貴俗人知，北省仙郎只自奇。", "顔色定應西蜀品，馨香不減上林枝。", "胭脂著雨深紅日，葆髪臨風半白時。", "幾欲相從花下飲，許昌詞藻愧難追。"]'),
('52f03591-7c62-4281-9ffe-495a593be3b1','寄題福唐林迥南華洞','陳襄','宋','宋诗','song-poetry','','[]','梅嶺峰前習隠亭，拂衣聊此玩真經。',64,'全唐诗/poet.song.24000.json','["梅嶺峰前習隠亭，拂衣聊此玩真經。", "四時花木錦繡谷，十里江山水墨屏。", "猿鶴只愁空北嶽，鵾鵬終待化南溟。", "知君不是榮軒冕，未忍鏘鏘去帝庭。"]'),
('9f40a2d3-9145-4630-a4a7-1e035645e616','古城','陳襄','宋','宋诗','song-poetry','','[]','蘆葦蕭疏天氣清，水含山色照重城。',64,'全唐诗/poet.song.24000.json','["蘆葦蕭疏天氣清，水含山色照重城。", "綠蕪何處管弦地，碧落舊時鐘鼓聲。", "三峽橋邊秋雨過，六鼇宮裏夜潮生。", "蕭郎秦女無歸約，十二瑶臺空月明。"]'),
('ff21892e-8c8a-453b-96d1-96726d224fa1','和咏鶴','陳襄','宋','宋诗','song-poetry','','[]','耻與籠禽飫稻泉，滿懷霜雪獨蕭然。',64,'全唐诗/poet.song.24000.json','["耻與籠禽飫稻泉，滿懷霜雪獨蕭然。", "千年華表曾留語，萬里青雲此息肩。", "養性最宜棲露苑，引吭時得唳晴天。", "神仙骨法人難相，除向瑶臺玉簡編。"]'),
('e8eaae56-bfe6-4a70-b010-75232c545d8a','慈聖光獻太皇后挽詞二首  其一','陳襄','宋','宋诗','song-poetry','','[]','天開華德嗣音徽，嘗擁真人御殿闈。',64,'全唐诗/poet.song.24000.json','["天開華德嗣音徽，嘗擁真人御殿闈。", "萬國母儀坤積載，兩朝聖嗣日光輝。", "羞籩忽棄參差荇，寶匣空餘澣濯衣。", "從此昭陵原上路，又添遺老泣皇妃。"]'),
('5f7a438c-9d28-439c-a523-2604f8a8ca78','慈聖光獻太皇后挽詞二首  其二','陳襄','宋','宋诗','song-poetry','','[]','慶壽蟠桃曉霧昏，忽聞笳鼓咽都門。',64,'全唐诗/poet.song.24000.json','["慶壽蟠桃曉霧昏，忽聞笳鼓咽都門。", "宮闈有範遺文母，社稷無憂付聖孫。", "四海心喪同祖妣，一封手詔易陵園。", "君王孝感凌穹昊，未盡東朝欲報恩。"]'),
('b58dd01e-cb0e-46d6-84e0-4251482d69cb','監簿楊倜得第南歸惠詩因和元韵贈其行','陳襄','宋','宋诗','song-poetry','','[]','楚客多年澤畔吟，文窮尤見用功深。',64,'全唐诗/poet.song.24000.json','["楚客多年澤畔吟，文窮尤見用功深。", "尺書屢貢賓王府，斗粟寧酬事道心。", "長鋏由來歌舊館，鳴騶從此別中林。", "寄言鄉校青衿子，君去何人更嗣音。"]'),
('0b56fd9e-ffa7-4fbb-ae59-6c89950aa6e5','和蘇子瞻通判在告中聞余出郊以詩見寄','陳襄','宋','宋诗','song-poetry','','[]','郊原綠意動遊人，湖上晴波見躍鱗。',64,'全唐诗/poet.song.24000.json','["郊原綠意動遊人，湖上晴波見躍鱗。", "閒逐牙旗千騎遠，暗驚梅萼萬枝新。", "尋僧每拂題詩壁，邀客仍將濾酒巾。", "寄語文園何所苦，且來相伴一行春。"]'),
('d1446af5-50a3-44e1-a26a-0d4d1f5c61ee','和子瞻沿牒京口憶西湖寒食出遊見寄二首  其一','陳襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','乞得湖山養病身，花時曾共憶行春。',64,'全唐诗/poet.song.24000.json','["乞得湖山養病身，花時曾共憶行春。", "嚶鳴幽鳥還遷木，觱沸清泉復采芹。", "皂蓋尋芳丘有李，綵樓觀戲巷無人。", "錦袍公子歸何晚，獨念溝中菜色民。"]'),
('1b9d0a8a-5f53-4621-9d0e-8bab3f8ab02c','和子瞻沿牒京口憶西湖寒食出遊見寄二首  其二','陳襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春陰漠漠燕飛飛，可惜春光與子違。',64,'全唐诗/poet.song.24000.json','["春陰漠漠燕飛飛，可惜春光與子違。", "半嶺烟霞紅旆入，滿湖風月畫船歸。", "緱笙一闋人何在，遼鶴重來事已非。", "猶憶去年題別處，鳥啼花落客霑衣。"]'),
('c401f7d6-054c-4116-896e-d0788349b9da','和子瞻沿牒京口憶吉祥牡丹見寄','陳襄','宋','宋诗','song-poetry','','[]','新接枝頭色倍添，馬蹄尋處帽欹檐。',64,'全唐诗/poet.song.24000.json','["新接枝頭色倍添，馬蹄尋處帽欹檐。", "春工別與鉛華麗，佛地偏資好相嚴。", "紅蕊欲開丹未渥，素香堪茹雪非甜。", "詩翁何事辜真賞，不許浮根浪發黏。"]'),
('bc4b26e8-befd-410d-bb45-3d3a07322579','過江外感懷','陳襄','宋','宋诗','song-poetry','','[]','江水無情含野烟，江風還似舊時天。',32,'全唐诗/poet.song.24000.json','["江水無情含野烟，江風還似舊時天。", "先生隠去思成死，今日重來十六年。"]'),
('9b568191-1f50-429d-9e33-1016b574a829','常州郡齋六首  其一','陳襄','宋','宋诗','song-poetry','','[]','近來無事學攖寧，聊得齋居養性靈。',32,'全唐诗/poet.song.24000.json','["近來無事學攖寧，聊得齋居養性靈。", "卧著麻衣穿草履，誰知參魯解忘形。"]'),
('3b903faf-6d36-44c9-b697-8fa3236fc04b','常州郡齋六首  其二','陳襄','宋','宋诗','song-poetry','','[]','山亭側畔構山房，便是耕雲釣月鄉。',32,'全唐诗/poet.song.24000.json','["山亭側畔構山房，便是耕雲釣月鄉。", "未達功名窮飲水，此生應不誤行藏。"]'),
('bc7009ac-f78d-42c2-9113-3a9fe1c3f888','常州郡齋六首  其三','陳襄','宋','宋诗','song-poetry','','[]','桐花著地雪成痕，時有幽禽巧語言。',32,'全唐诗/poet.song.24000.json','["桐花著地雪成痕，時有幽禽巧語言。", "應笑使君林野性，日依山水避塵喧。"]'),
('588ef8e6-c9d5-413a-9539-8f2580c56ab9','常州郡齋六首  其四','陳襄','宋','宋诗','song-poetry','','[]','使君非是愛山閒，道在盈虛消息間。',32,'全唐诗/poet.song.24000.json','["使君非是愛山閒，道在盈虛消息間。", "不見白雲無一事，等閒爲雨却歸山。"]'),
('51773021-9ef9-4018-adc8-9d11e770d9d0','常州郡齋六首  其五','陳襄','宋','宋诗','song-poetry','','[]','荀令當年此謫居，空文惟有七篇餘。',32,'全唐诗/poet.song.24000.json','["荀令當年此謫居，空文惟有七篇餘。", "我今亦作蘭陵守，不忍援毫便著書。"]'),
('48237e87-9d12-43c0-9519-c5701512059a','常州郡齋六首  其六','陳襄','宋','宋诗','song-poetry','','[]','一麾來此下巖丘，也學東山謝傅遊。',32,'全唐诗/poet.song.24000.json','["一麾來此下巖丘，也學東山謝傅遊。", "今日鳥聲併水色，不知何似五亭幽。"]'),
('06ad5cf2-6408-4e05-80b1-1809aa9f3524','遊善權洞二首  其一','陳襄','宋','宋诗','song-poetry','','[]','陰陽融結此山川，便有鹽堆與石田。',32,'全唐诗/poet.song.24000.json','["陰陽融結此山川，便有鹽堆與石田。", "風俗每來占水旱，即疑乾洞有神仙。"]'),
('6e25cbeb-3724-410a-8d69-525971f4e6ba','遊善權洞二首  其二','陳襄','宋','宋诗','song-poetry','','[]','水洞深無百尺泉，白龍奮蟄已多年。',32,'全唐诗/poet.song.24000.json','["水洞深無百尺泉，白龍奮蟄已多年。", "誰知此物能雲雨，常濟山南萬頃田。"]'),
('2540d184-4b18-4351-998a-3487fbb22689','題張渚道中','陳襄','宋','宋诗','song-poetry','','[]','班春無術勸汙萊，五十年間此一回。',32,'全唐诗/poet.song.24000.json','["班春無術勸汙萊，五十年間此一回。", "黄髪路傍應怪問，使君何事入山來。"]'),
('cebb02bd-7dc9-4658-85b1-4d213157e324','和如晦二首  其一','陳襄','宋','宋诗','song-poetry','','[]','俱爲澤國朱轓守，同是冰廳白首郎。',32,'全唐诗/poet.song.24000.json','["俱爲澤國朱轓守，同是冰廳白首郎。", "且喜朝廷憂外寄，故從書府輟班揚。"]'),
('5d41ef3d-a095-490e-8023-4a1d3851e339','和如晦二首  其二','陳襄','宋','宋诗','song-poetry','','[]','一別瀛山歲未期，三州聲稱已齊飛。',32,'全唐诗/poet.song.24000.json','["一別瀛山歲未期，三州聲稱已齊飛。", "欲將吏事文經術，獨恐迂儒取世譏。"]'),
('39270409-797c-479a-85cb-36663e834a02','簡子直','陳襄','宋','宋诗','song-poetry','','[]','吳郡三年困水災，昔時從事建麾來。',32,'全唐诗/poet.song.24000.json','["吳郡三年困水災，昔時從事建麾來。", "遥知到後疏遊燕，不比蘇韋放酒杯。"]'),
('bffbf437-a224-4f44-b96c-20280acc44fa','簡如晦','陳襄','宋','宋诗','song-poetry','','[]','登閣始聞公府薦，出轓俄擁使旌隨。',32,'全唐诗/poet.song.24000.json','["登閣始聞公府薦，出轓俄擁使旌隨。", "無人不說南徐守，儒雅風流獨一時。"]'),
('53cb798e-a98e-4414-a171-5c1d1f246e19','簡子容','陳襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','同館分飛來右浙，一麾瀟灑出南河。',32,'全唐诗/poet.song.24000.json','["同館分飛來右浙，一麾瀟灑出南河。", "琴書滿榻王常在，不獨西湖勝賞多。"]'),
('3eea9d3e-545b-42ad-bcbb-73dd523eb9ec','和如晦桃杏','陳襄','宋','宋诗','song-poetry','','[]','一色胚紅染露柯，誰栽安石舊巖阿。',32,'全唐诗/poet.song.24000.json','["一色胚紅染露柯，誰栽安石舊巖阿。", "自嗟老大無心賞，不及流鶑管顧多。"]'),
('7c0900b4-fa4c-4702-80d9-892d2216bfb5','和桃花因戲如晦','陳襄','宋','宋诗','song-poetry','','[]','顔色已饒丹杏蕊，馨香不減雪梅疏。',32,'全唐诗/poet.song.24000.json','["顔色已饒丹杏蕊，馨香不減雪梅疏。", "自從移入青陽觀，前度劉郎記得無。"]'),
('86791f7c-b7e7-4c0e-86e5-68f5d5625ffe','過罨畫溪','陳襄','宋','宋诗','song-poetry','','[]','五雲無處問新亭，月裏乘舟夜半行。',32,'全唐诗/poet.song.24000.json','["五雲無處問新亭，月裏乘舟夜半行。", "不見藤花相掩映，鄉人遥指畫溪名。"]'),
('05bfa4f4-23fe-4263-bb66-61cbcb2e09e2','和程大卿荔枝','陳襄','宋','宋诗','song-poetry','','[]','棠陰爲政有光晶，號令風行鬼亦驚。',32,'全唐诗/poet.song.24000.json','["棠陰爲政有光晶，號令風行鬼亦驚。", "和氣發來藏不得，直教丹荔背時生。"]'),
('8f9d2ea1-aa8d-40a3-a095-b3c975e83eef','余自白陽馳謁宜都周夢得長官飲于清江亭愛其山水之勝留題','陳襄','宋','宋诗','song-poetry','','[]','丹山西去水東流，亭在山南隔蓼洲。',32,'全唐诗/poet.song.24000.json','["丹山西去水東流，亭在山南隔蓼洲。", "船繫白楊歸不得，清江如畫主人留。"]'),
('ebdbccae-d98d-4ed4-a70f-b25926af3f61','和程大卿新闢諸寺門','陳襄','宋','宋诗','song-poetry','','[]','政絕多門寺却通，靈山勝境盡牢籠。',32,'全唐诗/poet.song.24000.json','["政絕多門寺却通，靈山勝境盡牢籠。", "應憐去魯遲遲意，令遍諸天國土中。"]'),
('28806162-e5a4-46d9-acdd-29b5638a653d','和張運使題長樂臺','陳襄','宋','宋诗','song-poetry','','[]','雲暗騶鳴出谷時，一方生齒庇餘輝。',32,'全唐诗/poet.song.24000.json','["雲暗騶鳴出谷時，一方生齒庇餘輝。", "知君才業非張翰，莫爲鱸魚有意歸。"]'),
('59b0b816-18f0-495e-9d61-8d32f1f672d0','程大卿書宿猿洞','陳襄','宋','宋诗','song-poetry','','[]','聞說山光是舊山，衣冠家此百年間。',32,'全唐诗/poet.song.24000.json','["聞說山光是舊山，衣冠家此百年間。", "自嗟亦有同來祖，兩處松楸得往還。"]'),
('637ef448-31a6-468f-a0b3-7917d69c420f','和定慧超勝長老寄謝紫衣頌三首  其一','陳襄','宋','宋诗','song-poetry','','[]','恩袍出挂壯禪扉，試問何人達此機。',32,'全唐诗/poet.song.24000.json','["恩袍出挂壯禪扉，試問何人達此機。", "船子夜來親下釣，碧潭明月有餘輝。"]'),
('300b2f04-e85a-419d-810e-be05d4804573','和定慧超勝長老寄謝紫衣頌三首  其二','陳襄','宋','宋诗','song-poetry','','[]','童子南來遺我詩，維摩方丈一伸眉。',32,'全唐诗/poet.song.24000.json','["童子南來遺我詩，維摩方丈一伸眉。", "不勞言語通消息，夏熱春寒各自知。"]'),
('3b2e92aa-dc9e-4eb0-bee2-29b2208ad089','和定慧超勝長老寄謝紫衣頌三首  其三','陳襄','宋','宋诗','song-poetry','','[]','得道無求幻與真，一筇一衲似閒雲。',32,'全唐诗/poet.song.24000.json','["得道無求幻與真，一筇一衲似閒雲。", "忽聞師唱報恩曲，百草千花特地春。"]'),
('94e7e2c5-4c6b-49f1-8ba7-225072d9d03b','偶書','陳襄','宋','宋诗','song-poetry','','[]','朝居晦息與山鄰，物理由來有屈伸。',32,'全唐诗/poet.song.24000.json','["朝居晦息與山鄰，物理由來有屈伸。", "獨把一心經萬事，逍遥須養谷中神。"]'),
('e0e369ea-0542-49af-aa48-5f495f19a680','題毗陵郡圖','陳襄','宋','宋诗','song-poetry','','[]','平湖千里接荆溪，萬頃良田不可堤。',32,'全唐诗/poet.song.24000.json','["平湖千里接荆溪，萬頃良田不可堤。", "我欲决渠疏積水，干塘江口地形低。"]'),
('57cd6cf4-1f70-461c-98c4-0ab0d5cfaa30','熙寧七年八月望日自杭之宋過永樂院觀承天佛日廣慧洎永樂四老上堂因而留題','陳襄','宋','宋诗','song-poetry','','[]','雷音一振絕微言，末學方知祖道尊。',32,'全唐诗/poet.song.24000.json','["雷音一振絕微言，末學方知祖道尊。", "莫訝師僧無見處，人人俱解句中玄。"]'),
('36759d19-90d7-45c6-95fc-70e83e34926e','和宛丘長官賞花','陳襄','宋','宋诗','song-poetry','','[]','遺我新詩雅興長，一時花譜爲傳芳。',32,'全唐诗/poet.song.24000.json','["遺我新詩雅興長，一時花譜爲傳芳。", "不須滿縣栽桃李，却羨風流騎省郎。"]'),
('bc14845c-e2b6-41ab-8daf-e5f2ca7800e0','潁川賞花二首  其一','陳襄','宋','宋诗','song-poetry','','[]','閒入郊園駐隼旟，百花紅紫萬千株。',32,'全唐诗/poet.song.24000.json','["閒入郊園駐隼旟，百花紅紫萬千株。", "如何春意多風雨，不惜漫天錦繡鋪。"]'),
('ee9721b5-9475-4440-a73c-644d571d033d','潁川賞花二首  其二','陳襄','宋','宋诗','song-poetry','','[]','千騎重來此建旟，新年花發舊年株。',32,'全唐诗/poet.song.24000.json','["千騎重來此建旟，新年花發舊年株。", "東皇應是憐孤宦，十里全歸錦帳鋪。"]'),
('c32bb2f3-c372-4ec2-83bf-39c4f7776e72','贈禪者','陳襄','宋','宋诗','song-poetry','','[]','昔年曾到此山中，正見山花滿砌紅。',32,'全唐诗/poet.song.24000.json','["昔年曾到此山中，正見山花滿砌紅。", "今日花開還照眼，分明見處本來同。"]'),
('cfb0f327-a958-4400-a538-cc33d326c98d','携家遊東園','陳襄','宋','宋诗','song-poetry','','[]','紅塔寺前千頃稻，青山門外百家村。',32,'全唐诗/poet.song.24000.json','["紅塔寺前千頃稻，青山門外百家村。", "年豐米賤無公事，不惜時來倒一樽。"]'),
('020c22e6-e47d-46b4-9fd4-94c34d626da0','贈鷺鷥','陳襄','宋','宋诗','song-poetry','','[]','兩個鷺鷥相對立，江邊無物蓼花疏。',32,'全唐诗/poet.song.24000.json','["兩個鷺鷥相對立，江邊無物蓼花疏。", "知君潔白如霜雪，何必臨川更羨魚。"]'),
('dd3040cd-10f1-4db4-a627-2ee94632fec3','寄戲劉道淵','陳襄','宋','宋诗','song-poetry','','[]','陸羽茶亭枕水隈，爲言無酒且徘徊。',32,'全唐诗/poet.song.24000.json','["陸羽茶亭枕水隈，爲言無酒且徘徊。", "山中此物尤難得，應是劉生不肯來。"]'),
('832b8674-41eb-41a1-b5fc-06519373c25b','題杭州寶巖寺垂雲亭','陳襄','宋','宋诗','song-poetry','','[]','小亭巉絕出雲間，萬象升沉不得閒。',32,'全唐诗/poet.song.24000.json','["小亭巉絕出雲間，萬象升沉不得閒。", "莫怪詩翁頭白早，時來向此寫湖山。"]'),
('b00ce483-cd02-4306-a66c-b29d321213dd','寄興教凈慈二長老','陳襄','宋','宋诗','song-poetry','','[]','老來爲郡苦間關，不及江雲自往還。',32,'全唐诗/poet.song.24000.json','["老來爲郡苦間關，不及江雲自往還。", "忽憶湖邊二禪老，等閒騎馬入南山。"]'),
('174f403a-4b9b-4e1b-a1de-1eb90d235d9d','題仙居偉羌山六絕  其一','陳襄','宋','宋诗','song-poetry','','[]','去年曾擥偉羌圖，云有仙人古篆書。',32,'全唐诗/poet.song.24000.json','["去年曾擥偉羌圖，云有仙人古篆書。", "千尺石巖無路到，不知科斗字何如。"]'),
('4cd0a76d-75c5-49f8-a2a0-25e92d430b0c','題仙居偉羌山六絕  其二','陳襄','宋','宋诗','song-poetry','','[]','盤盤英氣四紆餘，定有仙人此地居。',32,'全唐诗/poet.song.24000.json','["盤盤英氣四紆餘，定有仙人此地居。", "天子正求伊與呂，如何不見起耕漁。"]'),
('d5cacd80-9ef2-4902-8a79-9483c24fc7ae','題仙居偉羌山六絕  其三','陳襄','宋','宋诗','song-poetry','','[]','天鞠精靈久貯儲，中間豪杰出無虛。',32,'全唐诗/poet.song.24000.json','["天鞠精靈久貯儲，中間豪杰出無虛。", "鄉民世世家於此，爭使兒孫不讀書。"]'),
('3ac7eb97-7e49-4961-8766-d7fc00a12035','題仙居偉羌山六絕  其四','陳襄','宋','宋诗','song-poetry','','[]','峭壁回環幾百區，其間巖石可耕鋤。',32,'全唐诗/poet.song.24000.json','["峭壁回環幾百區，其間巖石可耕鋤。", "如何得片山如此，白首相將老母居。"]'),
('f5148b04-33b2-4342-b671-69cbc59efe22','題仙居偉羌山六絕  其五','陳襄','宋','宋诗','song-poetry','','[]','古意巑岏與世疏，一官羈絆可歸歟。',32,'全唐诗/poet.song.24000.json','["古意巑岏與世疏，一官羈絆可歸歟。", "此山未及西山好，下有仙人結草廬。"]'),
('5753d7ab-b1e9-43b4-8bca-7799ce3cbe0e','題仙居偉羌山六絕  其六','陳襄','宋','宋诗','song-poetry','','[]','四友之賢世莫如，白頭須作一鄉居。',32,'全唐诗/poet.song.24000.json','["四友之賢世莫如，白頭須作一鄉居。", "此山不惜將錢買，嘆息無人共結廬。"]'),
('82d8eadb-6495-4444-b440-39635f2d5d1d','中和堂木芙蓉盛開戲呈子瞻','陳襄','宋','宋诗','song-poetry','','[]','千林寒葉正疏黄，占得珍叢第一芳。',32,'全唐诗/poet.song.24000.json','["千林寒葉正疏黄，占得珍叢第一芳。", "容易便開三百朵，此心應不畏秋霜。"]'),
('fc6ac32d-756a-478d-acea-55c6f7a6fd9b','次韵柯弟太博見示超化牡丹  其一','陳襄','宋','宋诗','song-poetry','','[]','百草蕭條病朔風，雙枝成染魏家紅。',32,'全唐诗/poet.song.24000.json','["百草蕭條病朔風，雙枝成染魏家紅。", "直疑天與凌霜色，不假東皇運化工。"]'),
('c99bfa91-5fbc-46a6-85e6-f36d49ce3bd0','次韵柯弟太博見示超化牡丹  其二','陳襄','宋','宋诗','song-poetry','','[]','一朵鞓紅折寺園，忽驚寒律動春暄。',32,'全唐诗/poet.song.24000.json','["一朵鞓紅折寺園，忽驚寒律動春暄。", "非關花好難栽接，自是天時變木根。"]'),
('18886c68-8429-41a1-85ed-cf152bc349aa','馬篠潭報雨','陳襄','宋','宋诗','song-poetry','','[]','皇祐歲庚寅，陰陽久鬰堙。',240,'全唐诗/poet.song.24000.json','["皇祐歲庚寅，陰陽久鬰堙。", "二時愆雨澤，百物憫膏屯。", "穀價方翔踴，民言備苦辛。", "原疇無播種，道路有饑貧。", "縣令憂忘食，齋房退省身。", "朝歸占甲子，暮出看星辰。", "野祀曾徼福，雩壇示禮神。", "祈求觀古法，詢訪得龍津。", "遣吏蘋蘩潔，齋書肺腑陳。", "靈泉汲坎𦥨，仙仗下嶙峋。", "雷斧潛嗔樹，天波忽灑塵。", "音官沈鼓吹，市戶濕衣巾。", "隆應聲何速，盤旋志未伸。", "經綸惟四日，滂沛即逾旬。", "萬谷山源發，三農水利均。", "趨田多耒耨，入里少芻薪。", "苗稼晨爭插，坊庸夜不巡。", "謳謠興父老，燕喜集賓親。", "捐瘠蘇中壑，生成賦大鈞。", "邑人勿忘報，世世荷深仁。"]'),
('271c0c72-69a9-4c10-adf1-8f59cd627b26','李侍郎修路','陳襄','宋','宋诗','song-poetry','','[]','路餘百里兩山間，水驛山程總不安。',64,'全唐诗/poet.song.24000.json','["路餘百里兩山間，水驛山程總不安。", "誰把千金平滑磴，免教一葉委驚灘。", "行人感嘆何時已，賢守功名百世看。", "次第吾閩都似掌，却嗤蜀道號泥盤。"]'),
('4a2e33c0-b717-4afb-83d3-fb4850eb593c','冬至日獨遊吉祥寺  其一','陳襄','宋','宋诗','song-poetry','','[]','井底微陽回未回，蕭蕭寒雨濕枯荄。',32,'全唐诗/poet.song.24000.json','["井底微陽回未回，蕭蕭寒雨濕枯荄。", "何人更似蘇夫子，不是花時肯獨來。"]'),
('f179a8c1-90d8-4fa7-8c98-5d7cbc4699f7','冬至日獨遊吉祥寺  其二','陳襄','宋','宋诗','song-poetry','','[]','東君意淺著寒梅，十朵深紅未暇裁。',32,'全唐诗/poet.song.24000.json','["東君意淺著寒梅，十朵深紅未暇裁。", "安得道人殷七七，不論時節遣花開。"]'),
('8909e594-0939-4fab-839c-f044e0558fc2','冬至日獨遊吉祥寺  其三','陳襄','宋','宋诗','song-poetry','','[]','過眼榮枯電與風，久長那得似花紅。',32,'全唐诗/poet.song.24000.json','["過眼榮枯電與風，久長那得似花紅。", "上人宴座觀空閣，觀色觀空色即空。"]'),
('8512c481-35d5-47bd-a8e6-65bceb092703','句  其一','陳襄','宋','宋诗','song-poetry','','[]','西風斜日鱸魚香。',8,'全唐诗/poet.song.24000.json','["西風斜日鱸魚香。"]'),
('d87f650d-96c8-45ae-ba88-d8cc61f2c762','句  其二','陳襄','宋','宋诗','song-poetry','','[]','世有斯文屬孔顔。',8,'全唐诗/poet.song.24000.json','["世有斯文屬孔顔。"]'),
('61ff2a0a-c884-4d8d-bf79-06e8cac098f5','答范景仁嘆花花在相國寺近舞場','韓維','宋','宋诗','song-poetry','','[]','佛宮金碧開朝霞，遊人雜遝來正譁。',144,'全唐诗/poet.song.24000.json','["佛宮金碧開朝霞，遊人雜遝來正譁。", "危弦促管競繁咽，羅袖對舞春風斜。", "子時投閒一往步，正見綠樹團丹花。", "舉頭驚看不忍去，却視姝子猶泥沙。", "稍開欲謝各自好，似爲悅己爲容華。", "歸來想像入秀句，刻綴玉佩鏘珩牙。", "尚嫌獨賞不盡意，邀我共賦雄其誇。", "欲將奇警謝妍麗，力竭未有錙銖加。", "急須取酒趁殘艷，猶勝落盡乾咨嗟。"]'),
('04f08a9d-046b-4abc-b042-412747777091','觀龍和謝師厚','韓維','宋','宋诗','song-poetry','','[]','龍於經傳皆有云，明幽其德能屈伸。',128,'全唐诗/poet.song.24000.json','["龍於經傳皆有云，明幽其德能屈伸。", "嘗聞於耳昧厥真，乃今睹之信所聞。", "層陰填空白日昏，仰見巨尾垂輪囷。", "其長百丈圍車輪，彷彿如辨鬣與鱗。", "腥風蕭颯來逼人，觀者駭伏褫魄魂。", "須臾摇動卷縮雲，雲氣斷岸隨飛奔。", "驚雷下震萬瓦裂，暴雨一瀉群河翻。", "霆收無迹雨在物，吁龍出處何其神。"]'),
('1aeb2311-a5fc-4585-8203-5d9a2a3d5fa2','講武池和師厚','韓維','宋','宋诗','song-poetry','','[]','滄池擬溟渤，莽漾豁厚地。',180,'全唐诗/poet.song.24000.json','["滄池擬溟渤，莽漾豁厚地。", "曰吾神祖爲，氣象固宜爾。", "六合昔未一，教戰出精銳。", "至尊降黄屋，慘淡乘金氣。", "凌波飛百艘，撇烈若鶻翅。", "揚旌萬旅噪，伐鼓九淵沸。", "其行速天旋，其止甚陰閉。", "信乎王者師，足以服睽異。", "爾來承平久，地與兵革廢。", "秋風長蒲葦，爛漫失洲沚。", "惟見金明上，結構銷繡綺。", "春遊駐天蹕，萬國奉燕喜。", "鏗鍧鼓鐘響，雜遝羽旄美。", "豈惟與民樂，施及魚鳥細。", "宏哉艱難業，愉懌逮萬世。"]'),
('e9d31971-39ee-460c-80e1-89cd1d55734e','答蘇子美見寄','韓維','宋','宋诗','song-poetry','','[]','暮春遊京洛，適與夫子遘。',240,'全唐诗/poet.song.24000.json','["暮春遊京洛，適與夫子遘。", "衣焦未及展，挈酒且相就。", "佳林延凉飈，廣厦蔭清晝。", "浩然塵慮醒，坐看天骨秀。", "殷勤述平昔，感歎道艱疚。", "談辭足端倪，懷抱去蒙覆。", "志願始云獲，睽携遽然又。", "君舟既南馳，我馬亦東走。", "還譙寡儔侶，孤學日以陋。", "高風邈難親，離抱曷其救。", "得君別後詩，滿紙字騰驟。", "汪洋莫知極，精密不可耨。", "峻嚴山岳停，奔放江海漏。", "伏讀晝夜并，文義僅通透。", "有如享太牢，繼以金石侑。", "惟君抱雄才，文字乃兼副。", "要當被金甲，獨立諸將右。", "指揮神武師，爲國縛狂寇。", "獻俘天子廷，功以鐘鼎鏤。", "勉哉俊其時，此論講已舊。"]'),
('dc1e0f74-f99c-497f-93c2-7f7301ceb395','送趙員外之官憲州','韓維','宋','宋诗','song-poetry','','[]','仲扶岷峨秀，弱歲儒其冠。',264,'全唐诗/poet.song.24000.json','["仲扶岷峨秀，弱歲儒其冠。", "讀書覷前古，飽見萬事端。", "行已去畦町，爲文鄙彫剜。", "應舉二十載，不免瓢與簞。", "西游秦函國，崆峒上巑岏。", "却視關塞廣，有如掌中丸。", "攻守勢所利，浩然入窺觀。", "是歲羌事作，賊兵犯鄜丹。", "君懷濟時略，忠憤激肺肝。", "上書伏兩觀，音辭若琳玕。", "臣策倘見用，坐令敵氣殫。", "天子壯其語，且使位以官。", "黄綬繫腰下，行行不遑安。", "炎天風塵多，遠道車馬單。", "餞觴不親酌，曷致朋友懽。", "今茲塞垣將，所在麾旄攢。", "孰能謀而毅，孰能正以寬。", "孰用賞不信，孰爲刑不殘。", "諒非專達任，易以奇畫干。", "庶幾成大功，展子凌霄翰。", "顧我頑鈍者，託契歲屢寒。", "贈言非所工，當否聊一看。"]'),
('7184ae5a-7eba-447e-b808-c632e79670fb','遊北臺','韓維','宋','宋诗','song-poetry','','[]','南譙古佳郡，四郊富登臨。',264,'全唐诗/poet.song.24000.json','["南譙古佳郡，四郊富登臨。", "晨躋北原上，却視渦水陰。", "云昔魏太子，離宮構嶔崟。", "故事邈已遠，荒臺猶至今。", "危亭冠其巔，左右背長林。", "是月暑尚盛，秋行不能金。", "截然天地間，軒戶蕭以森。", "凉風泛廣坐，濁醪時一斟。", "圓歌貫珠璣，麗句鏗璆琳。", "雖無管弦樂，所要在適心。", "中宴下危磴，浮舟事幽尋。", "披藻出潛蚌，回橈散游禽。", "岸長草不斷，城轉樹更深。", "沙紋與水影，浮動光差參。", "游鱗不知數，瑣細如糝針。", "四顧物色靜，但聞天籟音。", "羨此魚鳥性，雲飛而淵沉。", "安得高世士，不爲時好侵。", "相携去韁鎖，投竿坐清潯。", "製芰爲我裳，紉蘭間予襟。", "上歌唐虞道，寄適朱弦琴。", "人生苟如此，何必組與簪。"]'),
('4b98aac1-cc98-4e04-a377-fbc88bf85e53','和三兄之山陽省孀姊書懷','韓維','宋','宋诗','song-poetry','','[]','君子蹈仁義，近自親愛始。',120,'全唐诗/poet.song.24000.json','["君子蹈仁義，近自親愛始。", "當行豈顧留，千里猶舉趾。", "伯氏有東役，駕言適淮涘。", "離樽未及展，濁醪未及灑。", "起視白日移，驅車一何駛。", "遵塗驪唱發，春風落端綺。", "義參成周作，辭追建安軌。", "感此留滯迹，一誦三四起。", "安得假羽翮，遠慰心所企。", "此志良未遂，灑泣詎能已。"]'),
('d45b363b-f64b-437b-a1e0-c4f6394c6719','答王詹叔見寄','韓維','宋','宋诗','song-poetry','','[]','詹叔好古者，卓立自既冠。',144,'全唐诗/poet.song.24000.json','["詹叔好古者，卓立自既冠。", "有如騏驥兒，一縱不可絆。", "近聞治周易，顛倒爻象彖。", "此書號精微，義與天地貫。", "吾知子之道，不止今所嘆。", "新詩溢巾幅，見寄警庸懦。", "噴薄百丈泉，峭絕萬仞岸。", "感激氣爲振，把誦手屢盥。", "陰風吹寒城，歲暮雲物換。", "丈夫及壯時，功名當照爛。", "無爲但默默，飽食大軀幹。", "爲報乏瓊玖，君其取章斷。"]'),
('f6a83673-b2da-4b45-b535-f2c75fc5ab9e','送曹殿丞秩滿還都','韓維','宋','宋诗','song-poetry','','[]','朝日照濠水，清霜發樹寒。',144,'全唐诗/poet.song.24000.json','["朝日照濠水，清霜發樹寒。", "長橋下廣陌，車馬來嘽嘽。", "借問行人誰，送者何盤桓。", "中郎罷從軍，遺愛民所嘆。", "雍容幕府舊，供帳清渦干。", "悲風思急管，薄暮留征鞍。", "酒酣惜分手，四坐慘不歡。", "長河轉轍迹，愁陰但漫漫。", "嗟予隔追餞，飲此離恨端。", "高標邈難親，坐向飛鴻看。", "嘗聞古君子，贈言當豆簞。", "願君保亮節，歲晚予其觀。"]'),
('b91ca1d2-485a-4069-83fa-1c78dc679b4c','與張仲巽遊善護院','韓維','宋','宋诗','song-poetry','','[]','高城面脩塗，呀豁若箕口。',192,'全唐诗/poet.song.24000.json','["高城面脩塗，呀豁若箕口。", "其右釋子廬，蒼柏蔭庭牖。", "翹翹幕中彥，疏懷脫喧垢。", "結轡游禪扃，彈弦樂嘉友。", "華榱翳廣坐，仰視眩丹黝。", "朱光羞晨櫻，紺玉折春藕。", "初筵頗清簡，中醉稍喧糅。", "歌休衆管作，令發洪鐘叩。", "橫浮或見違，義藴□□□。", "酒酣隘常見，大觀資遠取。", "上躋危磴盤，却立土崖斗。", "長川自西來，逶迤带坰藪。", "綠樹下成列，獵獵清風走。", "側身宇宙間，群動何紛糾。", "自顧齷齪極，天地一罌缶。", "安得修靈根，超然出諸有。"]'),
('1af879e0-2652-4bf5-9e26-bff63f6eeaa6','春夜懷仲巽','韓維','宋','宋诗','song-poetry','','[]','今茲春始仲，氣序忽已燠。',120,'全唐诗/poet.song.24000.json','["今茲春始仲，氣序忽已燠。", "及此暇夜清，開軒散煩蹙。", "金波麗中天，流光正穆穆。", "佳樹澄疏影，幽花運微馥。", "濁醪時獻斟，清論遞往復。", "諸季豈不歡，眷眷心所服。", "高文炳辰宿，淵議贊化育。", "匪才託遊好，餘潤久沾沐。", "茲焉隔清賞，耿耿私恨蓄。", "春芳正可樂，嘉會期晝卜。"]'),
('763bfad0-a00b-4242-b4fd-582ffea01bcd','寄蘇子美','韓維','宋','宋诗','song-poetry','','[]','暮登譙城上，延首望東道。',156,'全唐诗/poet.song.24000.json','["暮登譙城上，延首望東道。", "春風千里至，遠思生懷抱。", "故人客南楚，素節方自保。", "黄鵠垂其翼，赤驥伏棧皂。", "詩準李杜爲，字壓褚薛倒。", "壯哉南行作，遺我資遠討。", "若窺巨海涯，波瀾方洶浩。", "龍螭鬰騫騰，錯落效衆寶。", "往往仙人槎，突然忘枯槁。", "嘗聞會稽旁，山水天下好。", "覽君所咏嘆，滯想茲一掃。", "安得追王喬，乘雲逮霓葆。", "茹芝靈峰陽，徜徉以終老。"]'),
('a0d46fb1-a290-4729-88cc-89487b735eaf','初春吏隠堂作','韓維','宋','宋诗','song-poetry','','[]','微風稍破凍，芳萌亦吐林。',120,'全唐诗/poet.song.24000.json','["微風稍破凍，芳萌亦吐林。", "百鳥感春陽，鈎輈弄其音。", "振策遵城曲，逍遥寫煩襟。", "愛此堂下石，青潤挺琅琳。", "中坳貯清泉，測之不盈簪。", "纖鱗候暖戲，寂歷自浮沉。", "默視澹忘慮，白日爲移陰。", "人生本虛靜，垢濁無自侵。", "忽爲外物牽，至性不可尋。", "於焉得所監，一洗塵中心。"]'),
('b521a2bf-ce81-4180-8770-6b033d2262f8','立春觀杖牛','韓維','宋','宋诗','song-poetry','','[]','清霜凉初曙，高門肅無譁。',120,'全唐诗/poet.song.24000.json','["清霜凉初曙，高門肅無譁。", "行樹迎初日，微風轉高牙。", "茲辰亦何辰，見此氣候嘉。", "有司謹春事，象牛告田家。", "微和被廣陌，纓弁揚蕤葩。", "伐鼓衆樂興，剡剡彩杖加。", "盛儀適未已，觀者何紛拏。", "因思古聖人，時儆在不差。", "禮實久已廢，所重存其華。", "吾非魯觀賓，胡爲亦咨嗟。"]'),
('29e0c9ff-4685-4ea2-8911-0d7b51b1f467','魯恭太師廟','韓維','宋','宋诗','song-poetry','','[]','善教邈無迹，其流在民心。',84,'全唐诗/poet.song.24000.json','["善教邈無迹，其流在民心。", "君看魯太師，廟食猶至今。", "豈如文俗士，朱墨坐浮沉。", "趨營止目前，不顧患害深。", "去漢餘千載，此弊竟相尋。", "我行道祠下，感激爲悲吟。", "不見田雉馴，啼鴉空滿林。"]'),
('e447481d-3af5-4a4a-9ac5-da310a57a15a','服除送兄弟還都','韓維','宋','宋诗','song-poetry','','[]','日月忽已遠，再見新穀升。',156,'全唐诗/poet.song.24000.json','["日月忽已遠，再見新穀升。", "喪期有常數，吉我衣與襟。", "俯仰自悲咤，淚下肝膽崩。", "尚推立身報，未即泯餘生。", "肅肅忠憲公，秉德輔休明。", "報國有遺意，訓言猶在聽。", "况茲世厚恩，兄弟秩王庭。", "一朝出門去，事業各自營。", "上當答君仁，下以爲親榮。", "獨此抱痾瘵，謝喧守柴荆。", "掃冢奉時祭，履田課春耕。", "既無公家責，聊徇狷者情。", "出處雖云異，要以道爲程。"]'),
('174bf21d-4eab-44e5-8fde-e2dab75b5593','送兄弟還都至長葛河上四首 雙禽','韓維','宋','宋诗','song-poetry','','[]','雙雙河洲禽，文彩披丹質。',48,'全唐诗/poet.song.24000.json','["雙雙河洲禽，文彩披丹質。", "飛翔不離渚，鳴戲自終日。", "寒魚伏冰池，歲暮饑爾匹。", "不欲遠求林，投身避羅畢。"]'),
('0687be8d-2885-4c5b-a566-fa281031ab8f','送兄弟還都至長葛河上四首 晚步','韓維','宋','宋诗','song-poetry','','[]','愛此霽景佳，捨舟步高岸。',48,'全唐诗/poet.song.24000.json','["愛此霽景佳，捨舟步高岸。", "夕陽照渡口，急急水紋亂。", "霜鴉田間鳴，沙鳥波上散。", "登臨豈非美，當軫別後嘆。"]'),
('bf8c54d3-2e2e-44fe-930c-72ffc52509e0','送兄弟還都至長葛河上四首 舟中夜坐','韓維','宋','宋诗','song-poetry','','[]','晴霜落波底，斗柄插堤外。',48,'全唐诗/poet.song.24000.json','["晴霜落波底，斗柄插堤外。", "扁舟燈火明，樽酒夜相對。", "臨歡意暫遣，念離心已痗。", "篙師喜冰拆，理楫事晨邁。"]'),
('0d991cfc-0964-4bf8-9a80-57ee5aff173c','送兄弟還都至長葛河上四首 別後作','韓維','宋','宋诗','song-poetry','','[]','朔風吹驚鴻，行列失後先。',48,'全唐诗/poet.song.24000.json','["朔風吹驚鴻，行列失後先。", "蒼蒼雪壓船，齒齒冰著岸。", "離馬聲正悲，別臉淚猶泫。", "却望携手處，危檣映林見。"]'),
('c9f5f5d4-5d3e-448d-bc81-4b2dbc1755dc','靈溝道中','韓維','宋','宋诗','song-poetry','','[]','久跼慕遐放，出郊欣所矚。',48,'全唐诗/poet.song.24000.json','["久跼慕遐放，出郊欣所矚。", "清心曉岫碧，豁眼春原綠。", "耕人畢在野，鳴鳥催播穀。", "嗟爾農事勞，願聞時澤足。"]'),
('a92a0b7c-fb54-432a-ab35-1f9501fd4c89','西園暮雪','韓維','宋','宋诗','song-poetry','','[]','空園響松竹，霰雪靄霏霏。',84,'全唐诗/poet.song.24000.json','["空園響松竹，霰雪靄霏霏。", "仰視長雲色，皓然同一輝。", "天寒鳴雁急，日暮行人稀。", "惟見衆小禽，啾唧滿林飛。", "陰風起何處，拂拂來吹衣。", "俯念當世事，幽憤不可揮。", "歸來散群帙，獨掩袁安扉。"]'),
('12bc33f4-1163-4452-b6b5-42e6eea45973','東窗','韓維','宋','宋诗','song-poetry','','[]','高窗不掩秋氣清，下見瓦沼涵泓澄。',64,'全唐诗/poet.song.24000.json','["高窗不掩秋氣清，下見瓦沼涵泓澄。", "雨洗浮萍翠色靜，青叢綠蔓相纏仍。", "階前童童兩好樹，上有鳴禽不可數。", "杖藜書生愛苦吟，獨立西風無旦暮。"]'),
('77f5dbf7-1636-4b09-ae68-45de91da4ef3','曉霽','韓維','宋','宋诗','song-poetry','','[]','時澤鬰初霽，朝景爛已盈。',48,'全唐诗/poet.song.24000.json','["時澤鬰初霽，朝景爛已盈。", "幽人獨坐久，春鳩相應鳴。", "清風動佳樹，平地泛落英。", "方懷歲成喜，况值茲賞并。"]'),
('419ad981-219f-4ca5-9448-410f5bf2de75','新置北軒','韓維','宋','宋诗','song-poetry','','[]','紛敷北軒植，移劚來中園。',96,'全唐诗/poet.song.24000.json','["紛敷北軒植，移劚來中園。", "微雨一飄灑，咄咄芽蕊繁。", "輕黄吐雙蕉，寸碧羅叢萱。", "更憐二棕櫚，遠結蜀土根。", "清風落檐楹，翼羽何翻翻。", "惟此松竹姿，灑然出塵昏。", "衆芳自爭妍，正性中獨存。", "願秉歲寒操，翠色藹君軒。"]'),
('be39887e-1bd3-4304-87f1-918deae4fb2d','放魚','韓維','宋','宋诗','song-poetry','','[]','時哉清川魚，罹此鈎網牽。',96,'全唐诗/poet.song.24000.json','["時哉清川魚，罹此鈎網牽。", "稚子捧盤至，鱗采金翠駢。", "一感仁者意，泳我清泠泉。", "晨跳翻綠萍，暮息依白蓮。", "脫身刀俎間，永以終爾年。", "唯昔鄭國僑，亦嘗嘆悠然。", "以方斯可欺，孟子稱其賢。", "永懷古人懿，屢嘆春風前。"]'),
('c493f801-ccd7-4090-b6d3-d43f0cc0a942','次韵和三兄田家','韓維','宋','宋诗','song-poetry','','[]','東皋雨新足，綠野對柴扉。',48,'全唐诗/poet.song.24000.json','["東皋雨新足，綠野對柴扉。", "晴日風景曠，暮春草木肥。", "好鳥依林響，疲牛望舍歸。", "餉婦散田陌，桑間人語稀。"]'),
('c3286a0d-73f7-43df-a097-4986a5a4b976','村居曉起','韓維','宋','宋诗','song-poetry','','[]','天星何寥寥，野曠風露清。',48,'全唐诗/poet.song.24000.json','["天星何寥寥，野曠風露清。", "田父出門望，山鴉繞舍鳴。", "蠶桑從此起，農里各有營。", "顧慚不耕者，日宴掩茅衡。"]'),
('83326203-91a7-488f-a1d6-8310bdb913f1','秋雨南堂即事','韓維','宋','宋诗','song-poetry','','[]','南堂秋雨清，竹樹變愁靜。',48,'全唐诗/poet.song.24000.json','["南堂秋雨清，竹樹變愁靜。", "微寒病體蘇，燕坐塵事屏。", "高林颯已落，鳴雁去方永。", "何以消沉憂，予心在箕潁。"]'),
('0aee9626-add9-4f8a-80ac-104f754c360c','和子華許昌道中詩有隠逸之思','韓維','宋','宋诗','song-poetry','','[]','悲風中夜興，寒氣入我室。',252,'全唐诗/poet.song.24000.json','["悲風中夜興，寒氣入我室。", "頹然攬衣坐，中懷百憂溢。", "我生乏壯圖，少小事刀筆。", "窺古得微尚，趨時寡良術。", "野性不受羈，塵事憂見桎。", "况茲罹大艱，哀號重衰疾。", "生意且蕭瑟，何必慕祿秩。", "風俗日以惡，險詐路百出。", "素昧防閑術，睹此實怖慄。", "安能徇時好，嘵嘵喪天質。", "所頼子華兄，志尚古人匹。", "新詩來聯翩，意韵時高逸。", "中畫歸休計，羅列甚詳密。", "雅懷蕭灑心，期言倘能必。", "便當奉几杖，相與安蓬蓽。", "薄田能力耕，歲計猶不失。", "結廬守松楸，築圃蓺柿栗。", "鷄豚燕嘉辰，魚釣樂暇日。", "讀書取知道，白首窮經一。", "甘從野儒事，庶保幽人吉。", "咄哉軒冕徒，校此孰勞佚。"]'),
('56619bb5-d71d-44ae-801f-39c34a7ea0ae','奉寄汝守仲儀舅','韓維','宋','宋诗','song-poetry','','[]','嘗提十萬師，爲國扞羌寇。',216,'全唐诗/poet.song.24000.json','["嘗提十萬師，爲國扞羌寇。", "嚴兵坐大府，諸將無與右。", "旌纛儼成列，鐘鼓振前後。", "曰賞固自我，有誅孰敢救。", "勝勢前已决，威聲日西走。", "功名未及建，得此山城守。", "捧詔顧東路，怡然引車就。", "窮秋過舊許，整駕一來覯。", "高談不知疲，輒用火繼晝。", "卒無慍黜端，少以顔色漏。", "乃知君子心，得喪不自囿。", "悔非自取之，於道有不受。", "徒然頌德美，洪量詎窺究。", "孤城俯清汝，山勢遠相鬥。", "公庭日無事，燕坐陰華構。", "林寒山雪飛，地靜玉泉漱。", "於茲樂天理，足使道牙茂。", "時寄新詩章，窮閭慰衰疚。"]'),
('68ea2640-e439-42a4-a107-1dcaeead7782','蘇才翁與予定林下之約今被命提點湖南刑獄恐其侵尋而不能反作詩貽之','韓維','宋','宋诗','song-poetry','','[]','軒冕予已輕，山水君所樂。',96,'全唐诗/poet.song.24000.json','["軒冕予已輕，山水君所樂。", "相逢說高興，南望欲奔趠。", "今君被國恩，明刑弼予教。", "群公許風棱，列郡瞻氣貌。", "朝廷方急才，懸爵待明效。", "美官誠足慕，素約未宜撓。", "當懷平生言，拔足利名罩。", "笑謝世俗人，夷猶五湖棹。"]'),
('1d7d9bf0-7f4e-4b54-afd9-7e62304579c2','寄宗彥侄','韓維','宋','宋诗','song-poetry','','[]','清寒霽愈劇，幽居夜正閒。',132,'全唐诗/poet.song.24000.json','["清寒霽愈劇，幽居夜正閒。", "環爐盡兄弟，無爲愁苦顔。", "游心物象表，放論文字間。", "念汝不與此，慨然以長嘆。", "唯昨郭西門，爾車去班班。", "是月秋始仲，霜葉原上丹。", "相別曾未幾，朔雪滿河關。", "乃叔疏野性，雅慕詩考槃。", "近買靈溝地，郊居漸當安。", "薄宦奚足爲，真隠庶可攀。", "斯言倘汝志，投紱相與還。"]'),
('24f858b2-1573-4574-8d34-1926c93d52a6','歲暮','韓維','宋','宋诗','song-poetry','','[]','高風動河漢，肅肅下陰霜。',48,'全唐诗/poet.song.24000.json','["高風動河漢，肅肅下陰霜。", "起視夜向艾，華星粲相望。", "犬吠閭巷靜，哀鴻正南翔。", "歲暮已多感，及茲重成傷。"]'),
('b454f9fe-ba98-4ba4-95b8-6cdfe454fee7','送王氏兄弟','韓維','宋','宋诗','song-poetry','','[]','抱疾伏田里，晨昏結煩憂。',180,'全唐诗/poet.song.24000.json','["抱疾伏田里，晨昏結煩憂。", "如彼衣上垢，歲久不可漱。", "忽聞車馬音，來過吾廬幽。", "相見一長慟，悲風爲遲留。", "張燈具餐飯，涕泗稍復收。", "南堂夜相對，油然破離愁。", "雖無盈樽酒，清論代獻酬。", "高篇璨成誦，輸寫殊不休。", "婆娑雙鳳凰，飛舞光彩浮。", "忽然變瑰怪，風霆拔金虯。", "傾聽魄已悸，何暇測其由。", "君家門閥大，先世勤令猷。", "晉公典冊文，太尉廊廟謀。", "子孫今多才，信矣陰德流。", "還轅欲何語，贈子詩聿修。"]'),
('aa04f1eb-b77d-4fbd-90f9-6a56b69ce69c','讀杜子美詩','韓維','宋','宋诗','song-poetry','','[]','寒燈熠熠宵漏長，顛倒圖史形勞傷。',128,'全唐诗/poet.song.24000.json','["寒燈熠熠宵漏長，顛倒圖史形勞傷。", "取觀杜詩盡累紙，坐覺神氣來洋洋。", "高言大義經比重，往往變化安能常。", "壯哉起我不暇寐，滿座嘆息喧中堂。", "唐之詩人以百數，羅列衆制何煌煌。", "太陽重光燭萬物，星宿安得舒其芒。", "讀之踴躍精膽張，徑欲追攝忘愚狂。", "徘徊攬筆不得下，元氣混浩神無方。"]'),
('c9a4e348-b933-491c-b9f8-b3ad91a870a5','王詹叔惠酥','韓維','宋','宋诗','song-poetry','','[]','興平産良酥，厥品爲第一。',108,'全唐诗/poet.song.24000.json','["興平産良酥，厥品爲第一。", "歲時盛獻饋，霜梨副冰蜜。", "東來連車軫，并走衛霍室。", "盤筵得此物，主意自爲畢。", "詹叔官西州，遺我資口食。", "甘知馬酒薄，素覺鵝肪失。", "我今農里人，藜藿度閒日。", "多慚擲嘉味，徒用飽仁術。", "厚意如何報，還持况賢質。"]'),
('b6076a61-4af0-43d6-9da2-5543157f68d7','讀信陵傳','韓維','宋','宋诗','song-poetry','','[]','周綱亂無紀，群雄事吞爭。',96,'全唐诗/poet.song.24000.json','["周綱亂無紀，群雄事吞爭。", "猶能假仁義，以勢相奪傾。", "是時賢公子，信陵最知名。", "招摇大梁市，攬轡御侯嬴。", "義勝下予色，恩重忘彼生。", "竊符連王姬，奮錘遺國兵。", "救趙意何切，於魏情已輕。", "頼有毛薛在，終然臣節明。"]'),
('aaddd4ab-5d6e-4161-a10f-208c6e8109a9','又靈溝道中','韓維','宋','宋诗','song-poetry','','[]','春風來無迹，泱莽天地和。',108,'全唐诗/poet.song.24000.json','["春風來無迹，泱莽天地和。", "群生樂時陽，衆鳥舞且歌。", "嗟爾道旁叟，寒餒獨見羅。", "短席不自蔽，皮骨撐枯柯。", "呼童問所以，口噤不能哦。", "所見且如此，况餘生齒多。", "吾聞古三代，仁術固匪他。", "老幼孤洎疾，餼養平不頗。", "斯道久寂寞，吾悲其奈何。"]'),
('61c7bcf7-990b-4a2b-8454-dc03ec06640e','種柏寄蘇子美','韓維','宋','宋诗','song-poetry','','[]','人皆種花我種柏，爲此勁性寒不易。',64,'全唐诗/poet.song.24000.json','["人皆種花我種柏，爲此勁性寒不易。", "三春雖憐少姿媚，歲暮方看靄顔色。", "南堂之南可數到，列樹六本翠磔磔。", "安得驛使向姑蘇，持以贈君比明德。"]'),
('d60b0329-57a3-47ba-a7b0-eee50dfd808a','感季夏南堂懷江十蘇二','韓維','宋','宋诗','song-poetry','','[]','積雨漂暑餘，凉風作秋先。',168,'全唐诗/poet.song.24000.json','["積雨漂暑餘，凉風作秋先。", "南堂草木深，蟬蜩嘒籬掾。", "感此時節流，坐傷人事變。", "去年居京華，晨昏侍親燕。", "問誰過我頻，江蘇實邦彥。", "一朝艱禍纏，銜哀走窮縣。", "形骸悲瘵中，氣息僅如綫。", "鄰幾謫官去，門征校虧羨。", "子美亦遠遊，江湖一蓬轉。", "人生哀樂間，瞥若過目電。", "念此不敢已，淋漓淚垂面。", "二君希代寶，寧久世俗賤。", "天和酌無竭，玉德莫愈見。", "何以慰相思，酬篇佇來絢。"]'),
('89c86247-aafa-41cb-9666-dcf528ac2a78','覽梅聖俞詩編','韓維','宋','宋诗','song-poetry','','[]','夙昔誦佳句，跂予慕高風。',156,'全唐诗/poet.song.24000.json','["夙昔誦佳句，跂予慕高風。", "何意憂艱餘，邂逅此相逢。", "君初應府辟，捧檄來自東。", "引車窮檐下，眷然顧微躬。", "姿表穆以秀，純德信內充。", "乃知文章作，中與性情通。", "煌煌新詩章，垂光照昏蒙。", "啟櫝挹荆璞，引莛撞景鐘。", "高篇屢云闋，遠思殊未終。", "譬如巧琴師，哀彈發絲桐。", "中有沖淡意，要以心志窮。", "顧惟昧者聽，莫辨徵與宮。", "安得牙曠手，提耳發其聰。"]'),
('8ccaaeba-175b-4b15-a0c2-a4bb791b309b','西墅','韓維','宋','宋诗','song-poetry','','[]','城居不爲愜，言適西陂岡。',48,'全唐诗/poet.song.24000.json','["城居不爲愜，言適西陂岡。", "雀噪野堂靜，鷄鳴春日長。", "書棚落幽蠹，佛幔掩餘香。", "釋子廬巖至，清談殊未央。"]'),
('1027aaeb-0525-4f8b-a64e-f1104e370ab3','對雨思蘇子美','韓維','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','五月陰盛暑不效，飛雲日夕起嵩少。',208,'全唐诗/poet.song.24000.json','["五月陰盛暑不效，飛雲日夕起嵩少。", "回風颯颯吹暮寒，翠竹黄蕉雨聲鬧。", "北軒孤坐默有念，人生會合那可料。", "昔與子美比里閭，是月秋近足霖潦。", "吾徒無事數相過，日策疲馬度深淖。", "升君之堂伏君几，果餌羅列亦稍稍。", "開樽得酒味已酢，輔以諧謔聊可嚼。", "長歌激烈或孤起，大論紛紜特一噪。", "颯然夜氣變凄栗，連披短褐曳顛倒。", "且欣主人同氣類，安問鄰家厭呼笑。", "而今相望各千里，跼促有如魚在罩。", "人生此樂不易得，世事榮辱何足校。", "行當結侶候春水，一訪洞庭湖上棹。"]'),
('e8209d59-e69e-4a04-8b8b-5369f5bd49ca','出郊古意','韓維','宋','宋诗','song-poetry','','[]','跨馬長林下，落葉填荒溝。',84,'全唐诗/poet.song.24000.json','["跨馬長林下，落葉填荒溝。", "嚴霜熟秋實，野物畢以收。", "空場委餘穗，雀鷃鳴相求。", "仰視鴻鵠群，肅肅摩天游。", "清風下哀響，靜聽令人愁。", "時序迭而去，曾不與我謀。", "小人急趨利，君子懷德憂。"]'),
('be67d50d-d3f0-4d8a-9019-081b5b0b6291','和三哥入山二首','韓維','宋','宋诗','song-poetry','','[]','巢由沒已久，風迹曠不嗣。',120,'全唐诗/poet.song.24000.json','["巢由沒已久，風迹曠不嗣。", "長嘯箕潁間，悲風肅然至。", "傳聞龍山下，茅屋架三四。", "中有隠者棲，讀書樂仁義。", "飽觀人事變，深鈎易象秘。", "耕田給衣食，鄉里霑賑遺。", "呦呦山鹿群，摩撫馴不畏。", "乃知至仁心，足以通異類。", "聲名自馳擊，我心晏無累。", "寤寐想斯人，安得同所致。"]'),
('e4fef587-96d2-4af2-86bf-061cdb1a41d5','山林','韓維','宋','宋诗','song-poetry','','[]','長林翳空谷，茲惟群材府。',96,'全唐诗/poet.song.24000.json','["長林翳空谷，茲惟群材府。", "石路險且躋，不爲斧斤取。", "火雲無時蒸，衆葉朝自雨。", "仰視不見末，飛鳥安得度。", "下有靈藥草，其品難記數。", "駢然花實繁，紅紫貫四序。", "霜風落橡栗，投擲地虺怒。", "過嶺林更深，欲前防猛虎。"]'),
('c440e49d-50e2-448d-adf5-bac6c4c7fade','郊居值雨','韓維','宋','宋诗','song-poetry','','[]','愁雲覆西郊，氣象凄以冽。',120,'全唐诗/poet.song.24000.json','["愁雲覆西郊，氣象凄以冽。", "夜雨朝不止，冰霰相纏結。", "南堂何蕭條，散秩坐超忽。", "頹然附爐炭，兩髁冷如鐵。", "俯念田家苦，罹此寒事切。", "北風卷平野，茅屋左右穴。", "驅牛入門去，爨下火明滅。", "場功始云畢，貧不具衣褐。", "况無酒與羔，歲時相勞悅。", "高咏七月詩，傷哉愁心折。"]'),
('7c29e26d-d1d1-4370-85e3-ad66e359c802','答江鄰幾','韓維','宋','宋诗','song-poetry','','[]','君雖宦游者，閒適意有餘。',156,'全唐诗/poet.song.24000.json','["君雖宦游者，閒適意有餘。", "平居對樽酒，口誦離騷書。", "援琴寫其聲，世事皆蔑如。", "不知萬乘相，可易此樂無。", "諸詩來不竭，若有神物輸。", "予病廢學久，腹中日空虛。", "苦遭大敵壓，便甘等縲俘。", "清風濯我圃，竹樹相傾扶。", "益之以佳雨，清凉如可斟。", "聊休據梧瞑，且復带經鋤。", "鳴鶑久不去，乳鵲時驚呼。", "即此良自逸，安知城郭居。", "此與君不淺，相望重躊躇。"]'),
('61e4f821-f9f8-4022-a4e2-0490b45aed43','崔象之携長詩示予且欲以癭木樽相付作詩謝之','韓維','宋','宋诗','song-poetry','','[]','君家癭木樽，醜怪不可狀。',108,'全唐诗/poet.song.24000.json','["君家癭木樽，醜怪不可狀。", "自非好事者，棄置等盆盎。", "作詩一千言，引類何其壯。", "且思高世士，遺以資雅尚。", "曰予林壑性，受此頗宜當。", "我今衰病餘，卷縮就閒放。", "才非時用宜，茲器正相况。", "敢邀高世名，自觸譏與謗。", "再拜謝佳意，君何授之妄。"]'),
('20b816b6-2f7d-4061-a48a-7c65840dfbe8','奉答吳殿丞見贈','韓維','宋','宋诗','song-poetry','','[]','勢利躍諂子，聲名走夸兒。',96,'全唐诗/poet.song.24000.json','["勢利躍諂子，聲名走夸兒。", "我於二無一，世固背以馳。", "君從江海來，面有瀟灑姿。", "朝廷多舊游，絕迹不復追。", "足音三及門，乃得衆所遺。", "長篇爛盈目，清遠謬見推。", "將非樂閒放，獨與靜者宜。", "何以謝嘉况，湖山有前期。"]'),
('326eb761-d97b-4710-8355-ba598f40232d','從道損舅乞移山藥','韓維','宋','宋诗','song-poetry','','[]','弱歲抱衰病，好讀神農經。',120,'全唐诗/poet.song.24000.json','["弱歲抱衰病，好讀神農經。", "雜然衆藥品，粗識性與形。", "商於巖谷間，厥産芝朮菁。", "山家乘冬採，氣烈味亦并。", "常思負籠往，劚此地氣靈。", "近聞山旁縣，移本來公庭。", "石泉尚含潤，溪風有餘清。", "想像春叢敷，蔚蔚揚華英。", "駢羅良可佳，疲薾宜見矜。", "安得畦畹餘，種食羽翼生。"]'),
('c2171598-c73f-437f-950a-b0347da5d6fe','答崔象之見謝之作','韓維','宋','宋诗','song-poetry','','[]','陰風吹沙走長衢，方駕往過君之廬。',240,'全唐诗/poet.song.24000.json','["陰風吹沙走長衢，方駕往過君之廬。", "主人好事樂閒尚，揖我謂我非俗儒。", "欣然開館掃塵榻，語論清簡發不虛。", "投冠釋带聊自放，安用俗禮空囚拘。", "分朋四座鬥巧奕，聊以勝負爲歡娛。", "呼兒稍稍出珍玩，癭器礧砢承枯株。", "持竿拂壁似有重，最後乃挂雙海圖。", "云昔武皇恃威壯，驅石塞海怪可吁。", "鞭笞鬼神各就事，簸弄旗幟翻以舒。", "魚龍驚逃波浪惡，左右出沒揚牙鬚。", "但憐物類頗幽怪，畫手安辨曹與吳。", "北軒却下步小徑，竹深桂靜何縈紆。", "我來方冬氣凜冽，已愛翠色侵衣裾。", "即看春風撼芽甲，定見紅紫相欹扶。", "乘閒取醉更何適，主人勿遽嫌喧呼。"]'),
('26c56a21-a630-45f3-bc4f-63ec6dc64401','同曼叔出郊','韓維','宋','宋诗','song-poetry','','[]','驅馬信所適，路轉上野橋。',108,'全唐诗/poet.song.24000.json','["驅馬信所適，路轉上野橋。", "橋邊春水凈，縈回带平皋。", "兩崖卉木茂，東風澹正摇。", "故叢尚含綠，新芽已滿條。", "老小延我觀，名品各異標。", "問翁安致之，遠自伊洛郊。", "涉正曾未幾，已覺芳意饒。", "後日風更雨，繁紅定飛飄。", "顧謂同行客，有酒頻我招。"]'),
('94fe4ebb-5d71-4da7-a829-3f097203091a','送孔先生還山','韓維','宋','宋诗','song-poetry','','[]','先生樂道者，於世澹無欲。',120,'全唐诗/poet.song.24000.json','["先生樂道者，於世澹無欲。", "高風自絕人，正行不違俗。", "朅來城闕遊，不受塵事觸。", "目久望林壑，駕言反幽築。", "家臨滍水陽，路轉春山曲。", "東風吹百花，紅紫滿巖谷。", "蠶桑事未起，農里得徵逐。", "社酒濁易求，山蔬晴可劚。", "幽尋月吐嶺，高卧日照屋。", "應念塵中人，胡爲自羈跼。"]'),
('f0abeefa-bdb3-49da-a0b7-fa1158add687','送謝師直歸馬上作','韓維','宋','宋诗','song-poetry','','[]','送客西郭門，適與嘉賓遇。',84,'全唐诗/poet.song.24000.json','["送客西郭門，適與嘉賓遇。", "雜花被原野，南盡遠目注。", "撲撲亂朱紛，濛濛凝白霧。", "林下風正柔，繁香不飛去。", "日長人意閒，歸騎款不遽。", "陶然行且歌，良愜靜者素。", "却念陌上人，春愁紛似絮。"]'),
('a1122d52-6236-45cd-a942-b9d85ae75a4e','新植西軒','韓維','宋','宋诗','song-poetry','','[]','誰謂我圃隘，栽插尚盈畝。',144,'全唐诗/poet.song.24000.json','["誰謂我圃隘，栽插尚盈畝。", "築軒西臨兌，規地北占酉。", "陽條散繁華，怒甲擎故朽。", "封培童僕勞，窺看孩稚走。", "雖非觀游盛，要是吾廬有。", "壤疏人力薄，開發定遲後。", "所頼春風意，與物無薄厚。", "居閑日蕭散，對此自成偶。", "問我何所爲，卦象觀六九。", "問誰之與處，達者二三友。", "爲生昧機利，於事寡營取。", "但願花常好，酌我樽中酒。"]'),
('2c219c65-efe3-44f6-ab6e-0d754f6e6ffe','聖俞約晚見過不至','韓維','宋','宋诗','song-poetry','','[]','聞君敕車騎，晚駕慰愁獨。',48,'全唐诗/poet.song.24000.json','["聞君敕車騎，晚駕慰愁獨。", "焚香靄疏箔，灑水靜深屋。", "高懷豈我遺，幽思方自續。", "日暮尚徘徊，清風滿修竹。"]'),
('8cb66059-4e4c-4c52-925c-d43484e04b2d','送李廷老歸河陽','韓維','宋','宋诗','song-poetry','','[]','愛子良自持，不復前日并。',84,'全唐诗/poet.song.24000.json','["愛子良自持，不復前日并。", "乃能從古人，帖帖事閑靜。", "西軒雨新足，衆藥長條穎。", "援琴對濁酒，盡此夏日永。", "歸心不可留，知子念晨省。", "驅車遵大河，回首望嵩嶺。", "相思倘以詩，見寄慰幽屏。"]'),
('80a3f1a9-471e-4ca4-b72a-e287a1556f91','謁孔先生','韓維','宋','宋诗','song-poetry','','[]','月出高樹枝，影動酒樽處。',72,'全唐诗/poet.song.24000.json','["月出高樹枝，影動酒樽處。", "樹深月色薄，稍以燈火助。", "主人喜我過，斟酌亦云屢。", "於時幸無累，所談非近務。", "凉風自遠生，清景澹吾慮。", "方期西山秋，歷覽陪杖屨。"]'),
('2ba73d80-c98d-4c2e-98f9-5797c247ee94','晚坐同楊文叔賦','韓維','宋','宋诗','song-poetry','','[]','浮雲忽已沒，仰視天正碧。',48,'全唐诗/poet.song.24000.json','["浮雲忽已沒，仰視天正碧。", "凉風落我庭，燕子飛不息。", "門無車馬賓，巾屨得自適。", "顧慚無所爲，樂此朝與夕。"]'),
('b08898e9-a89c-412a-8739-6e66955cc83c','送樊進士歸寧','韓維','宋','宋诗','song-poetry','','[]','狂風吹飛花，爛漫天地間。',96,'全唐诗/poet.song.24000.json','["狂風吹飛花，爛漫天地間。", "春歸花已歇，遊子亦云還。", "言赴庭闈召，行色已在顔。", "豈在蓬蓽徵，爲子駐征鞍。", "豈無藜與藿，與子共盤餐。", "念子久遊行，歸得義所安。", "及時道當進，爲養祿要干。", "一吟送子詩，感惻淚霑翰。"]'),
('baab1a9d-2d39-459c-bc82-35bfe5555910','鋤園','韓維','宋','宋诗','song-poetry','','[]','上天浩無私，衆草同一榮。',132,'全唐诗/poet.song.24000.json','["上天浩無私，衆草同一榮。", "青青十步間，薰臭相雜并。", "卉藥數不多，十百其品名。", "蔓者善緣附，結陰在高甍。", "修竹雖自立，已復困纏縈。", "其餘叢與株，蕪沒不自呈。", "陰蟲穴其下，日夜百種鳴。", "紛然亂耳眼，我意初不平。", "朝鋤忽以靜，暮雨且復生。", "自念疲病者，莫與地力爭。", "盛衰固物理，安用勞我形。"]'),
('1653bffd-c1cb-4e81-b955-938e96326eda','石蘚','韓維','宋','宋诗','song-poetry','','[]','託根一何潔，冉冉冒幽石。',48,'全唐诗/poet.song.24000.json','["託根一何潔，冉冉冒幽石。", "不學蘿與薜，攀緣走巖壁。", "雲埋曉愈滋，雨洗秋更碧。", "移來色難改，足慰思山客。"]'),
('445c2c07-89b8-4535-a561-3ff2aa106af9','送八哥入都','韓維','宋','宋诗','song-poetry','','[]','驅車望平野，赤日照萬里。',48,'全唐诗/poet.song.24000.json','["驅車望平野，赤日照萬里。", "子行抱痾瘵，無乃困跂履。", "勿爲少別念，且爲會合喜。", "爲我謝親友，黄鵠今舉矣。"]'),
('3365c57e-c3ef-4a6a-8228-3c01425fd150','紅雀集汜水羅者得之云來自新羅與聖俞皆賦','韓維','宋','宋诗','song-poetry','','[]','有翩者微禽，爾類何穰穰。',72,'全唐诗/poet.song.24000.json','["有翩者微禽，爾類何穰穰。", "飽飛檐棟間，千百齊下上。", "幾人習汝見，於命保無枉。", "爾胡丹其質，投翅落異壤。", "殊尤衆所駭，安得免羅網。", "蒼茫海外國，長抱萬里想。"]'),
('6f5f29ac-925a-4fd3-a014-63c5e6fd9562','謝人惠金橘','韓維','宋','宋诗','song-poetry','','[]','開奩拜嘉貺，俯視目已眩。',48,'全唐诗/poet.song.24000.json','["開奩拜嘉貺，俯視目已眩。", "從天落旋星，有客射金彈。", "清香如始摘，佳味不少變。", "寄謝嶺頭人，梅花慚贈遠。"]'),
('ca12be45-bfa2-4f96-92c0-cf3d63afe7b9','孔先生以仙長老山水略錄見約同遊作詩答之','韓維','宋','宋诗','song-poetry','','[]','群峰羅立青巉巉，中有佛廟名香嚴。',336,'全唐诗/poet.song.24000.json','["群峰羅立青巉巉，中有佛廟名香嚴。", "飛泉洶涌出峰後，四時激射喧蒼巖。", "跳珠噴雪幾百丈，下注坎險鍾爲三。", "援蘿俯瞰石底凈，明鏡光溢青瑶函。", "淙流四走渠爲竇，左右吞嚙何其饞。", "緣源散討不知極，但見洞穴爭嶔嵌。", "攀藤直上出雲背，巖戶秘邃疑神緘。", "仰窺陰洞看懸乳，白龍垂鬚正䰐鬖。", "或凝如蓋覆宛宛，或散如指長摻摻。", "有臺高下且十數，如以勢位相臨監。", "平鋪老蘚柔可坐，誰藉綠罽遺不拈。", "北山之石何瑣碎，形制一一如鎸鑱。", "叩之清越諸谷應，不意此地聞韶咸。", "已霜桂樹垂凍壁，未臘梅蕊輝晴嵐。", "浮屠曰仙好事者，奄有勝迹窮搜探。", "書之遠寄龍山下，云此僅止存都凡。", "先生以本來示我，謂我所好同甘鹹。", "相期歷覽在他歲，事高意篤非予堪。", "人生蕭散不易得，常苦世累爲羈銜。", "吾徒幸當治平日，况又無事於牽貪。", "便須巾車不可後，願以几杖從君南。"]'),
('5be3b24c-27fb-424c-bea2-5a177babf421','公孫孝子','韓維','宋','宋诗','song-poetry','','[]','喪期著常數，在古固有之。',108,'全唐诗/poet.song.24000.json','["喪期著常數，在古固有之。", "嗟嗟三季後，禮讓俗亦衰。", "親亡有不葬，况問功與期。", "公孫布衣士，未免寒與饑。", "生兮已不恤，死者吾敢欺。", "孝生因其心，禮大實以時。", "挺然頹俗內，獨以古自爲。", "蕭蕭天平山，松柏有餘悲。", "何以表懿行，刻此無愧辭。"]'),
('34839478-46e3-4ae3-8613-e848efddbe00','下橫嶺望寧極舍','韓維','宋','宋诗','song-poetry','','[]','驅車下峻坂，西走龍陽道。',48,'全唐诗/poet.song.24000.json','["驅車下峻坂，西走龍陽道。", "青烟人幾家，綠野山四抱。", "鳥啼春意閒，林變夏陰早。", "應近先生廬，民風亦淳好。"]'),
('be064bba-ac6c-49b7-a542-939c2ccccaaf','寄題秀州槜李亭','韓維','宋','宋诗','song-poetry','','[]','雲水浩無極，茲亭安在哉。',60,'全唐诗/poet.song.24000.json','["雲水浩無極，茲亭安在哉。", "傳名落人間，猶使塵抱開。", "昔爲干戈地，今以遊觀來。", "物變未始窮，千年一浮埃。", "何時江山秀，曠然當酒杯。"]'),
('d46aa040-a6db-4405-9868-d1c6add05de4','寄家子震寺丞','韓維','宋','宋诗','song-poetry','','[]','商山不可極，跨壓梁與秦。',96,'全唐诗/poet.song.24000.json','["商山不可極，跨壓梁與秦。", "地産富靈藥，巖栖多異人。", "子才老不用，一邑聊庇身。", "方將斂餘閒，煉丹駐形神。", "訪道風雪夕，賞幽芝朮春。", "却顧人間事，輕若履下塵。", "曰予雖世士，心獨靜者親。", "相望在千里，我車何由巾。"]'),
('28112b3f-3b2a-4f93-abaf-e80c5cf0874d','重修西軒席上與弟侄皆賦','韓維','宋','宋诗','song-poetry','','[]','明窗散群帙，於此窮曛朝。',48,'全唐诗/poet.song.24000.json','["明窗散群帙，於此窮曛朝。", "竹色晚逾翠，草芽寒不彫。", "志慚仲舉大，節異淵明高。", "孔門有內樂，願附斯人曹。"]'),
('e57c4960-b1c7-4be4-9cf8-bae552ddd90c','嘉樹','韓維','宋','宋诗','song-poetry','','[]','殘芳不入眼，愛此嘉樹秀。',48,'全唐诗/poet.song.24000.json','["殘芳不入眼，愛此嘉樹秀。", "青雲重欲垂，翠幄遠相鬥。", "輕凉迎早夏，繁影亂清晝。", "茲日更徘徊，聊携一樽酒。"]'),
('9956df1c-9dfe-41b0-91ff-9ca54e2c6980','西園','韓維','宋','宋诗','song-poetry','','[]','西園日修整，竹樹相綴屬。',96,'全唐诗/poet.song.24000.json','["西園日修整，竹樹相綴屬。", "春華猶未敷，氣象鬰函蓄。", "密雨昏遠林，輕寒傍脩竹。", "於此隠几坐，物我同一目。", "弟妹四五人，時來問幽獨。", "我云憂與樂，在志所徇逐。", "無厭萬鍾慊，有道一簞足。", "置是不須議，春醪滿樽綠。"]'),
('306a76a1-15f6-4d69-9e34-8af58daf9fc9','西軒席上探得丁香樹子','韓維','宋','宋诗','song-poetry','','[]','物生各有性，矯之理宜傷。',48,'全唐诗/poet.song.24000.json','["物生各有性，矯之理宜傷。", "如何生微木，揉結始滋芳。", "開花不滿把，瑣碎垂丹黄。", "豈識青桂枝，一引百丈彊。"]'),
('eeecc402-e25b-4798-b25d-407808f3d38d','同陳道原謁象之','韓維','宋','宋诗','song-poetry','','[]','歊炎日爲倦，休駕一瀟灑。',48,'全唐诗/poet.song.24000.json','["歊炎日爲倦，休駕一瀟灑。", "風竹來迎人，翠色欲傾寫。", "神交不前約，至理非外假。", "窅然天地間，誰是忘言者。"]'),
('ec699579-3334-45bb-a907-fefc6c7c5177','答曼叔見寄','韓維','宋','宋诗','song-poetry','','[]','人生風波間，觸事喜乖隔。',144,'全唐诗/poet.song.24000.json','["人生風波間，觸事喜乖隔。", "前君還里中，王事有程格。", "歡言不一再，歸馬已在軛。", "相期高陽秋，叢菊手共摘。", "惟時家多虞，伯氏遭遠謫。", "蒼黄走國門，下馬拜顔色。", "孤舟千日宿，離思日侵迫。", "還家問生事，未免煩計畫。", "自念非世器，身以閑爲職。", "不能高奮飛，有類籠中翮。", "清霜落衆木，諸嶺應更碧。", "行當脫身去，爛醉松下石。"]'),
('720a6fe7-bb59-4b6d-a49c-8f530b91739f','和曼叔昆陽城','韓維','宋','宋诗','song-poetry','','[]','炎精滅無輝，賊莽伺天業。',120,'全唐诗/poet.song.24000.json','["炎精滅無輝，賊莽伺天業。", "帝乘餘運起，一劍無所挾。", "皇天相其怒，雷電助震疊。", "尋邑百萬師，破碎在俄霎。", "開漢中興基，其猶取諸篋。", "千載滍水上，行人指遺堞。", "威靈久不泯，如與耳目接。", "至今古祠上，過者猶惴讋。", "荆蕪起寒色，尚想戰血喋。", "屋瓦無遺處，秋風卷黄葉。"]'),
('7725406c-068e-45f0-878e-2eabacb706bf','治圃','韓維','宋','宋诗','song-poetry','','[]','久雨地氣泄，百草日以滋。',264,'全唐诗/poet.song.24000.json','["久雨地氣泄，百草日以滋。", "勃然翳我圃，積茀不可治。", "遂令蕭艾質，唐突蘭蕙姿。", "鴻鵠不肯下，跳蛙恃而嘻。", "長林困纏繞，蘿蔓鬰四垂。", "青雲避蒙密，白日爲蔽虧。", "久與人迹絕，陰有物怪窺。", "涉秋月既仲，薙人事芟夷。", "援斧一揮拂，榛蕪爲之披。", "俯憐蟻穴亂，坐聽蟲響移。", "濯濯行樹色，涓涓佳菊枝。", "凉風自西來，衆葉光參差。", "牆堵豁已去，南亭見華榱。", "却下走直道，無復蛇虺疑。", "維此峙嘉堋，飲射之所施。", "循玩失前穢，放懷得新怡。", "如昔漢初定，禮法壞不支。", "叔孫剗秦弊，樹茅絕其儀。", "皇皇天子庭，一旦羅尊卑。", "表位肅以整，衣冠紛陸離。", "圃也不足道，拔邪亦由斯。", "作詩試永歌，憤涕下交頤。"]'),
('f4e3f614-e87d-4a19-a434-e934baf54af0','答楊方叔感懷','韓維','宋','宋诗','song-poetry','','[]','吾聞古志人，往往感時節。',72,'全唐诗/poet.song.24000.json','["吾聞古志人，往往感時節。", "所悲非賤貧，要在奮功烈。", "子今才且少，方以藝自拔。", "譬如適萬里，所利輪與轄。", "翻然反虛無，乃與所事別。", "願持君子嘆，勉蹈古人轍。"]'),
('73308259-d418-455f-be29-d32e182ad79c','西軒同諸君探題得食奩','韓維','宋','宋诗','song-poetry','','[]','簡素與夙尚，提携得茲器。',48,'全唐诗/poet.song.24000.json','["簡素與夙尚，提携得茲器。", "春芳席餘紅，夏木蔭初翠。", "酣遊性所適，甘脆略云備。", "獨愧顔氏子，終朝守簞食。"]'),
('16c88723-2ab0-4854-a348-94443724256b','聞鶑','韓維','宋','宋诗','song-poetry','','[]','雨重朱實垂，風生綠陰亂。',48,'全唐诗/poet.song.24000.json','["雨重朱實垂，風生綠陰亂。", "珍禽何所來，清響千萬變。", "先鳴如有得，欲去不無戀。", "誰與緩哀弦，林間寫幽囀。"]'),
('d0bf06da-e4dc-45dc-9d0f-e8cd8c138a09','西軒欲雨同諸君偕賦','韓維','宋','宋诗','song-poetry','','[]','輕雷隠何山，雲色如黛涌。',48,'全唐诗/poet.song.24000.json','["輕雷隠何山，雲色如黛涌。", "凉滿翠竹浮，陰連芳樹重。", "煩襟一披豁，清思欲飛動。", "會待急雨來，華觴與君捧。"]'),
('8c373486-7623-4f25-858b-bcca556c6e1b','擬杜子美體賦夏日閒居三章  其一','韓維','宋','宋诗','song-poetry','','[]','階前萱草開丹花，竹根亂笋生如麻。',40,'全唐诗/poet.song.24000.json','["階前萱草開丹花，竹根亂笋生如麻。", "幽居無言感物華。", "衡門流亂車馬絕，繞舍閣閣喧鳴蛙。"]'),
('8ac7005c-748c-4021-889d-4fdda6d3c677','擬杜子美體賦夏日閒居三章  其二','韓維','宋','宋诗','song-poetry','','[]','何所爲樂夏日閒，手把內篇卧且觀。',40,'全唐诗/poet.song.24000.json','["何所爲樂夏日閒，手把內篇卧且觀。", "香氣氤氳滿簾間。", "圓荷貼水雨打亂，青蔓挂壁風吹寒。"]'),
('3cdca437-1b8b-4982-ba5d-1c247733cff1','擬杜子美體賦夏日閒居三章  其三','韓維','宋','宋诗','song-poetry','','[]','鄰家芳樹牆頭垂，群鴉引兒日夜啼。',40,'全唐诗/poet.song.24000.json','["鄰家芳樹牆頭垂，群鴉引兒日夜啼。", "驅之稍去還滿枝。", "我初厭鴉撓吾靜，聽之既久理亦齊。"]'),
('62edd14f-61ad-4127-b85a-6a88d46d753e','夏日覽物思古人三首 張仲蔚','韓維','宋','宋诗','song-poetry','','[]','棄置當世事，覃思天官書。',36,'全唐诗/poet.song.24000.json','["棄置當世事，覃思天官書。", "蓬蒿長沒人，寂寞守園廬。", "軒冕非所慕，賦詩常晏如。"]'),
('084ae48e-9614-467e-8ca0-421770ca085e','夏日覽物思古人三首 嵇康','韓維','宋','宋诗','song-poetry','','[]','翛然柳下鍛，豈不遺世喧。',36,'全唐诗/poet.song.24000.json','["翛然柳下鍛，豈不遺世喧。", "一忤貴公子，鳴弦竟誰冤。", "性烈才且雋，有味孫登言。"]'),
('acf83a21-ee84-4ee0-b24a-6089dc20654e','夏日覽物思古人三首 陶潛','韓維','宋','宋诗','song-poetry','','[]','衆鳥依嘉樹，想像先生居。',36,'全唐诗/poet.song.24000.json','["衆鳥依嘉樹，想像先生居。", "日哦高簡篇，濁酒自爲娛。", "世事不挂口，方且愛吾廬。"]'),
('6587c1ef-e778-40fb-8362-95540a13eb68','仲夏田家','韓維','宋','宋诗','song-poetry','','[]','仲夏農務急，老壯紛盈疇。',108,'全唐诗/poet.song.24000.json','["仲夏農務急，老壯紛盈疇。", "上天無愆沴，登我蠶與麰。", "晨興腰鐮出，子婦向田頭。", "綠樹繞阡陌，當晝豈暇休。", "柔絲繅滿盆，新實已可羞。", "歸來一歡笑，卒歲期無憂。", "爲民各有業，處世無異謀。", "但願歲嘗然，囷廩有乾糇。", "糟床注濁酒，鄰里日相求。"]'),
('afaebe6c-724a-4a7d-9a3b-1792c0eb56d4','鋤園寄京師友人','韓維','宋','宋诗','song-poetry','','[]','荷鋤中園立，飛雨灑清朝。',84,'全唐诗/poet.song.24000.json','["荷鋤中園立，飛雨灑清朝。", "黄鸝何處來，百囀繞林梢。", "感彼求友聲，慨然念吾交。", "煌煌天子都，賢俊相與遨。", "飄飄翔華纓，蹀蹀鳴金鑣。", "良時足遊行，高會自招邀。", "誰念張仲蔚，寂寞守蓬蒿。"]'),
('4fdbfedb-fbf3-4001-8b3a-8f65c58bf560','遊城南雙塔寺','韓維','宋','宋诗','song-poetry','','[]','軻峨郭南門，臺殿壓長路。',120,'全唐诗/poet.song.24000.json','["軻峨郭南門，臺殿壓長路。", "青林四回合，飛鳥不得度。", "房掩僧獨禪，庭喧鴉正哺。", "高蘿走蒼柏，丹花下垂布。", "中園饒佳果，結子滿朝露。", "久從城邑居，樂與清境遇。", "坐聽百禽響，日晏不忍去。", "微雨西北來，颯爽動林莽。", "歸鞅一回首，孤剎屹當午。", "終期濯凉風，杖策縱高步。"]'),
('2aadaeaf-2010-4095-a92e-b4094a3a9bd0','送催綱弟及蘇支使甥','韓維','宋','宋诗','song-poetry','','[]','養痾屬南夏，日夕偃茅衡。',120,'全唐诗/poet.song.24000.json','["養痾屬南夏，日夕偃茅衡。", "足音良可喜，况我弟與甥。", "清風敞閒館，竹樹藹前楹。", "一展親愛歡，觴斝屢云傾。", "高論文史間，或以政理并。", "念子始服官，王事自有程。", "啟告豈憚煩，期不墜厥聲。", "簡書有常畏，冒暑各言征。", "雖非遠別離，要使愴我情。", "還歸掩扉坐，華月林上明。"]'),
('5acda281-f658-4c29-a64c-4e4b07448769','同陳太丞遊龍興寺經藏院','韓維','宋','宋诗','song-poetry','','[]','空堂灑寒水，碧楸凉漠漠。',72,'全唐诗/poet.song.24000.json','["空堂灑寒水，碧楸凉漠漠。", "高眠得珍簟，委棄巾與屩。", "薰風穆然來，殿角鳴金鐸。", "清香有時聞，幽鳥無聲落。", "論詩愛平淡，語道造沖寞。", "非吾方外友，誰當共茲樂。"]'),
('a10a72e3-cb68-409f-8545-60ebbfba0a36','和晏相公西湖','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鳴蟬忽以急，夏景晏林塘。',144,'全唐诗/poet.song.24000.json','["鳴蟬忽以急，夏景晏林塘。", "不知何山雨，颯然送微凉。", "荷茭忽翻倒，四散飄暗香。", "清渠决决流，碧色浸稻秧。", "零落墮林實，瑣碎開水芳。", "公來必乘晚，散步方徜徉。", "簫鼓不從後，筆牘常在旁。", "游魚自成族，飛鳥不亂行。", "周覽時景佳，郁穆發新章。", "何意蓬蓽士，傳貺謬所當。", "時方苦炎暵，汗下揮其滂。", "三復大雅作，清風肅衣裳。"]'),
('ea264896-5431-4778-a488-f262e68ac590','崔象之過西軒以詩見貺依韵答賦','韓維','宋','宋诗','song-poetry','','[]','春陽入我圃，窗戶弄喧景。',144,'全唐诗/poet.song.24000.json','["春陽入我圃，窗戶弄喧景。", "幽池明可鑒，翠竹列如屏。", "折枯呈紫莖，掊墳見紅穎。", "端居閱時序，人事謝參省。", "生才不濟世，不如守閭井。", "聊慕莊氏說，處陰以休影。", "興來讀我書，興盡煮吾茗。", "崔侯乃同好，每見輒自警。", "守道心常晏，感時嘆屢永。", "邊隅事未寧，豪俊當馳騁。", "西麾覆妖巢，北指斷凶頸。", "既非二者任，且復安吾靜。"]'),
('17e4b696-8e5f-439b-b1aa-08fdd98563b1','別曼叔','韓維','宋','宋诗','song-poetry','','[]','歲晏多感慨，况復餞之子。',48,'全唐诗/poet.song.24000.json','["歲晏多感慨，况復餞之子。", "騰裝指近邑，弭蓋眷同里。", "日薄古原樹，天寒石橋水。", "毋爲少別念，春風候車軌。"]'),
('490d810a-ace6-489e-bd49-aa36a713228a','和晏相公湖上遇雨','韓維','宋','宋诗','song-poetry','','[]','公堂日多暇，薄暮遊清池。',156,'全唐诗/poet.song.24000.json','["公堂日多暇，薄暮遊清池。", "孤雲從西來，若與雲蓋期。", "急雨亂荷芰，紅綠左右披。", "沙禽带濕起，簇簇守前坻。", "烟樹晦空曲，蟬聲寂無遺。", "殘炎一洗濯，霽影開林西。", "禽飛還清波，蟬噪復故枝。", "晚槿揚朱華，秋草含碧滋。", "篙舟出堤去，微風滿平猗。", "卷幔極長望，止見隗與箕。", "舉酒無塵情，慨然起遐思。", "永懷古先訓，默蹈通介宜。", "乃知賢哲心，所得非遊嬉。"]'),
('4ab4bb33-3ed3-4030-b7f2-804c505182d1','答曼叔見寄','韓維','宋','宋诗','song-poetry','','[]','日君同里閭，杖履數相過。',198,'全唐诗/poet.song.24000.json','["日君同里閭，杖履數相過。", "靡爲不吾咨，有唱必君和。", "春風南陌遊，炎月北窗卧。", "貪從德義樂，不覺歲月破。", "而君宦遊者，動足落羈鎖。", "襄城雖近邑，去局有重坐。", "子來誠獨難，我往義當果。", "時天雨方霽，綠樹垂{禾袲}{禾袲}。", "策馬望城郭，青山映烟火。", "解衣塵慮清，垂箔月華墮。", "憐君九品賤，志尚勇不挫。", "乃云曹事簡，經史日自課。", "出詩且百篇，語法就平妥。", "相別不滿歲，美譽亦已播。", "顧慚糠秕姿，幾不見揚簸。", "投章匪云報，亦用警庸懦。"]'),
('675f6679-0e54-410b-a0b4-34bd0d6ad770','觀飼魚','韓維','宋','宋诗','song-poetry','','[]','群魚戲清川，容貌甚融易。',120,'全唐诗/poet.song.24000.json','["群魚戲清川，容貌甚融易。", "投餌落其間，紛爭忽無次。", "其來若有召，貪吻動如沸。", "波間互出沒，似亦夸巧智。", "警跳鱗迸雪，飽泳尾摇翠。", "安知滄海外，五犗不可致。", "幸逢觀者仁，不與鈎網值。", "莊生昔濠上，嘗嘆天理遂。", "利心一以發，所向固多累。", "我觀雖有殊，我得豈云異。"]'),
('33b9b3b9-33a5-4c82-9e0b-7cd0876b77f1','答象之謝惠黄精之作','韓維','宋','宋诗','song-poetry','','[]','仙經著靈藥，茲品上不刊。',192,'全唐诗/poet.song.24000.json','["仙經著靈藥，茲品上不刊。", "服之歲月久，衰羸反童顔。", "巖居有幽子，乘時劚蒼山。", "溪泉濯之潔，秋陽暴而乾。", "九蒸達晨夜，候火不敢安。", "持之落城市，誰復著眼看。", "富貴異所嗜，口腹窮甘酸。", "貧賤固不暇，錐刀乃其干。", "坐使至靈物，委棄同草菅。", "惟君沖曠士，敦然守高閒。", "食之易爲力，天和中自完。", "故以此爲饋，其容幾一簞。", "報我三百言，浩浩馳波瀾。", "何以喻珍重，如獲不死丹。", "方當煩燠時，把玩毛骨寒。", "他年靈氣成，與子驂雙鸞。"]'),
('aebe2f1a-5896-4da0-a824-8194508f7caf','奉和象之夜飲之什','韓維','宋','宋诗','song-poetry','','[]','淫陰泄爲雨，十日瀉不停。',288,'全唐诗/poet.song.24000.json','["淫陰泄爲雨，十日瀉不停。", "蓬蒿長四壁，濁潦流縱橫。", "嗷嗷鶴群遊，閣閣蛙亂鳴。", "端居積幽抱，沈鬰久未平。", "是時俯幾望，月魄嚮已盈。", "浮雲失四顧，孤輪午亭亭。", "微風濯炎熱，衣巾凜餘清。", "起我不暇懶，超遥步前庭。", "煩憂忽以去，曠如出幽囹。", "顧謂汝妻子，速具煎炮烹。", "同里四五人，予期得邀迎。", "隨時具蔬果，飣餖甘與青。", "雖無水陸珍，亦足侑杯觥。", "所期在乘興，豈問多品名。", "諸君於我厚，匪貌實以情。", "從容談笑間，蕩不見府城。", "肴來必虛反，觴至無留行。", "豈惟清言勝，或以善謔并。", "高風揖巢許，曠論齊殤彭。", "不知軒冕貴，直以道義榮。", "置身豈非德，撫事臨若驚。", "上天作陰沴，降水災吾氓。", "芒芒郊野外，浩若翻滄溟。", "垣廬隨波盡，稼穡安有成。"]'),
('3998d157-4fe0-40cd-93f5-c3654bbf76de','同曼叔遊高陽山','韓維','宋','宋诗','song-poetry','','[]','久聞高陽勝，近在汝州側。',228,'全唐诗/poet.song.24000.json','["久聞高陽勝，近在汝州側。", "跂予三年望，我願今卒獲。", "烟雲函兩山，臺殿開半壁。", "解鞍高林下，仰視怯登陟。", "蒼松盤老枝，矯矯入檐隙。", "微風韵其上，落耳寒惻惻。", "枇杷兩高樹，中國所未識。", "葉間青實駢，大與蜀土敵。", "我來暮暮後，花草已狼籍。", "不見躑躅紅，西巖向人碧。", "出門步榛薈，微逕不可索。", "援籬下幽澗，剝蘚題蒼石。", "鳥啼無定音，虎鬥有遺迹。", "石臺平挺挺，野竹瘦歷歷。", "主人尉下邑，奔走困符檄。", "喜我蕭散人，幽奇共搜剔。", "息陰時一憩，貪勝還自力。", "歸時山氣冷，草露濕遊屐。", "舉手謝峰巒，高秋復來覿。"]'),
('dd5aa2e4-5495-49ce-a5eb-055a17caa345','同曼叔遊菩提寺','韓維','宋','宋诗','song-poetry','','[]','高城如破崖，寺带喬木古。',60,'全唐诗/poet.song.24000.json','["高城如破崖，寺带喬木古。", "禪房掩清晝，佛畫剝寒雨。", "荒池野蔓合，濁水佳蓮吐。", "蕭條聯騎遊，淡薄對僧語。", "秋風日夕好，勝事從此數。"]'),
('ff9b1213-7089-4462-ae05-36fb4783c51e','遊漢高帝祠','韓維','宋','宋诗','song-poetry','','[]','平橋架荒塹，東上大岡尾。',108,'全唐诗/poet.song.24000.json','["平橋架荒塹，東上大岡尾。", "岡頭古木合，有廟蔭其底。", "攝衣升殿墀，龍顔儼當位。", "蝙飛畫帳喧，鼠嚙珠旒墜。", "不知誰來祀，狼籍樽與簋。", "殘碑壓鰲背，上有太和字。", "去此數百載，文剝失所次。", "伊人昔經構，視漢猶視彼。", "徘徊懷古意，日暮悲風裏。"]'),
('a79c143f-cdae-497a-b75e-e2fc7bd3c4e5','和崔象之潁橋觀贈陳清臣太丞兼簡陳','韓維','宋','宋诗','song-poetry','','[]','崔侯朝從西邑歸，面有矜色口且咨。',128,'全唐诗/poet.song.24000.json','["崔侯朝從西邑歸，面有矜色口且咨。", "云得高士陳其姓，非向可見所庶幾。", "嘗登於朝最吏課，一旦去之心甚怡。", "潁陽古觀三日語，坐見月出青松枝。", "深窮性命識原本，論議純一無瑕疵。", "周通旁暢未始極，曾不與道相乖違。", "陳雖平生所未識，以子而譽信不疑。", "向風長想日復夜，膏車秣馬吾其西。"]'),
('1b93c405-5fd2-4331-8e17-c92733f32a03','早登襄城之龍山呈曼叔','韓維','宋','宋诗','song-poetry','','[]','鳥啼齋前樹，促駕吾當西。',60,'全唐诗/poet.song.24000.json','["鳥啼齋前樹，促駕吾當西。", "朝從良友別，夕赴幽人期。", "方以會合喜，敢曰道路疲。", "予戇昧時利，百事棄不爲。", "惟有好賢心，未愧緇衣詩。"]'),
('200424b2-53bb-4cf3-b549-a0134238fd41','遊首山夜歸馬上作','韓維','宋','宋诗','song-poetry','','[]','蒼巖出幾曲，此與大道會。',48,'全唐诗/poet.song.24000.json','["蒼巖出幾曲，此與大道會。", "回看燈火處，已在林蘿外。", "凉風生雨氣，清月動山靄。", "漸近平橋路，淙淙聞石瀨。"]'),
('bdd3a7bf-9d2b-4bed-9fbd-f6fdd4c1c444','泛汝聯句','韓維','宋','宋诗','song-poetry','','[]','平居厭城郭，具舟泛清汝。',288,'全唐诗/poet.song.24000.json','["平居厭城郭，具舟泛清汝。", "藍光一水遠，鐵色兩崖古。", "日華動中流，沙紋亂前渚。", "湍鳴達公橋，草綠襄王墓。", "園英擁流沫，風葉墮殘雨。", "停橈弄山泉，扶杖過花塢。", "澄潭數亂石，斷石橫顛樹。", "泳波魚鬣舒，闖穴蛙首怒。", "衝雲一雁遠，唼荇群鷗聚。", "村間桑柘春，川闊牛羊暮。", "回頭綠樹失，卷幔青峰露。", "尋幽恣盤桓，泊淺屢回互。", "靈草不知名，珍禽啼在處。", "夕陽散鳴鳩，荒阡拱游兔。", "挽纜謠歌童，簪花立田婦。", "高歌客自如，歸涉人相負。", "青蒲戢戢生，紫燕翩翩度。", "雲烟波底明，井邑林外睹。", "欣逢閭里舊，愧乏鷄黍具。", "抰水薦抸鱗，掘石羞山茹。", "繞塘梅實綠，冒桂禽殻素。", "我巾聊一頹，石榼煩屢注。", "朱櫻出芳林，紫笋侑雕俎。", "高篇爛珠璧，至樂謝鐘鼓。"]'),
('342e5fa7-274b-483a-9cad-7e29ddc9b081','和曼叔靈樹相別','韓維','宋','宋诗','song-poetry','','[]','男兒易爲別，尋尺固可輕。',60,'全唐诗/poet.song.24000.json','["男兒易爲別，尋尺固可輕。", "今日摻子祛，悽惶不自平。", "豈其道里遠，要是隔音形。", "春風卷行迹，車馬無留征。", "回首高陽峰，隠約林間明。"]'),
('f358b4a0-7a41-45e0-ae16-ccb61fa15dbf','朝發靈樹寄曼叔師厚','韓維','宋','宋诗','song-poetry','','[]','朝發靈樹東，曠野陰氣積。',216,'全唐诗/poet.song.24000.json','["朝發靈樹東，曠野陰氣積。", "驅馬入草間，左右號鸛鷁。", "重雲黕玄幕，孤月隠白壁。", "欹危涉塗淖，轉側緣溝脈。", "凉風滿川陸，眺覽多所適。", "却想會合樂，轉首已成昔。", "諸君豪俊士，經訓飽搜昋。", "上下古與今，抗論堅莫敵。", "顧我處其間，傾聽但跼蹐。", "校士豈所當，直以氣類得。", "譬如禮天壇，珪璧奠且植。", "陶匏以其質，并列不爲惑。", "論心見表暴，吐口出白黑。", "朝案每共飲，夜床仍抵迹。", "嘲諧間一發，清笑高啞啞。", "自謂得如此，至死無厭斁。", "敢於百里間，而憚轡與策。", "因詩謝所思，酬篇無我默。"]'),
('4cc6dfb7-1f88-4daf-b15b-cb6746f868b0','發襄城寄曼叔','韓維','宋','宋诗','song-poetry','','[]','別離何從生，乃生歡愛間。',48,'全唐诗/poet.song.24000.json','["別離何從生，乃生歡愛間。", "一登君子堂，笑語十日連。", "薄暮躍馬去，飄忽如雲烟。", "毋言歡戚殊，世事舉皆然。"]'),
('0991af84-b8df-424c-80bb-723df390e673','滍城','韓維','宋','宋诗','song-poetry','','[]','駸駸二三騎，南并橫山去。',204,'全唐诗/poet.song.24000.json','["駸駸二三騎，南并橫山去。", "山窮遠川出，始見滍陽樹。", "荒城蘿蔦合，表裏無寸土。", "但聞鳥啼聲，不見鳥啼處。", "呼兒開棘扉，掃榻坐茅廡。", "清泉給盥濯，凉風生仰俯。", "濁醪稍似佳，山果來近圃。", "始酌薰然和，中飲淡無慮。", "案頭羲皇經，編絕幾見補。", "先生發其微，大義談四五。", "紛攘自諸家，簡易獨太古。", "形骸非我有，冠带尚誰取。", "道存固匪外，兩致默與語。", "是時季春望，山月夕已吐。", "清光出深竹，葉上露如雨。", "寒侵毛骨生，思有煙霞舉。", "却念人世間，紛紛何足數。"]'),
('19355cad-88f0-4031-afbe-78d2d5e7a429','九日客散西軒','韓維','宋','宋诗','song-poetry','','[]','窮閻車馬散，默坐弔孤影。',48,'全唐诗/poet.song.24000.json','["窮閻車馬散，默坐弔孤影。", "烟生竹町深，月出茅廬靜。", "道存輕外物，心寂喪前境。", "即此之吾生，安知慕箕潁。"]'),
('8f883b54-8c06-4e5f-964f-deda65a25c98','晚過象之葆光亭步月','韓維','宋','宋诗','song-poetry','','[]','浮沉閭里間，放志謝維縶。',48,'全唐诗/poet.song.24000.json','["浮沉閭里間，放志謝維縶。", "行貪月色靜，歸犯霜華濕。", "寒鼓出城重，飛星過樓急。", "却想竹亭下，主人猶獨立。"]'),
('0966916d-84eb-4644-b348-dba78c0a9cb5','曉出郊過方秀才舍飲','韓維','宋','宋诗','song-poetry','','[]','浮雲散朝陰，初日動晴煦。',48,'全唐诗/poet.song.24000.json','["浮雲散朝陰，初日動晴煦。", "行隨風葉遠，去傍田家路。", "人間無遽色，馬緩有安步。", "遥識主人舍，青帘出霜樹。"]'),
('abe56aff-40a3-45a1-86d1-cdcd5bc8a34c','潁橋路中別曼叔','韓維','宋','宋诗','song-poetry','','[]','磷磷清潁流，中截兩崖斷。',72,'全唐诗/poet.song.24000.json','["磷磷清潁流，中截兩崖斷。", "架橋在城底，斗出曠平漫。", "陰風無邊來，左右篷驚轉。", "我行感時節，跋馬重爲戀。", "雖非遠別戚，所恨良會散。", "却想置酒地，松陰野色晚。"]'),
('0475f81d-e47f-4e5f-a145-7e159b0ff4c2','送寧極還山','韓維','宋','宋诗','song-poetry','','[]','晨冰結車轍，朔野風正厲。',144,'全唐诗/poet.song.24000.json','["晨冰結車轍，朔野風正厲。", "君行良亦勤，正與苦寒值。", "超然出門去，曾不顧我議。", "譬如雲飛鴻，勢不受維縶。", "開籠恣其往，萬里在展翅。", "場功十月畢，田家足豳事。", "兒童樵牧歸，荆扉寂已閉。", "燃薪燭茅屋，并坐侄與弟。", "自愛村醪熟，或以山鹿饋。", "凍蔬劚青黄，寒藥煮根柢。", "從容溫飽間，萬事一無累。", "嗟予不得往，注目雲接地。"]'),
('7c2b755e-8098-4537-a5be-7e3fdda1bd08','雪中招象之','韓維','宋','宋诗','song-poetry','','[]','愁雲合無迹，密雪集冬仲。',108,'全唐诗/poet.song.24000.json','["愁雲合無迹，密雪集冬仲。", "狂翻寒空來，微泛與風弄。", "打窗驚暮急，壓竹愛宵重。", "明缸照狹室，簾押寂不動。", "環爐四五人，頗喜清談縱。", "崔侯著閒默，門外車轍凍。", "徘徊一堂裏，有類繭已蛹。", "濁醪誰與酌，短褐應自擁。", "何當策疲馬，清賞聊一共。"]'),
('2c463697-579a-438b-9246-d6c44c263f81','晚步潁上和曼叔','韓維','宋','宋诗','song-poetry','','[]','披榛登大堤，下視何嶪岌。',48,'全唐诗/poet.song.24000.json','["披榛登大堤，下視何嶪岌。", "野氣忍雪潤，河流带冰澀。", "沙禽寂不飛，行子暮逾急。", "不見洗耳人，悲風吹獨立。"]'),
('d510c2ee-2d33-4c68-8273-45df8a8b0eaa','和曼叔賦斷蓬見別','韓維','宋','宋诗','song-poetry','','[]','霜蓬飛無根，歲暮隨驚風。',48,'全唐诗/poet.song.24000.json','["霜蓬飛無根，歲暮隨驚風。", "翻翻走寒野，日以去故叢。", "譬如遠遊子，飄泊從西東。", "一感潁上別，慨嘆發予衷。"]'),
('382b7a75-b592-40d1-866a-ce5d81bfc292','雪後觀潩水','韓維','宋','宋诗','song-poetry','','[]','微陽動泉脈，遠水來渙渙。',48,'全唐诗/poet.song.24000.json','["微陽動泉脈，遠水來渙渙。", "斜日著底明，輕冰隨處斷。", "清函竹陰碎，綠與波紋亂。", "安得解扁舟，窮源事幽觀。"]'),
('6767072d-1a87-4c9a-b04e-3946c18b0cd4','步月','韓維','宋','宋诗','song-poetry','','[]','初陽奪殘凜，和氣不待春。',72,'全唐诗/poet.song.24000.json','["初陽奪殘凜，和氣不待春。", "况茲華月白，光彩清路塵。", "整我巾與屨，迢遥步城闉。", "仰觀衆星色，收芒避孤輪。", "虛無一境間，豈復知吾身。", "嗟哉御風者，有待奚足珍。"]'),
('d04e0226-57a8-4357-9d65-6e20c8cdf4ac','答曼叔見謝潁橋相過之什','韓維','宋','宋诗','song-poetry','','[]','潁川今古賢豪多，後生繼者爲誰何。',384,'全唐诗/poet.song.24000.json','["潁川今古賢豪多，後生繼者爲誰何。", "吾交曼叔少挺出，力自樹立非由它。", "潛心直欲到聖處，論議不避况與軻。", "讀書下筆知所趣，崇樹蘭茝遺蒿莪。", "軒昂頭角事高大，肯與世俗同其波。", "一從得官坐山縣，有如鷙鳥著網羅。", "朝符暮檄困奔走，尚畏官長來誅訶。", "時時矯首塵埃下，窺睹風月偷吟哦。", "我憐軼才就羈絆，歲一往視無蹉跎。", "扁舟遠放汝水岸，濁酒暮醉高陽阿。", "前時捧牒來潁上，謹視斂糴譏奸訛。", "官曹寂寞古寺冷，况復朔雪飛傞傞。", "馳書里中二三友，固要以義當予過。", "星言整駕夕已至，霜橋晚渡冰峨峨。", "燃薪暖我頻飲我，斟酌脯醤調鹽鹺。", "傾壺舉觴紛左右，客飽而笑君顔酡。", "危然正論中法義，豆籩羅列陳象犧。", "嘲俳乘醉忽以發，駛如鑿水放九河。", "哀弦孤引四坐寂，繼以簫笛相諧和。", "先生久與人迹絕，心如止水形枯柯。", "忽警此樂非外奬，不覺撫手促而歌。", "歸銜絡馬屢見奪，欲去未忍還婆娑。", "空堂想見別後意，一燈夜守陳編哦。", "興來落紙成大句，勢欲李杜相凌摩。"]'),
('5de3b64e-c60e-4058-94ce-9c20f9d41fc3','答曼叔惠小松之什','韓維','宋','宋诗','song-poetry','','[]','蒼蒼首山顛，偃蹇老松亞。',72,'全唐诗/poet.song.24000.json','["蒼蒼首山顛，偃蹇老松亞。", "清露落其實，翠鬣幽石罅。", "故人知我好，移種及茅舍。", "誰謂爾幹微，千尺自拱把。", "生雖春草齊，氣與凡木謝。", "欲知瀟灑力，來對風月夜。"]'),
('54a57e17-fced-43cd-97fb-0514215a5f9e','答辛子莊惠梅花之什','韓維','宋','宋诗','song-poetry','','[]','東風雪飛度清淮，淮邊野梅撩亂開。',80,'全唐诗/poet.song.24000.json','["東風雪飛度清淮，淮邊野梅撩亂開。", "想君此時駐征騎，題詩折花思悠哉。", "緘封千里到此地，桃杏芳意都未回。", "嶺頭奇艷忽照眼，不待驛使傳枝來。", "清香滿把愧佳贈，欲賦豈敢空銜杯。"]'),
('79c67244-a9a6-4dcf-b7ea-2a738bf082c9','和曼叔憩永惠院','韓維','宋','宋诗','song-poetry','','[]','立春月在季，我時如滍皋。',96,'全唐诗/poet.song.24000.json','["立春月在季，我時如滍皋。", "驚風揚紅塵，頗有行役勞。", "自駭茲剎勝，願言憩驂鑣。", "前對高花繁，後視萬竹交。", "虛堂坐閒敞，我轄忘載膏。", "聞君戾止日，飛雨正蕭條。", "佳景忽在眼，恍如隔晨朝。", "一吟竹邊句，清思靄餘飄。"]'),
('368e0f73-f77c-40e5-be60-3330d69bddea','謝元道惠桂樹子','韓維','宋','宋诗','song-poetry','','[]','洛陽奇卉兼四方，妖姿冶艷爭春陽。',112,'全唐诗/poet.song.24000.json','["洛陽奇卉兼四方，妖姿冶艷爭春陽。", "蔚然幽佳獨凌霜，中巖無人閟寒芳。", "山翁窮搜劚青蒼，名園得之爲輝光。", "護以雕闌面朱堂，葉敷瑶碧丹華揚。", "我今蓬茨蔽短牆，愧爾佳植空埋藏。", "騷人托辭興端良，辱贈顧德豈所當。", "角弓之詩不敢忘，與君歲暮揚芬香。"]'),
('2f4bd426-b623-4752-b11d-2294d3bc1de3','同魏進道晚過湖上','韓維','宋','宋诗','song-poetry','','[]','春風湖上泮，奈此凈綠何。',108,'全唐诗/poet.song.24000.json','["春風湖上泮，奈此凈綠何。", "平堤看瀲灧，皎如鏡新磨。", "支流別而東，下走萬玉珂。", "俜俜橋邊柳，芳芽綴柔柯。", "中洲嘉卉繁，條甲亦以羅。", "遊禽接翅羽，沉沉鳴聲和。", "避人去稍遠，盤空落還多。", "我來日已暮，佇視其頃俄。", "羨爾禽類微，終年樂清波。"]'),
('876fd17c-a4ca-4c7e-b53b-dfbb659d33b8','仲連兄治南堂','韓維','宋','宋诗','song-poetry','','[]','予生乏時用，惟懶性所便。',168,'全唐诗/poet.song.24000.json','["予生乏時用，惟懶性所便。", "强輓亦已退，雖鞭詎能前。", "有園不盈畝，正在居南偏。", "荒埋日失治，坐惜嘉觀捐。", "伯氏解官守，燕居此回旋。", "芟蕪屬時暇，斫枯候春妍。", "面堂一徑直，夾樹蘭與荃。", "畚土藝佳卉，沼盆注清泉。", "東風過牆頭，朱白爭繁鮮。", "芬香四飄散，蝶蜂來飛翾。", "向時疏懶人，游步始連連。", "微勤不少施，勝賞得以專。", "才勞拙者逸，此固物理然。", "作詩代俳笑，以繼南華篇。"]'),
('370210e4-f8bc-4c18-9774-d43d5e349c9a','南堂席上賦得花樹子','韓維','宋','宋诗','song-poetry','','[]','春風日暮急，薄寒生小苑。',48,'全唐诗/poet.song.24000.json','["春風日暮急，薄寒生小苑。", "群英不我遺，并坐慰幽蹇。", "歡來引觴酌，快甚瓴水建。", "才非孔文舉，坐愧客常滿。"]'),
('ca8543e0-cd51-4db6-be9d-418e8c0e9c16','送子華兄辭家後還都','韓維','宋','宋诗','song-poetry','','[]','春鳩鳴桑間，初日動原隰。',48,'全唐诗/poet.song.24000.json','["春鳩鳴桑間，初日動原隰。", "馬踏露草嘶，人對松風泣。", "茅廬耿夕返，金闕想晨入。", "回首別袖遠，惟見飛花急。"]'),
('ac342493-2b8d-4aca-94c2-88392aae5676','同子華兄象之宿資福院','韓維','宋','宋诗','song-poetry','','[]','風塵暗西郊，野寺欣稅鞅。',48,'全唐诗/poet.song.24000.json','["風塵暗西郊，野寺欣稅鞅。", "虛堂清氣肅，偃仰百骸放。", "至道本自簡，欲語不可强。", "夜深松檜寂，明月皎相向。"]'),
('a9345dc3-618c-455a-a0b7-cc0de5c76c49','三月十三日遊卞氏園','韓維','宋','宋诗','song-poetry','','[]','窄徑下深竹，有堤平若席。',48,'全唐诗/poet.song.24000.json','["窄徑下深竹，有堤平若席。", "開樽蔭密樹，正見溪水碧。", "游魚出柳根，翕忽無定迹。", "酒行不須遽，月色林上白。"]'),
('938de3fc-6590-47ad-9918-7f77a0174c07','贈在己上人','韓維','宋','宋诗','song-poetry','','[]','人生天地間，萬物同一理。',60,'全唐诗/poet.song.24000.json','["人生天地間，萬物同一理。", "子今名已是，智要獨在己。", "乞詩東南歸，固已謝塵滓。", "東南美林壑，佛剎凈如水。", "勉當窮吾言，將有大於此。"]'),
('1dc65979-b8e9-4b46-a53f-a0fe78bea4b7','聽琴','韓維','宋','宋诗','song-poetry','','[]','達士寡世慕，至音遺俗彈。',48,'全唐诗/poet.song.24000.json','["達士寡世慕，至音遺俗彈。", "一聞正始奏，坐使太古還。", "殘雪照樽酒，晴陽挂檐端。", "曲罷了無得，清松空自寒。"]'),
('8dc04b8e-0780-4e36-8a69-9d343f82a1d7','南溪','韓維','宋','宋诗','song-poetry','','[]','長林拂雲根，一逕絕城腹。',180,'全唐诗/poet.song.24000.json','["長林拂雲根，一逕絕城腹。", "荆扉带翠樾，斗下地愈束。", "清溪自南來，勢抵北崖曲。", "清平水流漫，東去入脩竹。", "境幽百物遂，魚鳥得所欲。", "况依仁者居，不與鈎彈觸。", "有如嘉賓至，相與娛聽囑。", "鳥飛鳴我傍，魚泳出深淥。", "薄暮登前岡，四顧山在目。", "雨滋春稼繁，風動野花馥。", "達人樂天性，不待外物足。", "遂令茲地勝，久不事營築。", "顧我指崖下，秋當結茅屋。", "渠波環古臺，輦石坐幽澳。", "霜前復來觀，兔肥山酒熟。"]'),
('02fcf799-6923-40e8-b107-7a9f6bcaf86c','陪寧極回馬上作','韓維','宋','宋诗','song-poetry','','[]','我有龍陽約，垂駕輒復停。',156,'全唐诗/poet.song.24000.json','["我有龍陽約，垂駕輒復停。", "念與高士期，不宜後其行。", "春風三月尾，澗谷花草明。", "尋花踏幽草，南出山脚青。", "婆娑一古樹，是曰先生庭。", "館我茅檐下，山瓢日夕傾。", "摘林飣朱實，掘竹羞紫萌。", "朝聽谷禽響，夜對山月清。", "高論簡以正，疏懷淡無營。", "徒知服深遠，難用一善名。", "維也少頑鈍，幾爲世網嬰。", "一親德義游，頗見外物輕。", "門牆倘可依，他時來執經。"]'),
('f3305c4d-34a1-482f-9c84-15ef67cec070','九日高會有懷寧極','韓維','宋','宋诗','song-poetry','','[]','親賓過我舍，置酒樂嘉節。',48,'全唐诗/poet.song.24000.json','["親賓過我舍，置酒樂嘉節。", "不見箕山人，坐令歡意歇。", "霜風吹嘉菊，撩亂籬下發。", "欲寄一枝芳，雲深去鴻滅。"]'),
('c64b0d9c-d94c-4092-913c-9f72b18f1f73','憶寧極','韓維','宋','宋诗','song-poetry','','[]','雨滴庵上茅，風亂窗外竹。',48,'全唐诗/poet.song.24000.json','["雨滴庵上茅，風亂窗外竹。", "繁聲夜入耳，欲寐不得熟。", "獨懷歸田客，石徑滑馬足。", "連山暗秋霧，一燈何處宿。"]'),
('770684f2-2049-488b-97f6-54897ebe1d25','百合花','韓維','宋','宋诗','song-poetry','','[]','真葩固自異，美艷照華館。',48,'全唐诗/poet.song.24000.json','["真葩固自異，美艷照華館。", "葉間鵝翅黄，蕊極銀絲滿。", "并萼雖可佳，幽根獨無伴。", "才思羨游蜂，低飛時款款。"]'),
('a8d9a5ce-4c89-449b-a240-add86538e717','送三哥守蜀','韓維','宋','宋诗','song-poetry','','[]','昔我忠憲公，握節臨西州。',48,'全唐诗/poet.song.24000.json','["昔我忠憲公，握節臨西州。", "于今三十載，餘愛尚應留。", "旌旗愴獨往，山水記同遊。", "一歌緇衣詩，涕下不能收。"]'),
('3d391dc9-c59e-498f-b639-15e767e90494','入都席上答曼叔見送','韓維','宋','宋诗','song-poetry','','[]','少乏四方志，所懷在林丘。',48,'全唐诗/poet.song.24000.json','["少乏四方志，所懷在林丘。", "塵埃豈我事，義往不得留。", "進酒長亭上，離馬儼行輈。", "臨分子無慘，且復相從遊。"]'),
('23060148-55a2-4d13-9e65-6c8708167484','同晏著作飲薛園坐中賦','韓維','宋','宋诗','song-poetry','','[]','鄙生秉愚尚，與世實齟齬。',180,'全唐诗/poet.song.24000.json','["鄙生秉愚尚，與世實齟齬。", "寄身軒裳內，懶惰衆不數。", "朅來西都游，獲并丞相府。", "命駕多從君，載酒即得侶。", "洛水南北涯，勝事著自古。", "名園藹相望，香剎屹時睹。", "最憐薛家溪，架閣在西滸。", "渾流激石來，知自嵩少雨。", "如從柁樓下，夜聽潮生浦。", "採珠櫻在盤，剝玉笋登俎。", "雜花雖云晚，紅白尚可取。", "興來倒冠巾，萬事一塵土。", "想在京輦日，耳目塞如堵。", "出憎車馬喧，坐厭名利語。", "幸茲清景對，醉死亦吾所。"]'),
('6a0a1a12-1424-4b65-b346-e491b72cf9d8','再遊薛園','韓維','宋','宋诗','song-poetry','','[]','朱櫻滿芳林，夏景始云變。',72,'全唐诗/poet.song.24000.json','["朱櫻滿芳林，夏景始云變。", "郊園掩深寂，休駕一來玩。", "殘花掃空蹊，密竹亂清澗。", "置酒臨層軒，波禽俯鳴泛。", "南風揚綃衣，微暑忽飄散。", "感此幽思生，吾其老佳觀。"]'),
('ab7bc8f0-1d98-4179-86ba-b356bd6a397f','奉答張寺丞再招遊薛園','韓維','宋','宋诗','song-poetry','','[]','名都富游踐，所歷多異境。',84,'全唐诗/poet.song.24000.json','["名都富游踐，所歷多異境。", "貪奇事穹覽，一過不再省。", "茲園獨勤來，三盡晝刻永。", "目清林葉凈，耳快石泉冷。", "如錢拾蟹殻，比針玩魚影。", "苦耽幽事樂，常使歸思耿。", "再招發新章，吾駕促當整。"]'),
('6a6ea587-eeab-4fbd-9f98-25943d32aba2','答公懿以屢游薛園見詒','韓維','宋','宋诗','song-poetry','','[]','抱痾積閑縱，世味頗能淡。',192,'全唐诗/poet.song.24000.json','["抱痾積閑縱，世味頗能淡。", "惟于山水娛，自謂老不厭。", "况茲伊洛間，久畜游賞念。", "幽扉深隠竹，小約度平塹。", "解鞍庇清陰，拂席見殘艷。", "長溪自南流，小閣忽東瞰。", "游人坐兀兀，鳴鳥來泛泛。", "蟹潛石穴幽，魚泳柳根暗。", "川童或群嬉，林女有孤覘。", "醉觴豈留行，吟筆靡停占。", "臨歡興何長，遵事迹猶暫。", "伊予志巖壑，偶官祿石甔。", "要須三徑足，歸迹便可斂。", "買林接婆娑，鑿澗分瀲灧。", "田廬常閉門，野艇時放纜。", "聊書平生懷，特爲異時驗。"]'),
('f0bd911b-b0a9-4e9e-90ff-73cad75b2183','游龍門詩十二首 寶應寺','韓維','宋','宋诗','song-poetry','','[]','林巒若無路，鐘磬時出谷。',36,'全唐诗/poet.song.24000.json','["林巒若無路，鐘磬時出谷。", "鑿石排僧龕，研金畫佛屋。", "日沒上方夕，明燈滿雲木。"]'),
('d11b5b72-ce3f-4ba4-a294-2a0d6c19c2a2','游龍門詩十二首 白傅影堂','韓維','宋','宋诗','song-poetry','','[]','遠人乘化往，生死不爲累。',36,'全唐诗/poet.song.24000.json','["遠人乘化往，生死不爲累。", "肖象即當年，忘言非翼世。", "一奠祠下觴，清風肅然至。"]'),
('9c334856-308b-4751-a8e9-1aab120be51e','游龍門詩十二首 石樓','韓維','宋','宋诗','song-poetry','','[]','縈回陟雲根，結構出石面。',36,'全唐诗/poet.song.24000.json','["縈回陟雲根，結構出石面。", "河傾八灘惡，野豁兩崖斷。", "曠然懷抱開，舉酒臨壯觀。"]'),
('069df94f-267b-4313-aabb-0cecbce1632a','游龍門詩十二首 香山上方','韓維','宋','宋诗','song-poetry','','[]','貪奇忘我勞，上上不復省。',36,'全唐诗/poet.song.24000.json','["貪奇忘我勞，上上不復省。", "窮遊盡人迹，却立看佛頂。", "日暮不忘歸，青山滿烟景。"]'),
('7e193ac3-329a-40d4-bc56-7d6c1cef28ab','游龍門詩十二首 乾元寺','韓維','宋','宋诗','song-poetry','','[]','林深寺獨在，谷轉路猶邈。',36,'全唐诗/poet.song.24000.json','["林深寺獨在，谷轉路猶邈。", "徐行出萬木，斗起造雙閣。", "一踐清凉境，始知人世濁。"]'),
('f0366b39-494e-491f-abeb-76174a5a3fb0','游龍門詩十二首 廣化寺','韓維','宋','宋诗','song-poetry','','[]','日照香剎端，風生石門下。',36,'全唐诗/poet.song.24000.json','["日照香剎端，風生石門下。", "精誠或有禱，嘉况如可把。", "安得飛片雲，坐看靈澤灑。"]'),
('28b95a12-bd7f-466f-9b2c-fc1189f161b0','游龍門詩十二首 菩提院望雒亭','韓維','宋','宋诗','song-poetry','','[]','茲亭何岧嶢，下瞰伊與洛。',36,'全唐诗/poet.song.24000.json','["茲亭何岧嶢，下瞰伊與洛。", "惟昔定鼎地，絕雲飛觀閣。", "姬公安在哉，氣象空回薄。"]'),
('e0507ed5-c7b2-4bf5-bf74-73e832e968f5','游龍門詩十二首 利涉塔院','韓維','宋','宋诗','song-poetry','','[]','許公讀書地，塵像一來拂。',36,'全唐诗/poet.song.24000.json','["許公讀書地，塵像一來拂。", "門掩僧不歸，檐低燕飛出。", "高人不可見，石塔鎮寒骨。"]'),
('6b8fa5c9-3d16-4d15-84cf-c5439c2365e0','游龍門詩十二首 聖善寺','韓維','宋','宋诗','song-poetry','','[]','陟逕凡幾盤，坐堂聊一息。',36,'全唐诗/poet.song.24000.json','["陟逕凡幾盤，坐堂聊一息。", "龍去空舊巖，崖崩有遺石。", "不見林下僧，鳥啼山寂寂。"]'),
('5b69fe0f-380b-42dd-b559-23db591293e2','游龍門詩十二首 盧溪','韓維','宋','宋诗','song-poetry','','[]','伊人沒已久，溪溜亦如綫。',36,'全唐诗/poet.song.24000.json','["伊人沒已久，溪溜亦如綫。", "淳風揖老僧，清陰坐春院。", "始晤入山深，幽林鳥聲變。"]'),
('3b505221-c4c3-420d-9d2e-0ce79530ae63','游龍門詩十二首 西溪','韓維','宋','宋诗','song-poetry','','[]','我從南嶺來，引轡下雲木。',36,'全唐诗/poet.song.24000.json','["我從南嶺來，引轡下雲木。", "不知溪流處，但見翠滿谷。", "凉葉覆山泉，脩篁翳茅屋。"]'),
('ee4d6d40-13d2-452d-b62d-4e89714c9ae1','游龍門詩十二首 潛溪','韓維','宋','宋诗','song-poetry','','[]','李公舊林壑，及此與幾授。',36,'全唐诗/poet.song.24000.json','["李公舊林壑，及此與幾授。", "清泉流不竭，密竹老逾秀。", "我慚疏野人，來值溪花後。"]'),
('ea6b45ca-de1c-4532-9e41-6bf3bc228be0','登上東門','韓維','宋','宋诗','song-poetry','','[]','朝發上東門，回首望帝宅。',108,'全唐诗/poet.song.24000.json','["朝發上東門，回首望帝宅。", "宮城鎮大野，瀍洛去不息。", "是時雨新霽，雲物有佳色。", "嵩峰如迎人，百里見晴碧。", "平川邈如畫，日照崖脚赤。", "道傍公卿墳，鰲背負脩石。", "蒼苔剝文字，十五尚可識。", "賢愚不復辨，零落同一迹。", "薄暮桑榆風，空悲懷古客。"]'),
('5b50f385-a500-410f-8ef9-fb7d00bb963e','孝義橋','韓維','宋','宋诗','song-poetry','','[]','殘花辭故都，細雨度清洛。',48,'全唐诗/poet.song.24000.json','["殘花辭故都，細雨度清洛。", "浮梁拖龍腹，徑石亂鵝殻。", "山形豁如對，林色秀可握。", "漁子何處去，長罾波面落。"]'),
('c95c08ce-b8d3-43bd-8047-1f1ab14fc506','行慶關','韓維','宋','宋诗','song-poetry','','[]','高關拒重阻，險狀固天設。',180,'全唐诗/poet.song.24000.json','["高關拒重阻，險狀固天設。", "俯窺洪流奔，仰視赤崖絕。", "來往無時停，千載一車轍。", "我行觸飛雨，舍轡上嵽嵲。", "筋勞不敢息，黄土百丈裂。", "伊昔六國餘，楚漢起相嚙。", "乘時急形便，利害校一髪。", "生民入鞭笞，溪谷日流血。", "時平屬真主，汾壤事西謁。", "翠華此回旋，萬騎出巖闕。", "斯人一何幸，澤浸厚地徹。", "烜哉行慶名，高與日星揭。", "干戈昔不守，符傳今尚撤。", "昏明變夷險，在德信前說。", "愧無能銘才，吊古空慘切。"]'),
('63d25aa1-812f-475f-a41e-719b13fc8c21','和晏相公雪','韓維','宋','宋诗','song-poetry','','[]','去年陽氣驕，不雪盡冬序。',168,'全唐诗/poet.song.24000.json','["去年陽氣驕，不雪盡冬序。", "今年未開臘，已見六花注。", "矜新忽微飄，爭急遂橫騖。", "浩蕩天地和，曠爽樓觀曙。", "蔽日驚蛾飛，集廱紛鷺翥。", "膏潤通大田，光輝借前樹。", "縈檐魯縞輕，委庭荆璞聚。", "微生窗戶明，巧作樽罍助。", "相公謝朝柄，燕處均養素。", "上嘉時澤滋，俯樂心賞遇。", "南閣罷圖史，西亭回杖屨。", "步逕憐缺玉，攀林看墮絮。", "長吟寫幽適，高隠動遐慕。", "愧非右席才，莫奉梁園賦。"]'),
('5981e0fd-907b-4aee-b607-7142710f46d1','徐秘校携酒過池上同賦','韓維','宋','宋诗','song-poetry','','[]','凉風灑疏雨，過我池上林。',48,'全唐诗/poet.song.24000.json','["凉風灑疏雨，過我池上林。", "感此望歲懷，酌酒相與吟。", "殘花猶動目，飛泉時驚心。", "徘徊將歸駕，清醉方自今。"]'),
('cb44084e-55cb-447e-953e-4747d176f02a','之靈巖三首  其一','韓維','宋','宋诗','song-poetry','','[]','積陰曠初霽，策馬望嵩洛。',48,'全唐诗/poet.song.24000.json','["積陰曠初霽，策馬望嵩洛。", "斜日黑雲西，回光照城郭。", "牛散陂草深，蛙鳴溝水濁。", "雷遠尚餘音，山前垂雨脚。"]'),
('67363476-1c10-474a-9e3b-960631e0de0b','之靈巖三首  其二','韓維','宋','宋诗','song-poetry','','[]','朝行曲河道，暮夜不遑止。',48,'全唐诗/poet.song.24000.json','["朝行曲河道，暮夜不遑止。", "野草熏滿衣，山蟬鳴裂耳。", "我僕痡秋陽，我馬困石齒。", "未厭行役勞，當前碧蒿起。"]'),
('39a262ce-d1c4-4cc3-b8f7-af2b45618f1d','之靈巖三首  其三','韓維','宋','宋诗','song-poetry','','[]','山高景逾變，所覽今非昨。',48,'全唐诗/poet.song.24000.json','["山高景逾變，所覽今非昨。", "雲覆嵩頂寒，河傾灘面□。", "□中塔廟湧，日暮鐘磬作。", "延首望洛城，氣象□□□。"]'),
('4a29d94c-2690-428c-9468-42dc02e5304e','會聖宮','韓維','宋','宋诗','song-poetry','','[]','驅車□□□，回首望陵樹。',132,'全唐诗/poet.song.24000.json','["驅車□□□，回首望陵樹。", "岡原何鬰盤，左右瞰龍□。", "□□□□□，□此延真馭。", "冠山崇朱堂，面洛□□□。", "□□□□璧，鐵馬有餘怒。", "深沉風塵表，想□□□□。", "□朝尚仁儉，供養事殊古。", "充邑無豪宗，埋枕廢嬪御。", "寂寞歌舞音，飛花亂紅素。", "小臣駭奇觀，怳若夢帝所。", "巍巍列聖業，欲頌慚非甫。"]'),
('b5ff8d38-f4eb-48cf-85a0-4272779dafda','王家渡','韓維','宋','宋诗','song-poetry','','[]','浮舟亂清洛，中流望嵩少。',48,'全唐诗/poet.song.24000.json','["浮舟亂清洛，中流望嵩少。", "山晴水光晚，藍碧近相照。", "倚崖睨落日，坐覺身世小。", "嘆息浮生勞，臨風一長嘯。"]'),
('c7cd3be8-0c87-4ab9-a2ac-370bbf607170','董家園對雨','韓維','宋','宋诗','song-poetry','','[]','霏微池上來，蕭散竹間度。',48,'全唐诗/poet.song.24000.json','["霏微池上來，蕭散竹間度。", "稍遠樹頭花，頗沉波面絮。", "狂收遊騎迹，喜動田翁語。", "對酒豈不佳，幽寂自成趣。"]'),
('3b48322f-1356-4125-95a5-68e469b85895','之石窟寺馬上作','韓維','宋','宋诗','song-poetry','','[]','今辰忘我勞，幽事隨所歷。',48,'全唐诗/poet.song.24000.json','["今辰忘我勞，幽事隨所歷。", "翠麥回一川，黄花明半壁。", "山林契宿尚，老大悲物役。", "便欲從溪僧，分居窟崖石。"]'),
('64dcee3b-eb46-42bf-89a4-85bc1f8e0431','答仲章別後見寄','韓維','宋','宋诗','song-poetry','','[]','會合非素期，追懽得同好。',48,'全唐诗/poet.song.24000.json','["會合非素期，追懽得同好。", "旅情忘鬰約，春事入吟嘯。", "子行反崤鞏，我去旁嵩少。", "悵望洛陽花，金樽不同倒。"]'),
('687003be-704e-4d4c-92a7-0eda17ed7cbd','和晏相公泛南湖韋家園過西溪至許家園','韓維','宋','宋诗','song-poetry','','[]','湖心點點生圓荷，黄花白花滿晴波。',120,'全唐诗/poet.song.24000.json','["湖心點點生圓荷，黄花白花滿晴波。", "環堤客樹垂婆娑，魚沉鷺矯各自得。", "人生不樂其謂何，南塘過盡西溪綠。", "上下名園依小曲，相君從容來賞矚。", "不驅大旆事喧鬧，直解扁舟作幽獨。", "幕中賓從才且良，酒酣落筆摛文章，珠聯璧疊爭煒煌。", "政成禮息無一事，明日復此醉華觴。"]'),
('39554567-5e37-4ca8-8cc1-675a665ef4bd','又和春遊','韓維','宋','宋诗','song-poetry','','[]','青春之來漫無蹤，但見佳氣流融融，天地百物和風中。',120,'全唐诗/poet.song.24000.json','["青春之來漫無蹤，但見佳氣流融融，天地百物和風中。", "輕雷殷出草根綠，丹霞散作枝上紅。", "鳴蜂喧空蝶撲地，似與遊人報芳意。", "東城南陌交輪轡，朝塵暮雨纔幾日，已見殘花落如積。", "人生勞苦誠可悲，奔走事役無休時，天意以眷使其熙。", "會須舉酒爛漫醉，當與不取庸非癡。"]'),
('2dbe4dc8-67fc-467a-87b8-cf29b4d16b98','和孫廷平坦嵩山十首 古木陰','韓維','宋','宋诗','song-poetry','','[]','山木以不材，故能遂擁腫。',36,'全唐诗/poet.song.24000.json','["山木以不材，故能遂擁腫。", "陰成衆人息，於世豈非用。", "不用用已成，茲理古所重。"]'),
('ca658c5c-17b0-4434-8196-fa62bf3d25a5','和孫廷平坦嵩山十首 寒溪石','韓維','宋','宋诗','song-poetry','','[]','寒溪水痕落，怪石千萬狀。',36,'全唐诗/poet.song.24000.json','["寒溪水痕落，怪石千萬狀。", "須防遊屐滑，不礙釣舟漾。", "安得平若席，卧看孤月上。"]'),
('45c6afc6-5ea7-4621-a124-6981d75fbe0a','和孫廷平坦嵩山十首 孤竹蘋','韓維','宋','宋诗','song-poetry','','[]','春山夜多雨，點蘋生水涘。',36,'全唐诗/poet.song.24000.json','["春山夜多雨，點蘋生水涘。", "誰與賞幽芳，惟有巖中子。", "抱琴沙上立，日暮清風起。"]'),
('45a68dfc-ea07-4ed2-8b39-18622432a73c','和孫廷平坦嵩山十首 垂崖鞭','韓維','宋','宋诗','song-poetry','','[]','蟄蛇拖脩尾，下映赤壁烟。',36,'全唐诗/poet.song.24000.json','["蟄蛇拖脩尾，下映赤壁烟。", "騏驥久不出，此物甘棄捐。", "常恐雷雨至，飛起蒼崖顛。"]'),
('1fb42934-26c4-4186-9fd4-5335fae67362','和孫廷平坦嵩山十首 雲際鐘','韓維','宋','宋诗','song-poetry','','[]','層雲冒諸嶺，迢迢起何處。',36,'全唐诗/poet.song.24000.json','["層雲冒諸嶺，迢迢起何處。", "稍與暝烟沉，還隨晚風度。", "聲絕人倚樓，東風月纔吐。"]'),
('ca0e0dd9-5eee-47c9-a8b3-e0d7f1865a40','和孫廷平坦嵩山十首 天外峰','韓維','宋','宋诗','song-poetry','','[]','孤峰望不極，却視天形低。',36,'全唐诗/poet.song.24000.json','["孤峰望不極，却視天形低。", "天高豈可踰，直以雲濛之。", "何時一掃去，高下皎不疑。"]'),
('f2b2ef89-593d-4f76-bd0b-93fee31871ff','和孫廷平坦嵩山十首 秋原菊','韓維','宋','宋诗','song-poetry','','[]','秋風原上菊，百草同蕃滋。',36,'全唐诗/poet.song.24000.json','["秋風原上菊，百草同蕃滋。", "霜至草已死，黄花始離離。", "君子不獨異，顯晦顧有時。"]'),
('4883c5e3-2876-4418-a140-96a217b6c446','和孫廷平坦嵩山十首 漁舟火','韓維','宋','宋诗','song-poetry','','[]','拖網潭上歸，孤烟出峰背。',36,'全唐诗/poet.song.24000.json','["拖網潭上歸，孤烟出峰背。", "稍沒寒霧中，微明秋雨外。", "起我江湖心，鱸魚方可膾。"]'),
('e1938c38-4e84-44a9-bacf-bbd8a6521aff','和孫廷平坦嵩山十首 春溪水','韓維','宋','宋诗','song-poetry','','[]','陽生溪谷溫，坼坼冰面破。',36,'全唐诗/poet.song.24000.json','["陽生溪谷溫，坼坼冰面破。", "淥隨波色還，白放雲光墮。", "野鷗豈知此，終日忘形坐。"]'),
('406ae2c2-59b0-41e5-9a37-a8862ab334cf','和孫廷平坦嵩山十首 幽谷泉','韓維','宋','宋诗','song-poetry','','[]','鳴泉瀉幽谷，谷響聲又激。',36,'全唐诗/poet.song.24000.json','["鳴泉瀉幽谷，谷響聲又激。", "上蔭百丈松，下有無數石。", "會脫炎天屨，坐浸兩脚赤。"]'),
('609b9e7b-8387-458b-8023-b79015440c13','和晏相公觸事成詠四首  其一','韓維','宋','宋诗','song-poetry','','[]','梧桐傾鳴鳳，鳴鳳邀高翔。',36,'全唐诗/poet.song.24000.json','["梧桐傾鳴鳳，鳴鳳邀高翔。", "微蟲縷衆葉，玲瓏秋日光。", "本性苟不易，憔悴庸何傷。"]'),
('a6035fe3-02ce-40f7-aadb-c38354ea265a','和晏相公觸事成詠四首  其二','韓維','宋','宋诗','song-poetry','','[]','栟櫚結雙根，皮附若毛氄。',36,'全唐诗/poet.song.24000.json','["栟櫚結雙根，皮附若毛氄。", "乘秋一剪剝，碧葉始竦竦。", "豈識山中木，終年自擁腫。"]'),
('56852db8-72e8-467b-a867-850e88010cd6','和晏相公觸事成詠四首  其三','韓維','宋','宋诗','song-poetry','','[]','誅茅結園屋，日夕所遊造。',36,'全唐诗/poet.song.24000.json','["誅茅結園屋，日夕所遊造。", "雀來啄其茨，蚓出穴其穾。", "中虛尚可托，外此非吾保。"]'),
('4b0cacdd-ddd1-457a-973e-217e86936144','和晏相公觸事成詠四首  其四','韓維','宋','宋诗','song-poetry','','[]','種竹患不多，既多亦爲苦。',36,'全唐诗/poet.song.24000.json','["種竹患不多，既多亦爲苦。", "長根走地脈，凌突敗垣堵。", "物情有利害，爲爾執揮斧。"]'),
('1d9bb666-51bb-422f-9258-9c92861717a4','同鄰幾避暑景德','韓維','宋','宋诗','song-poetry','','[]','脩廊環無端，華殿鳥斯革。',132,'全唐诗/poet.song.24000.json','["脩廊環無端，華殿鳥斯革。", "石鯨窺廣庭，金像飛半壁。", "高槐十丈餘，凉葉散檐隙。", "茲游得我所，烈日徒自赤。", "體煩愜清潭，髪散謝危幘。", "彷徉或持書，靜默方對奕。", "惟時驕陽甚，燥氣裂金石。", "城郭困風埃，田疇有憂色。", "顧慚無用軀，獨此享嘉適。", "舉頭望赤霄，安得片雲黑。", "滂沱爲飛霖，一洗周八極。"]'),
('965439bd-0d28-435d-9ba7-c0ebdc2c69c2','監宿呈一二交游','韓維','宋','宋诗','song-poetry','','[]','牆根蟋蟀鳴不休，夜宿學省高梧秋。',64,'全唐诗/poet.song.24000.json','["牆根蟋蟀鳴不休，夜宿學省高梧秋。", "昏燈釘壁照孤坐，悲風攪腸生百憂。", "久從塵事非我意，直有爛醉爲身謀。", "誰能擺落世俗累，願敝肥馬同輕裘。"]'),
('08ce929b-fdea-48ec-9a2e-cb8a68db5406','監宿書懷寄崔九象之','韓維','宋','宋诗','song-poetry','','[]','偶隨世緣出，歲晏未得還。',48,'全唐诗/poet.song.24000.json','["偶隨世緣出，歲晏未得還。", "譬如無心雲，會自歸故山。", "所嗟平生友，日夕阻追攀。", "想子獨宿夜，燈明深竹間。"]'),
('fa9adfde-69b3-4517-9466-60cdc6184a3b','官舍書事','韓維','宋','宋诗','song-poetry','','[]','官曹本自冷，况值秋風後。',48,'全唐诗/poet.song.24000.json','["官曹本自冷，况值秋風後。", "落葉頻委階，斜光半穿牖。", "幽閑夙所尚，默靜頗能久。", "門外聲利喧，於吾竟何有。"]'),
('8bca84f4-be0f-4d17-bd05-be0fb559a38d','答原甫試墨見貽','韓維','宋','宋诗','song-poetry','','[]','金壺道人丸法墨，持買都城人莫識。',98,'全唐诗/poet.song.24000.json','["金壺道人丸法墨，持買都城人莫識。", "君先得之寫大句，光與日彩相吞蝕。", "句精墨妙氣怒豪，意欲斬鯨連巨鰲。", "鯨鰲天地兩微物，何足辱吾鈎與刀。", "丈夫卷舒固有道，願君少安無草草。", "都城不獨墨好酒亦好，安得不飲自枯槁。"]'),
('2473b2b9-9d7e-453b-ba88-58f944203fcb','和原甫省中種菊','韓維','宋','宋诗','song-poetry','','[]','種菊待佳節，節至花自繁。',144,'全唐诗/poet.song.24000.json','["種菊待佳節，節至花自繁。", "朝感凉風吹，夕愛清露團。", "封培才幾日，翠類紛珊珊。", "君曹本稱劇，占署無停翰。", "才優顧多暇，曾不廢覽觀。", "作詩見高興，讀之起予嘆。", "念昔田里居，幽事頗復論。", "種此黄紫雜，撩亂發牆根。", "擷英泛濁酒，親友日爲歡。", "一朝走京邑，連歲遭阻艱。", "鬢毛將看白，淚眥熒莫乾。", "時物豈不佳，感傷自有端。"]'),
('bb333b84-4b66-464b-8833-ae62ae591fbb','監宿同鄰幾賦','韓維','宋','宋诗','song-poetry','','[]','浮雲吐寒月，餘霰清夜氣。',84,'全唐诗/poet.song.24000.json','["浮雲吐寒月，餘霰清夜氣。", "蕭條廣文直，冷冽久不寐。", "所欣同心友，談笑亦來塈。", "高步南樓陰，清風散餘醉。", "仰看星斗移，俯念歲時逝。", "茲曹寡吏責，疏拙得所庇。", "幸君數來臨，共作苦吟計。"]'),
('9177445e-54f7-4465-9c64-b9c2a173bf90','和聖俞喜雪','韓維','宋','宋诗','song-poetry','','[]','窮冬不雪天子憂，既禱乃降惟神休。',80,'全唐诗/poet.song.24000.json','["窮冬不雪天子憂，既禱乃降惟神休。", "人間半夜天地白，靈澤一灑萬彙周。", "乃知天人相響影，自古王者重修省。", "登賢黜邪朝序清，鋤奸戮妖海波靜。", "群公不勞歲奔走，四時不干雨暘正。"]'),
('849c3ce2-81b1-4af1-80d7-0f3a84c1aa1e','和聖俞飲廷老家晚又飲原甫家','韓維','宋','宋诗','song-poetry','','[]','人生天地間，常爲外物驅。',156,'全唐诗/poet.song.24000.json','["人生天地間，常爲外物驅。", "自非無心者，不能忘所趨。", "所趨既若一，莫如飲酒娛。", "飲酒既復醉，萬事皆分銖。", "醉心兀無思，安問賢與愚。", "醉目浩無睹，安識嬙與嫫。", "是非兩棄絕，幸免禍患俱。", "况吾二三友，襟抱達者徒。", "所營既同方，所處又比閭。", "惟吾廷老生，宛在城北隅。", "北隅雖云遠，跨馬亦須臾。", "季冬陰氣凝，風力利石砮。", "從今雪花落，徑往不待呼。"]'),
('7a89a67f-01df-4235-9dd6-00afad153a2e','奉同沖卿元日雪霽朝會稱觴','韓維','宋','宋诗','song-poetry','','[]','漢家萬國朝元正，帝呵風師灑其廷。',224,'全唐诗/poet.song.24000.json','["漢家萬國朝元正，帝呵風師灑其廷。", "雨寒成花皆六出，一洗天地塵埃清。", "高風半天捲雲去，空色紺碧惟華星。", "金烏東來照宮殿，瑞氣著物皆光榮。", "綉衣虎士扶脩旗，皂旄絳幅紛葳蕤。", "洞開重門納冠劍，肅肅環佩來東西。", "樂懸未作舞在綴，雉扇稍映宮簾垂。", "黄鐘獨奏君德盛，赫然天日當彤墀。", "群臣拜舞千萬壽，四方來王敢不祗。", "愚聞聖人制禮意，上崇一尊臨衆卑。", "等威殊絕防僭慢，非止矜麗誇雄爲。", "仰瞻儀物固自肅，又况烜赫鋪德威。", "小臣不及觀放仗，趨出恍惚猶驚疑。", "朝廷大體安敢識，贊詠盛節形諸詩。"]'),
('55931254-48e0-4242-bc04-197286211010','奉同原甫度支廳壁許道寧畫松','韓維','宋','宋诗','song-poetry','','[]','長松盤青冥，鬰與窗戶對。',120,'全唐诗/poet.song.24000.json','["長松盤青冥，鬰與窗戶對。", "許翁寫生意，獨得毫墨外。", "年侵日昏剝，拂拭自君輩。", "得非神物守，以待真賞會。", "翛然簿書暇，恍若巖壑內。", "舉手捫紫烟，側耳聽清籟。", "蒼林與老石，野性舊所愛。", "一從官都邑，茲遊頗乖背。", "慰此寤寐懷，典刑亦足頼。", "幸當掃塵壁，促駕我其邁。"]'),
('2e5b172a-1a3c-4fab-bc4d-c587e5c6b731','又和原甫省壁畫蟹','韓維','宋','宋诗','song-poetry','','[]','天工不爲神，衆物自我具。',48,'全唐诗/poet.song.24000.json','["天工不爲神，衆物自我具。", "錢侯掃墨筆，敖跪生指顧。", "如依石穴出，尚想秋江度。", "真僞本相奪，安知彼非誤。"]'),
('abd5a22e-d1b5-47a6-b9ea-34ac93879050','和聖俞遊梁王吹臺有感','韓維','宋','宋诗','song-poetry','','[]','高臺壓萬井，四絕埃與氛。',96,'全唐诗/poet.song.24000.json','["高臺壓萬井，四絕埃與氛。", "上有金僊廬，凌虛結楣棼。", "嘗聞登其巔，直視太行雲。", "壯觀良跂予，夙駕慚後君。", "况當朱炎月，烈風來朝曛。", "泛瀲白正醴，飄颻輕練裙。", "想像簫鼓處，寥寥如有聞。", "一寫沈鬰憂，懷古何足云。"]'),
('1441cccb-7c02-4bf4-ad27-ffeb9ea64967','和聖俞逢羊','韓維','宋','宋诗','song-poetry','','[]','雉以媒就獲，鹿以由見羈。',60,'全唐诗/poet.song.24000.json','["雉以媒就獲，鹿以由見羈。", "物情非本然，實自巧者爲。", "惟人莫或使，勢利中奪移。", "朝游固金石，暮變險阱機。", "世路有如此，君無獨羊悲。"]'),
('27786e63-293d-4b4e-8ae7-90cdbf907328','和原甫盆池種蒲蓮畜小魚','韓維','宋','宋诗','song-poetry','','[]','江湖豈非壯，浩蕩不可尋。',72,'全唐诗/poet.song.24000.json','["江湖豈非壯，浩蕩不可尋。", "安知一斛水，坐得萬里心。", "植蒲翠節聳，種蓮紫實沉。", "群魚不盈寸，泳淺安其深。", "主人樂幽事，清興生中林。", "獨觀物性得，鵬海均牛涔。"]'),
('40c5dd9f-81d7-427d-9502-2aebf00f63ed','監中直舍種竹同沖卿鄰幾探韵賦得風字','韓維','宋','宋诗','song-poetry','','[]','職事惰不理，種竹養疏慵。',48,'全唐诗/poet.song.24000.json','["職事惰不理，種竹養疏慵。", "愛此炎暵辰，獨抱霜雪容。", "清陰動脩架，秀色如本叢。", "日落衆客散，蕭蕭庭戶風。"]'),
('fafa3a4a-1ca8-45b9-b630-0228cafcf14c','和原甫曉雨','韓維','宋','宋诗','song-poetry','','[]','喜雨濯炎夜，餘飛入晨光。',72,'全唐诗/poet.song.24000.json','["喜雨濯炎夜，餘飛入晨光。", "起來坐軒戶，北風吹我裳。", "碧折萱葉亂，翠添林笋長。", "翩翩庭中燕，群飛戲清凉。", "直恐煩暑盡，從此零秋霜。", "欣然跨馬出，一醉故人觴。"]'),
('476ad9a8-f6e1-4e35-8fac-447b9f2920a2','和鄰幾館宿觀伯鎮題壁有作','韓維','宋','宋诗','song-poetry','','[]','城南飲騎散，君赴蓬山廬。',156,'全唐诗/poet.song.24000.json','["城南飲騎散，君赴蓬山廬。", "禁門肅清夜，飛閣何渠渠。", "深沉漏下始，蕭颯雨氣餘。", "俯仰河漢明，高情邈沖虛。", "獨懷同舍郎，被命分左魚。", "得州東南勝，繞郭生芙蕖。", "苦嗟已留滯，三歲紛塵裾。", "人生固不一，理亦相乘除。", "或彼有所近，或此亦以疏。", "馮唐匿郎署，白首常晏如。", "方朔雖金門，避世等樵漁。", "古來守道者，期不忘厥初。", "但願飲酒間，時讀古人書。"]'),
('e63566fa-390b-46c3-8972-b91ffbf2037f','和王昭君','韓維','宋','宋诗','song-poetry','','[]','漢宮姝麗地，華觀連珍臺。',108,'全唐诗/poet.song.24000.json','["漢宮姝麗地，華觀連珍臺。", "娥眉三千人，皆自良家來。", "昭君乃獨出，負色羞自媒。", "一爲丹青誤，白雪成緇埃。", "結歡萬里外，不得少徘徊。", "車馬悵不前，觀者爲悲摧。", "空令琵琶曲，千載傳餘哀。", "物生美惡混，天意未易回。", "蘭茝苟不珍，且願生蒿萊。"]'),
('d40bf43b-8156-414e-965b-1c368788e03a','和聖俞聞景純吹笛妓病愈','韓維','宋','宋诗','song-poetry','','[]','刁侯好事聞當年，至今風韵獨依然。',128,'全唐诗/poet.song.24000.json','["刁侯好事聞當年，至今風韵獨依然。", "歸來不作留滯嘆，能出窈窕夸樽前。", "前時賓客會清夜，橫笛裂玉吹孤圜。", "新聲妙逐柔指變，餘響欻與高雲連。", "悲風蕭瑟四座聳，清笑自足遺拘攣。", "近聞有疾勿藥喜，主人欲飲期數賢。", "氣羸曲節宜少緩，體軟舞態當益妍。", "人生行樂不可後，幸及華月秋娟娟。"]'),
('88f1bd5c-7d6d-48e0-9cfd-c54e8ee64f42','同楊方叔游開寶上方有懷里中二三故人','韓維','宋','宋诗','song-poetry','','[]','京都寡臨觀，茲地高且明。',144,'全唐诗/poet.song.24000.json','["京都寡臨觀，茲地高且明。", "仲冬一來望，曠然寫予情。", "千載豪傑盡，夷門荆棘生。", "時平盛民物，華屋連飛甍。", "長烟冒百里，下視色正青。", "慨彼塵土間，擾擾何多營。", "往車無徐驅，來馬無停征。", "顧慚託閒官，幸得游衍并。", "念我同里人，三四不在行。", "孔公老龍山，孫子令江城。", "崔閒盎有粟，辛困冠無纓。", "一回西南首，慘淡意莫平。"]'),
('0d6b9439-69a0-4350-b1aa-6159f5fc28cd','和原甫去年對雪思梅今年對梅思雪','韓維','宋','宋诗','song-poetry','','[]','中州寒燠與南異，常恨梅花開不早。',80,'全唐诗/poet.song.24000.json','["中州寒燠與南異，常恨梅花開不早。", "今年朔雪冬不飛，臘月繁英似南好。", "君憐芳物感時節，愁見高風凍雪掃。", "苦嗟十九不稱意，徒自令人顔色老。", "雪遲梅早非我力，會使金樽日傾倒。"]'),
('49a2aa6d-ec34-4892-a3a4-5fa657b99534','奉同原甫槐陰行','韓維','宋','宋诗','song-poetry','','[]','天門觀闕雙凌霞，下有馳道開平沙。',96,'全唐诗/poet.song.24000.json','["天門觀闕雙凌霞，下有馳道開平沙。", "高槐左右覆朱梐，綠陰翠氣相蒙遮。", "朝回亙雲下寶騎，游散掣電奔香車。", "我慚太學官况冷，旦暮出此驅疲騧。", "清風吹冷南就局，炎日轉景東還家。", "昏然百事不知省，空復春葉零秋華。"]'),
('3baf9304-b99e-43c8-909f-83c4bb960f11','伏日同當事諸君飲延祥觀','韓維','宋','宋诗','song-poetry','','[]','適郊憚勤遠，近市厭喧跼。',96,'全唐诗/poet.song.24000.json','["適郊憚勤遠，近市厭喧跼。", "紛然異趨嚮，日晏靡寧足。", "回車憩琳館，邂逅得所欲。", "凉飈颯生林，飛雨時度竹。", "醇醪挹雲漿，佳果咀冰玉。", "讙爭校奕棋，談笑追割肉。", "茲辰著休令，嬉燕動輦轂。", "聊從一時樂，庶以同厥俗。"]'),
('5b1f0df2-d6a6-4ab2-a2d9-9f04f71c337d','之祀奉呈同行二進士','韓維','宋','宋诗','song-poetry','','[]','煌煌儒者宮，是惟風教首。',108,'全唐诗/poet.song.24000.json','["煌煌儒者宮，是惟風教首。", "群賢日造集，經訓謹傳授。", "公田有常廩，著令所從久。", "逋租積歲月，課督豈宜後。", "浮舟出東郊，秋日麗榆柳。", "幸同二三子，談笑失炎晝。", "鄙生竊薄祿，萬補無一有。", "佇觀盛化流，朝列登秀茂。", "彼微主簿官，豈敢息奔走。"]'),
('7ea4d565-bd10-444f-a3f4-22d499831a4f','圉城視囿','韓維','宋','宋诗','song-poetry','','[]','下馬步榛薈，弔古高陽門。',84,'全唐诗/poet.song.24000.json','["下馬步榛薈，弔古高陽門。", "鳴蜩亂深樾，蔓草被頹垣。", "席陰得佳木，解带休我煩。", "二年官儒館，始嘆吏役喧。", "學圃蹈孔戒，征利服軻言。", "黽勉職事間，大懼失所存。", "秋風熟梨棗，令人思故園。"]'),
('68887e92-a2ec-4f29-877b-40b88ba70f6b','和沖卿晚秋過金明池','韓維','宋','宋诗','song-poetry','','[]','聞君西郊行，正值秋風晚。',132,'全唐诗/poet.song.24000.json','["聞君西郊行，正值秋風晚。", "清霜卷枯荷，碧玉瑩池面。", "浮空結脩梁，涌波抗華殿。", "雲烟渺凈色，覽望一蕭散。", "緬思暮春際，都人盛嬉燕。", "連帷錯繡綺，方車騖金鈿。", "填填鼓鐘響，耳目厭譁眩。", "乃令塵囂辭，而有清曠戀。", "達人冥至理，喧寂無異觀。", "偶然秉化往，何適非汗漫。", "吾知禦寇游，所樂在觀變。"]'),
('c808b157-cbe8-4f7c-8b3d-87be56bdacb2','送北都留臺王國博','韓維','宋','宋诗','song-poetry','','[]','鑿川當鑿源，植木當植根。',120,'全唐诗/poet.song.24000.json','["鑿川當鑿源，植木當植根。", "修身有本末，請自心術言。", "中正檢欹側，明誠破疑昏。", "性通學且博，事業乃可論。", "問胡能致然，聖有六經存。", "子誠好古士，拔足立貴門。", "願分留臺務，力學甘避喧。", "吾知大其業，流遠實亦繁。", "歸來騁夷路，良馬駕輕軒。", "贈言君勿嗤，茲道古所敦。"]'),
('dbe385f9-9e11-4298-a6f4-5fb995d924fb','奉答聖俞寄鴨脚實見貽','韓維','宋','宋诗','song-poetry','','[]','南國有佳樹，結陰君子堂。',72,'全唐诗/poet.song.24000.json','["南國有佳樹，結陰君子堂。", "秋風彫碧葉，素實登新嘗。", "緬懷朋游重，千里走絳囊。", "朋游方會合，論文開酒場。", "共嘉明物珍，含甘咏雕章。", "章罷默不樂，爲君一停觴。"]'),
('0e4e8f40-6c59-416f-bd22-121ecab8220f','和永叔小飲懷同州江十學士','韓維','宋','宋诗','song-poetry','','[]','翰林文章伯，好古名一世。',192,'全唐诗/poet.song.24000.json','["翰林文章伯，好古名一世。", "家無金璧儲，所寶書與器。", "北堂冬日明，有朋聯騎至。", "新樽布几案，二鼎屹先置。", "大鼎葛所銘，小鼎澤而粹。", "坐恐至神物，光怪發非次。", "群賢刻金石，墨本來四裔。", "紛穰罷卷軸，指擿辨分隸。", "其中石贊藏，家法非一二。", "精莊與飄逸，兩自有餘意。", "興來輒長歌，歡至遂沉醉。", "顔饑足簞瓢，韓飲尚文字。", "乃知內可樂，不必鐘鼓貴。", "溫溫江馮翊，茲理久所詣。", "賦詩多雅言，嗜酒見淳氣。", "歲晏不在席，使我長嘆喟。"]'),
('a2bf05e1-82c7-49f4-aff3-b7c43db8e1e5','和永叔言懷','韓維','宋','宋诗','song-poetry','','[]','弱歲抱衰病，掩關卧園廬。',180,'全唐诗/poet.song.24000.json','["弱歲抱衰病，掩關卧園廬。", "端居寡人事，永日惟對書。", "得花輒手植，生草每自鋤。", "最憐脩竹姿，擢幹青玉如。", "添栽歲歲廣，翠色滿窗疏。", "起坐一堂內，樂此不願餘。", "偶來從吏役，幽事日以疏。", "出門何所見，擾擾塵中車。", "素懷就湮沒，有恨不可攄。", "尚念祿仕微，欲返復躊躇。", "高賢侍天陛，文章冠嚴徐。", "迹雖臺省遊，志慕江湖漁。", "鳳皇覽輝下，阿閣正其居。", "顧惟蒿艾翮，分甘侶田鴽。", "因詩益自警，庶不忘厥初。"]'),
('d9091738-2920-4355-bc51-d20b0ec5e4d7','和勝之彈琴','韓維','宋','宋诗','song-poetry','','[]','寥寥太虛內，漠然函至音。',84,'全唐诗/poet.song.24000.json','["寥寥太虛內，漠然函至音。", "淳源一以泄，其流播爲琴。", "衆人玩其器，賢者識其心。", "勝之明達士，於此趣已深。", "發爲新詩謠，如聽松風吟。", "鍾牙久不作，誰辨雅與淫。", "昭氏貴弗鼓，茲言良所欽。"]'),
('3039d926-630b-4a66-93a6-afccda85fac5','奉同原甫賦澄心堂紙','韓維','宋','宋诗','song-poetry','','[]','江南國土未破前，澄心名紙世已傳。',176,'全唐诗/poet.song.24000.json','["江南國土未破前，澄心名紙世已傳。", "高堂久傾不復見，誰謂此物猶依然。", "當時萬杵搗雲葉，鋪出几案滑且堅。", "剡溪藤骨不足數，蜀江玉屑誰復憐。", "君臣嬉燕盛文采，駢章麗曲鬥巧儇。", "一朝零落隨散地，中原篋笥生光鮮。", "君安得此尚百幅，題以大句先群賢。", "群賢落筆富精麗，瓊琚寶玦相鈎聯。", "嗟予材力豈當敵，雖欲强賦何能妍。", "耽獨玩物古所戒，崇尚浮藻政豈先。", "江南可哀紙可惜，後有觀者存吾篇。"]'),
('51e9d208-d714-41f1-8a13-0b5d4bdcc955','又和北軒竹上甘露','韓維','宋','宋诗','song-poetry','','[]','君家竹上露，點綴如明璫。',48,'全唐诗/poet.song.24000.json','["君家竹上露，點綴如明璫。", "垂枝乍驚重，映日復能光。", "聊可助清興，安知爲羨祥。", "應從草制暇，延咏對華觴。"]'),
('ddbab98c-6d16-4312-975b-a395ca5c369a','同勝之明叔遊東郊','韓維','宋','宋诗','song-poetry','','[]','仲冬景氣佳，曠然思遠涉。',168,'全唐诗/poet.song.24000.json','["仲冬景氣佳，曠然思遠涉。", "晨遵大堤去，寒日在馬鬣。", "浮屠紅塵外，樓殿煥層疊。", "地遐幽景閑，瑶碧秀林葉。", "清香時出箔，餘經尚委笈。", "躋閣眺遠陂，浮陽來曄曄。", "花枝亦已柔，行見春露浥。", "久耽田野樂，况與賢俊接。", "逍遥永日暇，塵事不過睫。", "昔人重時晷，所志樹勛業。", "慨予胡不然，空陋無所挾。", "詩情朝生腸，酒氣暮醺頰。", "陶陶大化內，得此自爲愜。", "諸君能我從，遊履方屢躡。"]'),
('6f7a6ddb-a6e7-4bce-83e9-394c28281298','奉答詹叔過澶之舊州有作','韓維','宋','宋诗','song-poetry','','[]','荒城巋遺堵，曙色起桑柘。',48,'全唐诗/poet.song.24000.json','["荒城巋遺堵，曙色起桑柘。", "肅肅胡雁群，風急不得下。", "子行感興廢，弔望一停駕。", "緘詩寄故人，明燈讀寒夜。"]'),
('374321d1-b900-403e-8af9-5b9ddd3eed82','騏驥池上與沖卿同賦','韓維','宋','宋诗','song-poetry','','[]','清簾翳華屋，脩樹環廣池。',72,'全唐诗/poet.song.24000.json','["清簾翳華屋，脩樹環廣池。", "凉風欣然來，忽若與我期。", "感激氣節異，念言此何時。", "雲霄有靈匹，嘉會方在茲。", "瓜華動都邑，舉俗共遨嬉。", "嗟我獨不飲，奈此天運爲。"]'),
('903e417a-81fb-4e0c-8411-33bc1cebd531','答貢甫酌騏驥池上見詒','韓維','宋','宋诗','song-poetry','','[]','金行戰陽暑未北，炎鬰填胸汗流液。',288,'全唐诗/poet.song.24000.json','["金行戰陽暑未北，炎鬰填胸汗流液。", "空堂大祖不可度，欲取清風自湔滌。", "耽耽華廄列官守，對起二亭嚴案席。", "天渠分水濯龍驥，下注方池氣清激。", "叢篁冠島鷺飛映，凉樹摇波蟬不息。", "脫然冠带一去體，始信天時有人力。", "况吾所與二三友，日坐清閑哦簡策。", "篇章爛若揚組繡，歌頌鏗如出金石。", "嘉賓亦有邂逅至，間以謳歌侑棋奕。", "我時聊設薄主人，杯案隨時具肴核。", "鱉小惟憂堵父怒，樽空屢動崔侯色。", "歡來始覺非外假，鐘鼎瓢簞各其適。", "念昔與君伯仲遊，江翁梅老常接迹。", "得酒有時竟狂醉，賦詩往往連日夕。", "幾年契闊遠朋好，今日蕭條無吏役。", "青衫不踏廣文戶，白羽罷走將軍檄。", "即看秋風破炎毒，高興倏然動肝鬲。", "諸君無事能我從，當使風流似平昔。"]'),
('3d2e81b2-e9c9-4eca-bb96-b33d6a840d02','次韵和平甫同介甫當世過飲見招','韓維','宋','宋诗','song-poetry','','[]','炎風得秋亦已凉，喜抱塵策羅南窗。',323,'全唐诗/poet.song.24000.json','["炎風得秋亦已凉，喜抱塵策羅南窗。", "策中古人不可見，獨咏君子予心降。", "高文大論日傾吐，響快有類鐘應撞。", "却嗟吾儕多暇日，俚謠暴謔何其嚨。", "驅車正得我所念，起具肴蔌陳杯缸。", "自憐愚戇接豪邁，蔽履乃與華冕雙。", "聖經王道有本末，斟挹醇粹揮其尨。", "須臾上下今與古，武庫千矛鏦。", "疑懷滯義一開豁，有如暗室來明釭。", "馮侯抗議亦殊健，短鈎長{缶丕}相撐摐。", "介卿後至語閑暇，偃載戈甲韜旌幢。", "弱弓枉矢尚何用，久已束手甘避逄。", "是時君有山陽役，扁舟已具河之矼。", "朝吟淮山翠撲撲，夜夢楚水鳴淙淙。", "軒然欲去坐所惜，文字雅正姿信悾。", "行年三十不得飽，况有薦道登朝邦。", "遂令奔放不自斂，欲旅漁釣終湖江。", "朝廷攬賢無遠近，北盡漠塞南嶺瀧。", "如君才大齒且壯，安可推亮而居龐。", "功名得時看樹立，豈若都尉眉空厖。"]'),
('0603537d-f15c-41e6-896c-92206c94622a','奉答原甫登契丹嶺見寄','韓維','宋','宋诗','song-poetry','','[]','中原昔失御，幽冀不復華。',156,'全唐诗/poet.song.24000.json','["中原昔失御，幽冀不復華。", "我朝示仁撫，金幣歲屢加。", "君恩謹宣道，使才慎推差。", "翰林承命行，驅駕絕漠沙。", "晨登寒山嶺，回望萬里家。", "勁風搜貂裘，嚴冰斷馬撾。", "鄉心感歸雁，塞淚零悲笳。", "慷慨屬國節，迢遞博望槎。", "幸古有此賢，庶足開顰嗟。", "晴陽展歸旗，喜氣日以嘉。", "入門解征衫，金樽灧流霞。", "哀弦間清唱，嬌鬟蔚如鴉。", "一慰行役勞，期君柳初芽。"]'),
('ae610ddc-2555-4b9b-8767-3c374a0fe4e5','和吳九王二十八雪詩','韓維','宋','宋诗','song-poetry','','[]','方冬氣潛溫，得晚陰始重。',132,'全唐诗/poet.song.24000.json','["方冬氣潛溫，得晚陰始重。", "狂隨風力翻，怒若雲面涌。", "中微玉霏屑，後盛毛紛氄。", "寒光動城闕，甘滋入田壟。", "鵬騫海水飛，驥憤鹽車覂。", "縈樓巧作層，覆道高城甬。", "群方破昏霧，萬物被光寵。", "塗歌涵太和，送賀仰高拱。", "判官坐丞華，賦詩掩垂隴。", "貂裘擁宵談，金杯落晨捧。", "此興吾不薄，君門旦當踵。"]'),
('1f5ebca5-ca6a-44e5-8141-18fe420906a6','答曼叔客居見詒兼簡里中諸君','韓維','宋','宋诗','song-poetry','','[]','少乏經世才，引分甘自置。',156,'全唐诗/poet.song.24000.json','["少乏經世才，引分甘自置。", "不意田野姿，尚爲軒冕寄。", "三年太學館，飽食無所議。", "京都多賢豪，出入許陪厠。", "時從騎省吟，或就步兵醉。", "低回衆人內，自謂處身智。", "耽耽秘書府，實待才俊地。", "乃昏落其間，衆口沸嘲詈。", "茫如觸駭機，狂顧不知避。", "忽逢故人來，一道平生志。", "歸心西南飛，勁疾霜後鷙。", "遠慚龍陽隠，近愧葆光吏。", "詩以謝諸君，顛冥非吾事。"]'),
('ca4e3e3f-e3cd-44d6-b40d-bb7dbb794e94','和彥猷在華亭賦十題依韵 顧林亭','韓維','宋','宋诗','song-poetry','','[]','昔人久塵土，問林得其居。',48,'全唐诗/poet.song.24000.json','["昔人久塵土，問林得其居。", "但傳故老言，安知密與疏。", "平湖無遺宇，寒烟生廢墟。", "風流未都盡，猶頼著書餘。"]'),
('31642cd9-4218-4cd2-8676-9d023887b9ed','和彥猷在華亭賦十題依韵 寒穴','韓維','宋','宋诗','song-poetry','','[]','寒泉發何年，四序常自平。',48,'全唐诗/poet.song.24000.json','["寒泉發何年，四序常自平。", "上凜冰雪氣，中密瑶玉聲。", "豈無蛇蜮潛，但見沙水清。", "妄飲亦可戒，山木令人酲。"]'),
('8383a097-a5d8-45f0-ae39-109b1243086d','和彥猷在華亭賦十題依韵 吳王獵場','韓維','宋','宋诗','song-poetry','','[]','吳王昔用武，所樂惟干戈。',48,'全唐诗/poet.song.24000.json','["吳王昔用武，所樂惟干戈。", "安知聖人意，祝網解其羅。", "朝行數田獲，暮返論戰多。", "千載亦何有，柔桑陰滿坡。"]'),
('2c0f3aa9-e2c0-45a3-bb53-0c0d2eae7e32','和彥猷在華亭賦十題依韵 柘湖','韓維','宋','宋诗','song-poetry','','[]','柘湖淪此地，柘山巋其瀕。',48,'全唐诗/poet.song.24000.json','["柘湖淪此地，柘山巋其瀕。", "復驚秦時女，化作湖上神。", "世事喜反覆，孰能識涯津。", "物變雖萬殊，不惑固有人。"]'),
('ef7bbf86-2c3c-4bef-a0f0-78b0a1835336','和彥猷在華亭賦十題依韵 秦始皇馳道','韓維','宋','宋诗','song-poetry','','[]','秦王騁奇觀，不憚阻且脩。',48,'全唐诗/poet.song.24000.json','["秦王騁奇觀，不憚阻且脩。", "萬里走轍迹，八荒開囿遊。", "勞歌久已息，遺築今尚留。", "千載威神盡，驪山空古丘。"]'),
('b335e3a5-0567-4fa2-9b29-e2798f76eda7','和彥猷在華亭賦十題依韵 陸瑁養魚池','韓維','宋','宋诗','song-poetry','','[]','林塘豈如昔，尚想昔時居。',48,'全唐诗/poet.song.24000.json','["林塘豈如昔，尚想昔時居。", "秋草自鳴鸛，寒波猶戲魚。", "紛紜鈎餌底，瑣碎刀匕餘。", "任公有奇術，默坐歲幾餘。"]'),
('1f1207b8-c1d2-4d2d-85b4-f5f6656fcba8','和彥猷在華亭賦十題依韵 華亭谷','韓維','宋','宋诗','song-poetry','','[]','穹穹華亭谷，中有不竭流。',48,'全唐诗/poet.song.24000.json','["穹穹華亭谷，中有不竭流。", "其微初濫觴，其大終載舟。", "寒色皎可鑑，嵐光鬰如浮。", "當解塵中纓，一濯潭上秋。"]'),
('a0e12d6f-90c3-4fd7-9661-a08bc94137b7','和彥猷在華亭賦十題依韵 陸機宅','韓維','宋','宋诗','song-poetry','','[]','出身豈明代，涉禍固以深。',48,'全唐诗/poet.song.24000.json','["出身豈明代，涉禍固以深。", "一觀廢興迹，可用當所箴。", "高門非昔時，喬木或遺陰。", "空令弔古士，感激成幽尋。"]'),
('e0e6b480-6799-4663-9856-fd48c4ac4af7','和彥猷在華亭賦十題依韵 崑山','韓維','宋','宋诗','song-poetry','','[]','晉衰士不競，識者逃其名。',48,'全唐诗/poet.song.24000.json','["晉衰士不競，識者逃其名。", "陸生起江湖，文藻振英聲。", "遂令崑丘號，長配山不傾。", "君看玉就毀，孰與樗全生。"]'),
('57a6422a-9e2a-4650-bb76-830d1103a028','和彥猷在華亭賦十題依韵 三女岡','韓維','宋','宋诗','song-poetry','','[]','三女史無載，于何永其名。',48,'全唐诗/poet.song.24000.json','["三女史無載，于何永其名。", "坡傳妃子逝，村記昭君生。", "和戎與走蜀，爲恨兩莫平。", "爾兮亦胡爲，崇岡屹如城。"]'),
('08590017-390d-4a75-a94c-3254eb994c2b','和胡公謹遊李寺丞北園','韓維','宋','宋诗','song-poetry','','[]','春郊不數到，俯仰恨流景。',120,'全唐诗/poet.song.24000.json','["春郊不數到，俯仰恨流景。", "李侯有嘉招，滯念茲一騁。", "名園带喬樹，亭榭散清影。", "解我塵中衣，觴行日舒永。", "花團錦纈明，竹竦摇碧靜。", "從容方罫間，萬事不關省。", "善謔寧類鄱，高歌或如郢。", "行遵水曲幽，望出林梢迥。", "興來非外奬，理愜有真領。", "薄莫聯歸鞍，清風吹不醒。"]'),
('4a29803f-c6c9-4380-80ae-d3b518c4a9d9','賦永叔家白兔','韓維','宋','宋诗','song-poetry','','[]','天公團白雪，戲作毛物形。',195,'全唐诗/poet.song.24000.json','["天公團白雪，戲作毛物形。", "太陰來照之，精魄孕厥靈。", "走弄朝日光，赩然丹兩睛。", "不知質毛異，乃下遊林坰。", "一爲世俗怪，罝網遂見縈。", "我嘗論天理，於物初無營。", "妍者偶自得，醜者果誰令。", "豺狼穴高山，吞噬飫膻腥。", "蒼鷹{扌甹}不得，逸虎常安行。", "是惟獸之細，田畝甘所寧。", "糧粒不飽腹，連群落燖烹。", "幸而獲珍貴，愁苦終其生。", "糾紛禍福餘，未易以迹明。", "將由物自爲，或繫時所丁。", "恨無南華辯，文字波濤傾。", "兩置豺與兔，浩然至理真。"]'),
('39034c33-dedc-47fb-9012-f48f0777e124','又賦京師初食車螯','韓維','宋','宋诗','song-poetry','','[]','翰林置酒冬之嚴，庶羞羅列窮脆甘。',103,'全唐诗/poet.song.24000.json','["翰林置酒冬之嚴，庶羞羅列窮脆甘。", "有餽奇味衆莫覘，久秘不出須賓酣。", "紅爐熾炭發其鉗，金鍾一引連三四。", "滿坐詫美歡笑談，肯復重顧蟶與蚶。", "京都貴人粱肉厭，遠致異物無微纖。", "駢珍錯怪百類兼，何久遺此不得參。", "乃知物用有遠。"]'),
('b6476dfb-434e-41c9-8436-077fe4272c5a','九日北園思臨渦之遊','韓維','宋','宋诗','song-poetry','','[]','吾生豈鷹鸇，胡爲見羈紲。',96,'全唐诗/poet.song.24000.json','["吾生豈鷹鸇，胡爲見羈紲。", "題鞭古勝地，落帽秋佳節。", "一爲塵事牽，坐嘆高會缺。", "天兼水澄淡，樹與堤曲折。", "萸房露應重，菊艷晨可擷。", "嘉景成想像，清樽廢提挈。", "陰風吹北園，衆槁聲切切。", "把酒望霜空，冥鴻溯遼碣。"]'),
('701fd935-7180-4ec9-9272-81ef243febd4','南堂對竹懷江十鄰幾','韓維','宋','宋诗','song-poetry','','[]','端居無所聊，稍復治文字。',204,'全唐诗/poet.song.24000.json','["端居無所聊，稍復治文字。", "南堂冬日明，窗戶暖可喜。", "圖書羅滿前，意覽不由次。", "聊收靜者趣，以亂憂人思。", "亭亭當軒竹，使我長嘆喟。", "封植苦不早，顔色頗憔悴。", "勁節亮不改，虛心如有遲。", "緬懷江夫子，循道久不試。", "邈然高簡姿，不受世俗累。", "一官才復進，左謫良何亟。", "德義我所珍，軒冕安能貴。", "長嘯汝水濱，濁醪日自釃。", "效陶有新篇，翼孔著高議。", "弦琴坐虛室，默與古人值。", "顯晦一其心，淡然天淳粹。", "思之不可見，暑謝寒已摯。", "諒非對此君，茲懷何由慰。"]'),
('2ce59419-8e5b-451f-8f17-58b28a4bd5f7','夜坐有懷黎君','韓維','宋','宋诗','song-poetry','','[]','霜風動脩竹，寒月照廣庭。',96,'全唐诗/poet.song.24000.json','["霜風動脩竹，寒月照廣庭。", "此夕南堂客，得無羈旅情。", "束書萬里外，徒步游上京。", "豈憚行役勞，所期功與名。", "高文日以麗，經義素所明。", "顧我頑鈍姿，無以延英聲。", "銜哀謝時好，守拙伏茅衡。", "佇君取高第，光華慰友生。"]'),
('02003776-6c82-487d-8a47-eebbb18bb8f8','和子華兄宴王道損公宇','韓維','宋','宋诗','song-poetry','','[]','濟濟高燕會，衆賓且喜樂。',204,'全唐诗/poet.song.24000.json','["濟濟高燕會，衆賓且喜樂。", "方冬氣常溫，是日寒始若。", "愁雲際平林，垂見雪花落。", "四座喜相顧，有引必虛爵。", "中堂豈非佳，東圃羅帟幄。", "當亭列射格，抗的明灼灼。", "雕弓既出韔，勁矢各在握。", "主人揖讓興，客以次序作。", "目惴綵樹移，心傾鐘鼓數。", "笑言何謔失，儀節亦稱娖。", "酒酣事頗變，極口縱談謔。", "失令固有罰，出語輒見酌。", "平生愛疏放，論議鄙齪齪。", "歡來一狂散，豈顧醒後怍。", "詩人亦有言，善戲不爲虐。", "所頼衆君子，闊達見表襮。", "還家遂酩酊，豈復記鳴柝。"]'),
('2ce80c73-6c55-44ec-996f-cb53ed9e5f55','和象之雨中見寄','韓維','宋','宋诗','song-poetry','','[]','沉陰子所嘆，幽事我爲樂。',48,'全唐诗/poet.song.24000.json','["沉陰子所嘆，幽事我爲樂。", "雨沼散圓荷，風蛙亂靈葯。", "清凉體自正，虛靜道所托。", "誰識此中心，一樽成獨酌。"]'),
('66f85ec9-817f-496a-a0f4-b8f568c75c83','喜吳沖卿重過許昌','韓維','宋','宋诗','song-poetry','','[]','前君廣文直，共宿官舍冷。',144,'全唐诗/poet.song.24000.json','["前君廣文直，共宿官舍冷。", "携觴慰羈旅，鳴弦破愁靜。", "竹陰月娟娟，樓角星炳炳。", "是時冬夕長，諧笑得馳騁。", "爾來還故棲，樂事成引領。", "君方志遠擊，我固分幽屏。", "趨舍既云異，會合安可幸。", "不謂旬浹間，所得亦以併。", "清笑煩滯闋，高談謬疑正。", "琅琅別後篇，鏗若御笙磬。", "索居久其職，此適固爲橫。", "一感朋盍難，舉酒良自慶。"]'),
('5c7c43a0-b982-4020-abee-e7dd363c299b','同戴處士游湖','韓維','宋','宋诗','song-poetry','','[]','京塵倦遊久，愛此西城曲。',48,'全唐诗/poet.song.24000.json','["京塵倦遊久，愛此西城曲。", "泉溫草尚青，春近波先淥。", "幽人幸相對，高論良自足。", "蚩蚩北州民，安得同我欲。"]'),
('2836088e-e046-49b6-b3ca-af50e1f2eb98','同曼叔觀潁昌酴醿','韓維','宋','宋诗','song-poetry','','[]','前日看花花正發，今日看花花欲歇。',64,'全唐诗/poet.song.24000.json','["前日看花花正發，今日看花花欲歇。", "入門但見綠陰下，寂寞無人委春雪。", "狂風飄簸百卉盡，惟有清香吹不絕。", "攀條惆悵可奈何，與君把酒到明月。"]'),
('1865683b-707f-4851-9408-10349d41c588','夜泊湖上','韓維','宋','宋诗','song-poetry','','[]','春風淡無力，池色晚更靜。',48,'全唐诗/poet.song.24000.json','["春風淡無力，池色晚更靜。", "人歸簫鼓歇，月出樓觀迥。", "驚鷗啄浮星，遊鯉下明鏡。", "誰當拏畫船，徹夕縱孤泳。"]'),
('a3dfdf2d-75b5-4812-aada-5394d7763484','化光東堂賦得奕棋','韓維','宋','宋诗','song-poetry','','[]','君家何所樂，棋奕侑清興。',48,'全唐诗/poet.song.24000.json','["君家何所樂，棋奕侑清興。", "簾垂虛堂肅，子落文楸靜。", "機心久已忘，勝勢安敢競。", "吾知霍將軍，固亦有天幸。"]'),
('3aca402c-cce0-42ea-9003-9a01b89df729','九月十日西湖席上得樂字','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','秋雲淡不飛，霜水清欲落。',72,'全唐诗/poet.song.24000.json','["秋雲淡不飛，霜水清欲落。", "維舟坐近浦，悲風滿衡薄。", "良遊未爲晚，佳節止在昨。", "湛湛觴醪醇，娜娜菊枝弱。", "天時倏代去，所恃有行樂。", "何能學次公，忉咄謝多酌。"]'),
('e866f92b-0785-49b4-8cd4-114efab3feff','元道席上得秋風爲題下爲韵送廣信舍弟','韓維','宋','宋诗','song-poetry','','[]','秋風感人切，况在欲別者。',48,'全唐诗/poet.song.24000.json','["秋風感人切，况在欲別者。", "狂翻斷蓬轉，寒助離樽瀉。", "吹雲急燕雁，獵草嘶代馬。", "莫作塞垣聲，端令客淚下。"]'),
('5321a5c1-ac5b-4120-95fc-546b4fb76fe0','過李膺墓同曼叔作','韓維','宋','宋诗','song-poetry','','[]','漢衰奄寺熾，威柄敢專有。',96,'全唐诗/poet.song.24000.json','["漢衰奄寺熾，威柄敢專有。", "桓桓李司隸，誓奪還君手。", "登門盛賢俊，破柱發姦醜。", "身雖以此亡，慕者猶恐後。", "我行襄之野，把酹孤冢右。", "精誠有相激，淚落入卮酒。", "剖心死亦仁，滅頂過何咎。", "大雅稱明哲，於君豈其謬。"]'),
('1bec7b5b-8749-47e1-a43e-753f5333277c','和太祝端居有懷叔恬秘書','韓維','宋','宋诗','song-poetry','','[]','鄙生復田廬，疏絕豪俊後。',120,'全唐诗/poet.song.24000.json','["鄙生復田廬，疏絕豪俊後。", "側聆楊生賢，名挂時輩口。", "嚮風結遐想，幾歲欲奔走。", "比聞官旁郡，斂板不去手。", "沈埋文俗間，有類魚落笱。", "頗思沿檄來，一洗煩滯久。", "覽君端居作，懷佇日延首。", "竊高田蘇遊，遂信尹公友。", "丈夫相期意，不必銜杯酒。", "作詩助嘉招，此志非邂逅。"]'),
('dcadd1c4-eab8-4763-b387-c4ebe21c08ba','送李寺丞宰藍田','韓維','宋','宋诗','song-poetry','','[]','君誠巖壑徒，出宰亦山縣。',48,'全唐诗/poet.song.24000.json','["君誠巖壑徒，出宰亦山縣。", "尚喜終南峰，蒼翠不去眼。", "春風吹征車，千里度灞滻。", "到日勝事繁，花光老秦甸。"]'),
('231f1c32-b47d-4b0d-aa03-822f47e2c225','奉酬南陵三君別後見寄','韓維','宋','宋诗','song-poetry','','[]','齋居有常禁，跬步不得語。',48,'全唐诗/poet.song.24000.json','["齋居有常禁，跬步不得語。", "清歡猶反思，濁酒成獨撫。", "野杏亂飛春，鄰鷄靜啼午。", "寂寥正如此，坐見前山雨。"]'),
('67e812ba-6c61-40c0-b5c3-43215ae7edf2','雨後之南陵點饌','韓維','宋','宋诗','song-poetry','','[]','齋房厭危坐，出戶曠舒散。',48,'全唐诗/poet.song.24000.json','["齋房厭危坐，出戶曠舒散。", "草木雨多思，雲山晚相亂。", "縈回俯川陸，窈窕見樓觀。", "耳目久塵埃，茲辰一湔浣。"]'),
('f005de0a-3f6c-4abd-a411-9db6cfe87919','偃仰','韓維','宋','宋诗','song-poetry','','[]','鵲噪庭柏喧，朝光來入隙。',72,'全唐诗/poet.song.24000.json','["鵲噪庭柏喧，朝光來入隙。", "祠官謝餘事，偃仰百骸適。", "回思朝市人，小大各有役。", "區區就終盡，萬古同一迹。", "而我遂慵散，興味良不極。", "富貴非所慕，茲願儻有獲。"]'),
('3330aeff-f5eb-4948-a3e9-324d5df675d5','哀傳馬','韓維','宋','宋诗','song-poetry','','[]','喧呼國西門，驛使通萬里。',120,'全唐诗/poet.song.24000.json','["喧呼國西門，驛使通萬里。", "十亭傳一馬，日夜不得止。", "枯腸嗛芻豆，瘦骨繫轡箠。", "力盡求未息，忽已仆泥滓。", "死者既不補，存者行復爾。", "聞古至治世，微物均福祉。", "不壅王澤流，其先在官理。", "國家富郡邑，一板萬生齒。", "付與有失宜，得無馬之似。", "投鞍坐太息，春爲悲風起。"]'),
('021ca72c-7eae-4a0c-8827-768e0946e61b','冬至日作','韓維','宋','宋诗','song-poetry','','[]','初陽動新琯，微霰集前墀。',96,'全唐诗/poet.song.24000.json','["初陽動新琯，微霰集前墀。", "舉宗會佳節，拜賀儼成儀。", "念我閨中人，獨此隔容徽。", "昔同奉祭籩，今自享酹卮。", "彷彿平生像，凄愴故年衣。", "寒燈清無光，僮使侍虛帷。", "對之忽悲結，零淚不可揮。", "嬌兒何所識，摴博自爲嬉。"]'),
('bfe00fae-9cb2-4cc7-9870-279e94035cb2','切切','韓維','宋','宋诗','song-poetry','','[]','我懷切切重切切，今日歸當去年月。',64,'全唐诗/poet.song.24000.json','["我懷切切重切切，今日歸當去年月。", "香車不復故道來，血淚空霑舊行轍。", "嚴風正射人面過，凍地惟憂馬蹄裂。", "舉頭且願愁陰開，悲攪胸腸刻霜雪。"]'),
('82b4f860-52dd-4aed-86dc-a17a818ba609','席上探得游字餞兩浙提刑張吉老','韓維','宋','宋诗','song-poetry','','[]','聖朝用中典，前代所未侔。',96,'全唐诗/poet.song.24000.json','["聖朝用中典，前代所未侔。", "一罰有失平，天子以爲憂。", "祥刑慎處糾，輟子蓬萊丘。", "御前賜印紙，盡部東南州。", "才豪勇自放，霜隼凌高秋。", "清風翩兩旗，八月下吳舟。", "勉哉樹休問，考績待其尤。", "毋忘臨觴贈，義重閨臺游。"]'),
('3e667697-e028-4420-b1fe-585729b3e435','同曼叔諸君登醴泉觀凝碧亭','韓維','宋','宋诗','song-poetry','','[]','門前車馬塵，當晝塞昏霧。',72,'全唐诗/poet.song.24000.json','["門前車馬塵，當晝塞昏霧。", "安知此亭上，秋色生四顧。", "黄花散晴陽，赤葉變寒露。", "境非遊覽舊，人得朋從素。", "樂幽魚群行，賞俊鳥橫度。", "惜無一樽酒，留連清景暮。"]'),
('324dec83-b5d5-4b32-80ea-a8a5dcb580e1','次韵和永叔種菊過節方開','韓維','宋','宋诗','song-poetry','','[]','皇天於萬生，難用一理曉。',132,'全唐诗/poet.song.24000.json','["皇天於萬生，難用一理曉。", "芝蘭喜憔悴，蒿艾長美好。", "况茲封培晚，榮茂安得早。", "頼逢賢主人，拂飾文字巧。", "不然彼微芳，零謝同衆槁。", "清霜不能凋，秀色出庭草。", "珊珊黄金明，落落衆星小。", "人生苦多累，適意會常少。", "在昔陶公園，恨無酒樽倒。", "斂襟賦寒華，高唱徒杳裊。", "幸無斯人嘆，一醉可遺老。"]'),
('5b594ef4-f256-42e0-9d45-40edc2303bf3','又和楊之美家琵琶妓','韓維','宋','宋诗','song-poetry','','[]','楊君好古天下無，自信獨與常人殊。',220,'全唐诗/poet.song.24000.json','["楊君好古天下無，自信獨與常人殊。", "勤身所營世或棄，反眼不顧我以趨。", "彼其察物類有道，能取精妙遺其粗。", "官卑俸薄不自給，買童教樂收圖書。", "客來呼童理弦索，滿面狼籍施鉛朱。", "樽前一聽啄木奏，能使四坐改觀爲歡娛。", "有時陳書出衆畫，羅列卷軸長短俱。", "破縑壞紙抹漆黑，筆墨僅辨絲毫餘。", "補裝斷綻搜尺寸，分別品目窮錙銖。", "以茲爲玩不知老，自適其適誠吾徒。", "豈無高門華屋貯妖麗，中掛瑶圃崑崙圖。", "青紅采錯亂人目，珠玉磊落熒其軀。", "苟非絕藝與奇迹，楊君視之皆蔑如，楊君好古天下無。"]'),
('c03cdad2-73c9-4f40-81c0-394b63402973','遺吳沖卿大饗碑文','韓維','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','蒼碑剝龍螭，突兀古殿側。',288,'全唐诗/poet.song.24000.json','["蒼碑剝龍螭，突兀古殿側。", "世變文字異，歲久苔蘚蝕。", "諒非好事者，塵土未嘗拭。", "我來仰首看，百過不自息。", "曩者魏方盛，帝丕託威德。", "馳驅百萬衆，南指斗牛域。", "誓將殄氛祲，飲馬長江邑。", "翠華鬰回翔，高會誇故國。", "肅肅環佩響，煌煌羽旄飾。", "鼓鐘何鏜鎝，淮漢爲震仄。", "罷饗示得意，摛文永鑱勒。", "從臣梁孟皇，隸法當世特。", "奉詔無與讓，淋漓奮其墨。", "爾來幾千歲，卓卓見筋力。", "端莊九鼎重，勁挺群珪植。", "威儀商山老，氣象漢庭直。", "惟昔銘栒戈，先儒固難迹。", "况我鄙陋極，視此空嘆惜。", "常恐日磨滅，不辨點與畫。", "呼工模於紙，一掃見白黑。", "緘包比瓊瑶，把玩廢寢食。", "于時大經九，有詔講謬忒。", "刊之太學中，爲後代法式。", "沖卿邦家彥，學問古今積。"]'),
('90207875-d98d-4184-9998-0ce927d68460','久旱喜雨','韓維','宋','宋诗','song-poetry','','[]','炎風駕京塵，久旱氛祲惡。',168,'全唐诗/poet.song.24000.json','["炎風駕京塵，久旱氛祲惡。", "羲和鞭日車，光焰赫飛躍。", "群生困熬暴，嘉穀坐焦灼。", "高堂袒裼卧，汗下如鞭索。", "安知於此時，乃見嘉樹落。", "狂飄隨烟雲，急灑動林薄。", "蕭然宇宙間，昏霧一疏瀹。", "雖忻意暫豁，所嘆施未博。", "雷霆司天令，何乃久寂寞。", "微陰雖自復，陽亢不爲却。", "安得躋帝閽，一鼓造化橐。", "太上方厲政，進賢登謇諤。", "日將太平近，此變不應作。", "吾徒勿咨嗟，坐看雨時若。"]'),
('2067fbc5-487b-41b7-9cbb-8be13fe2e283','和江十浮光隠者','韓維','宋','宋诗','song-poetry','','[]','我本巖壑性，落身名利場。',144,'全唐诗/poet.song.24000.json','["我本巖壑性，落身名利場。", "譬如籠中鳥，飛舉意不忘。", "常恨此世人，與古不相方。", "爭名塞朝市，養志空巖房。", "近聞二三子，卜築淮山旁。", "松柏手自種，夏陰鬰蒼蒼。", "晨釣淮上石，暮返林中堂。", "琴樽自爲樂，過是皆秕糠。", "乃知天下士，未易一概量。", "好事江夫子，慕之著辭章。", "名落塵土間，清風何激揚。", "安知後來者，不及董與黄。"]');
